        public ActionResult UploadVideoforKYC()
        {
            var filename = Request.Files;
            foreach (string file in Request.Files)
            {
                HttpPostedFileBase hpf = Request.Files[file] as HttpPostedFileBase;
                if (hpf.ContentLength == 0)
                    continue;
                if (hpf != null)
                {
                    var newfilename = "WEB_" + Guid.NewGuid().ToString() + "_" + Path.GetFileName(hpf.FileName);
                    var imagepath = @"\Retailer_Video\" + newfilename + ".mp4";
                    hpf.SaveAs(Server.MapPath("~/") + imagepath);
                    var userid = User.Identity.GetUserId();
                    var allkycchk = db.Retailer_Details.Where(x => x.RetailerId == userid && x.PSAStatus == "Y" && x.AadhaarStatus == "Y" && x.ShopwithSalfieStatus == "Y" && x.videokycstatus == "N" && x.videokycpath == null).SingleOrDefault();
                    if (allkycchk != null)
                    {
                        allkycchk.videokycpath = imagepath;
                        allkycchk.videokycstatus = "N";
                        db.SaveChanges();
                    }
                }
            }
            return Json("OK", JsonRequestBehavior.AllowGet);
        }
