        public ActionResult Dashboard()
        {
            var userid = User.Identity.GetUserId();
            #region Auto credit transfer Calling
            CallAutofundtransfer(userid);
            #endregion calling
            var emailmobile = db.Users.Where(x => x.UserId == userid).SingleOrDefault();
            var remdetails = db.Retailer_Details.Where(x => x.RetailerId == userid).SingleOrDefault();
            var createedby = remdetails.CretedBy;
            var emailmobilests = db.Email_Mobile_Verify.SingleOrDefault().emailmobile_verified;
            if (emailmobilests.ToUpper().Contains("ALL") || emailmobilests.ToUpper().Contains("SIGNUP"))
            {
                if (emailmobilests.ToUpper().Contains("SIGNUP"))
                {
                    if (createedby == "Signup")
                    {
                        if (emailmobile.EmailConfirmed == false || emailmobile.PhoneNumberConfirmed == false)
                        {
                            return RedirectToAction("VeryFY_Profiles_users", "Home", new { area = "Retailer" });
                        }
                    }
                }
                else
                {
                    if (emailmobile.EmailConfirmed == false || emailmobile.PhoneNumberConfirmed == false)
                    {
                        return RedirectToAction("VeryFY_Profiles_users", "Home", new { area = "Retailer" });
                    }
                }
            }
            var printer1 = db.Printer_paperSize_Changes.Where(a => a.Userid == userid && a.Print_Name == "A4_Print").Count();
            if (printer1 == 0)
            {
                Printer_paperSize_Changes ff = new Printer_paperSize_Changes();
                ff.Userid = userid;
                ff.Print_Name = "A4_Print";
                ff.status = "Y";
                db.Printer_paperSize_Changes.Add(ff);
                db.SaveChanges();
            }
            var printer2 = db.Printer_paperSize_Changes.Where(a => a.Userid == userid && a.Print_Name == "Thermal_Print").Count();
            if (printer2 == 0)
            {
                Printer_paperSize_Changes ff = new Printer_paperSize_Changes();
                ff.Userid = userid;
                ff.Print_Name = "Thermal_Print";
                ff.status = "N";
                db.Printer_paperSize_Changes.Add(ff);
                db.SaveChanges();
            }
            var allkycchk = db.Retailer_Details.Where(x => x.RetailerId == userid && x.PSAStatus == "Y" && x.AadhaarStatus == "Y" && x.ShopwithSalfieStatus == "Y" && x.videokycstatus == "N" && (x.videokycpath == null || x.videokycpath != null)).SingleOrDefault();
            if (allkycchk != null)
            {
                return RedirectToAction("VideoKYCstatus");
            }
            ViewBag.show = "Today";
            var entry = db.Slab_Flight.FirstOrDefault(a => a.UserId == userid);
            ViewBag.markup = entry.RetailerMarkupCharge;
            var vv = db.Retailer_Details.Where(a => a.RetailerId == userid).SingleOrDefault();
            ViewBag.email = vv.Email;
            ViewBag.name = vv.RetailerName;
            ViewBag.frmname = vv.Frm_Name;
            ViewBag.image = vv.Photo;
            //Retailer News
            var news = (from pp in db.Message_top where (pp.users == "Retailer" || pp.users == "All") where pp.status == "Y" select pp).ToList();
            ViewBag.newsdata = news;
            //Upcomming Holiday
            //List<show_upcomming_holiday_Result> li = new List<show_upcomming_holiday_Result>();
            var li = db.tbl_Holiday.ToList();
            ViewBag.showholiday = li;
            ViewBag.msg = TempData["msg"];
            TempData.Remove("msg");
            RecentTrans RecTra = new RecentTrans();
            string txt_to_date1 = DateTime.Now.ToString();
            string frm_date = Convert.ToDateTime(txt_to_date1).ToShortDateString();
            string to_date = Convert.ToDateTime(txt_to_date1).AddDays(1).ToString();
            DateTime from = DateTime.Now;
            DateTime to = DateTime.Now;
            var ledger = db.recent_Retailer(userid, "TOP10", 10, from, to).ToList();
            DateTime todaysDate = DateTime.Now.Date;
            int month = todaysDate.Month;
            int year = todaysDate.Year;
            int Nxtmonth = todaysDate.AddMonths(1).Month;
            int Nxtyear = todaysDate.AddMonths(1).Year;
            TargetSetviewmodel vmodel = new TargetSetviewmodel();
            var allOn = db.tblRetailerSetTargets.Where(a => a.Status == true).ToList();
            vmodel.remTargetCategory = allOn.Where(a => a.Date.Value.Month == month && a.Date.Value.Year == year).ToList();
            vmodel.remTargetCategoryNxt = allOn.Where(a => a.Date.Value.Month == Nxtmonth && a.Date.Value.Year == Nxtyear).ToList();
            vmodel.productItems = db.tblPruductGifts.ToList();
            vmodel.recent_Retailer = ledger;
            vmodel.CategoryImages = Directory.EnumerateFiles(Server.MapPath("~/CategoryImages")).Select(fn => Path.GetFileNameWithoutExtension(fn));
            return View(vmodel);
        }
