        public ActionResult VeryfyUserEmailOTP(string btnveryfyotp, string hdmobileotp, string hdemailotp)
        {
            var userid = User.Identity.GetUserId();
            var emailmobile = db.Users.Where(x => x.UserId == userid).SingleOrDefault();
            ViewBag.emailsts = emailmobile.EmailConfirmed;
            ViewBag.mobilests = emailmobile.PhoneNumberConfirmed;
            var remdetails = db.Retailer_Details.Where(x => x.RetailerId == userid).SingleOrDefault();
            if (remdetails != null)
            {
                if (!string.IsNullOrEmpty(hdmobileotp) && !string.IsNullOrEmpty(hdemailotp))
                {
                    var deleteotp = db.MobileOtps.Where(aa => aa.Userid == userid).ToList();
                    if (btnveryfyotp == "MobileEmail")
                    {
                        var otpmobile = db.MobileOtps.Where(aa => aa.Userid == userid && aa.Type == "MobileVeryfy" && aa.mobileno == remdetails.Mobile).OrderByDescending(aa => aa.Date).FirstOrDefault().Otp;
                        var otpemail = db.MobileOtps.Where(aa => aa.Userid == userid && aa.Type == "EmailVeryfy" && aa.mobileno == remdetails.Mobile).OrderByDescending(aa => aa.Date).FirstOrDefault().Otp;
                        if (otpmobile == hdmobileotp && otpemail == hdemailotp)
                        {
                            var result = db.Users.Where(x => x.UserId == userid).FirstOrDefault();
                            if (result != null)
                            {
                                result.PhoneNumberConfirmed = true;
                                result.EmailConfirmed = true;
                                db.SaveChanges();
                                db.MobileOtps.RemoveRange(deleteotp);
                                db.SaveChanges();
                                return RedirectToAction("Dashboard", "Home");
                            }
                            else
                            {
                                return RedirectToAction("VeryFY_Profiles_users");
                            }
                        }
                        else
                        {
                            return RedirectToAction("VeryFY_Profiles_users");
                        }
                    }
                    else
                    {
                        if (btnveryfyotp == "Mobile")
                        {
                            var otpmobile = db.MobileOtps.Where(aa => aa.Userid == userid && aa.Type == "MobileVeryfy" && aa.mobileno == remdetails.Mobile).OrderByDescending(aa => aa.Date).FirstOrDefault().Otp;
                            if (otpmobile == hdmobileotp)
                            {
                                var result = db.Users.Where(x => x.UserId == userid).FirstOrDefault();
                                if (result != null)
                                {
                                    result.PhoneNumberConfirmed = true;
                                    db.SaveChanges();
                                    db.MobileOtps.RemoveRange(deleteotp);
                                    db.SaveChanges();
                                    return RedirectToAction("Dashboard", "Home");
                                }
                                else
                                {
                                    return RedirectToAction("VeryFY_Profiles_users");
                                }
                            }
                            else
                            {
                                return RedirectToAction("VeryFY_Profiles_users");
                            }
                        }
                        if (btnveryfyotp == "Email")
                        {
                            var otpemail = db.MobileOtps.Where(aa => aa.Userid == userid && aa.Type == "EmailVeryfy" && aa.mobileno == remdetails.Mobile).OrderByDescending(aa => aa.Date).FirstOrDefault().Otp;
                            if (otpemail == hdemailotp)
                            {
                                var result = db.Users.Where(x => x.UserId == userid).FirstOrDefault();
                                if (result != null)
                                {
                                    result.EmailConfirmed = true;
                                    db.SaveChanges();
                                    db.MobileOtps.RemoveRange(deleteotp);
                                    db.SaveChanges();
                                    return RedirectToAction("Dashboard", "Home");
                                }
                                else
                                {
                                    return RedirectToAction("VeryFY_Profiles_users");
                                }
                            }
                            else
                            {
                                return RedirectToAction("VeryFY_Profiles_users");
                            }
                        }
                    }
                }
                else
                {
                    return RedirectToAction("VeryFY_Profiles_users");
                }
            }
            else
            {
                return RedirectToAction("VeryFY_Profiles_users");
            }
            return RedirectToAction("VeryFY_Profiles_users");
        }
