        public ActionResult Excel_Actual_Retailer_income(DateTime txt_frm_date, DateTime txt_to_date)
        {
            var userid = User.Identity.GetUserId();
            txt_to_date = txt_to_date.AddDays(1);
            var ch = db.show_all_user_income(txt_frm_date, txt_to_date, "Retailer", userid).ToList();
            DataTable dataTbl = new DataTable();
            dataTbl.Columns.Add("Type", typeof(string));
            dataTbl.Columns.Add("Total Success", typeof(string));
            dataTbl.Columns.Add("Total Pending", typeof(string));
            dataTbl.Columns.Add("Total Failed", typeof(string));
            dataTbl.Columns.Add("Income", typeof(string));
            if (ch.Count > 0)
            {
                foreach (var item in ch)
                {
                    dataTbl.Rows.Add(item.Type, item.TotalSuccess, item.TotalPending, item.TotalFailed, item.Amount);
                }
            }
            else
            {
                dataTbl.Rows.Add("", "", "", "", "");
            }
            var grid = new GridView();
            grid.DataSource = dataTbl;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=Excel_Actual_Retailer_income.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();
            return View();
        }
