        public ActionResult ExceluploadRecharge()
        {
            var userid = User.Identity.GetUserId();
            var fromdate = DateTime.Now.Date;
            var todate = fromdate.AddDays(1);
            var info = db.Recharge_excelupload_data.Where(aa => aa.Userid == userid && aa.uploaddate >= fromdate && aa.uploaddate <= todate).ToList();
            return View(info);
        }
        [HttpPost]
        public ActionResult ExceluploadRecharge(string ddl_status, DateTime txt_frm_date, DateTime txt_to_date)
        {
            ViewBag.chk = "post";
            var userid = User.Identity.GetUserId();
            txt_to_date = txt_to_date.AddDays(1);
            var info = db.Recharge_excelupload_data.Where(aa => aa.Userid == userid && aa.uploaddate >= txt_frm_date && aa.uploaddate <= txt_to_date).ToList();
            return View(info);
        }

        public ActionResult BulkRechargeupload()
        {
            var userid = User.Identity.GetUserId();
            var pendingrechargeinfo = db.Recharge_excelupload_data.Where(aa => aa.Status == "Pending" && aa.Userid == userid).ToList();
            var bulmode = db.bulk_payments.Where(a => a.userid == userid).SingleOrDefault();
            foreach (var item in pendingrechargeinfo)
            {
                var idno = item.idno;
                var rchnumber = item.Rch_no;
                var amount = item.Amount.ToString();
                var opt_nm = item.optname;
                var op1 = item.op1;
                var op2 = item.op2;
                var op3 = item.op3;
                var optcodeinfo = (from t1 in db.Operator_Code select t1).AsEnumerable().Where(r => r.operator_Name.Trim().ToUpper() == item.optname.ToUpper()).SingleOrDefault();
                if (optcodeinfo != null)
                {
                    if (optcodeinfo.Operator_type.ToUpper() == "DTH" || optcodeinfo.Operator_type.ToUpper() == "PREPAID" || optcodeinfo.Operator_type.ToUpper() == "POSTPAID")
                    {
                        if (bulmode.payment != "OFF")
                        {
                            recharge(rchnumber, amount, opt_nm, op1, op2, op3, idno);
                        }
                        else
                        {
                            item.Status = "Not Proceed";
                            item.Reason = "Bulk Payment Status Off";
                        }
                    }
                    else
                    {
                        if (bulmode.payment == "FETCH")
                        {
                            var optcode = optcodeinfo.new_opt_code;
                            var resp = viewbill(opt_nm, optcode, rchnumber, "10", op1, op2, op3, "");
                            JsonResult jsonResult = Json(resp, JsonRequestBehavior.AllowGet);
                            dynamic res = jsonResult.Data;
                            var respcgkk = res.Data;
                            var response1key = ""; string response1value = null;
                            foreach (KeyValuePair<string, object> kvp in respcgkk)
                            {
                                var key = kvp.Key;
                                var value = kvp.Value.ToString();
                                if (key == "Response")
                                {
                                    response1key = key;
                                    response1value = value;
                                }
                            }
                            if (response1value == "SUCCESS")
                            {
                                recharge(rchnumber, amount, opt_nm, op1, op2, op3, idno);
                            }
                            else
                            {
                                item.Status = "Not Proceed";
                                item.Reason = "Bill Fetch Issue";
                            }
                        }
                        else if (bulmode.payment == "WITHOUTFETCH")
                        {
                            if (optcodeinfo.Operator_type.ToUpper() != "LPG Gas")
                            {
                                recharge(rchnumber, amount, opt_nm, op1, op2, op3, idno);
                            }
                            else
                            {
                                item.Status = "Not Proceed";
                                item.Reason = "Not Allow to Without Fetch";
                            }
                        }
                        else
                        {
                            item.Status = "Not Proceed";
                            item.Reason = "Bulk Payment Status Off";
                        }
                    }
                    Thread.Sleep(1000);
                }
                else
                {
                    item.Status = "Not Proceed";
                    item.Reason = "Operator MissMatch";
                }
            }
            db.SaveChanges();
            return Json("", JsonRequestBehavior.AllowGet);
        }
