            ViewBag.pan_status = (bool)res.pan_status;
            ViewBag.pan = (string)res.pan;
            ViewBag.type = (string)res.type;
            return View(retailer_details);
        }
        [HttpGet]
        [AllowAnonymous]
        public object EKYC_Varification_Status(string userid)
        {
            bool aadhar_status = true;
            bool pan_status = true;
            string type = "";
            try
            {
                VastwebmultiEntities db = new VastwebmultiEntities();
                var retailer_exist = db.Retailer_Details.Any(s => s.RetailerId == userid);
                if (!retailer_exist)
                {
                    throw new Exception("Retailer Not Found");
                }
                var verify_data = db.AAdharPanEKYC_Verify.Single();
                var retailer_verification_data = db.Retailer_Details.Where(s => s.RetailerId == userid).Single();
                type = verify_data.verify_type;
                if (retailer_verification_data.CretedBy == "Signup")
                {
                    aadhar_status = (bool)retailer_verification_data.aadhar_verification;
                    pan_status = (bool)retailer_verification_data.pan_verification;
                }
                else
                {
                    if (verify_data.type == "all")
                    {
                        aadhar_status = (bool)retailer_verification_data.aadhar_verification;
                        pan_status = (bool)retailer_verification_data.pan_verification;
                    }
                }
                var obj = new
                {
                    status = true,
                    aadhar_status,
                    aadhar = retailer_verification_data.AadharCard,
                    pan_status,
                    pan = retailer_verification_data.PanCard,
                    type
                };
                return obj;
            }
            catch (Exception ex)
            {
                var obj = new
                {
                    status = false,
                    message = ex.Message,
                    aadhar_status = false,
                    pan = false,
                    type
                };
                return obj;
            }
        }
        [HttpGet]
        public JObject AadharVerificationOtpSent(string aadhar)
        {
            var obj = new JObject();
            using (VastwebmultiEntities db = new VastwebmultiEntities())
            {
                var userid = User.Identity.GetUserId();
                var retailer = db.Retailer_Details.Where(s => s.RetailerId == userid).Single();
                if (!String.IsNullOrEmpty(retailer.AadharCard))
                {
                    aadhar = retailer.AadharCard;
                }
                else
                {
                    bool aadharExist = db.Retailer_Details.Any(s => s.AadharCard == aadhar && s.RetailerId != userid);
                    if (aadharExist)
                    {
                        obj.Add("Status", false);
                        obj.Add("Message", "Aadhar Card Already Exist");
                        return obj;
                    }
                }
                if (String.IsNullOrEmpty(aadhar) || aadhar.Length != 12)
                {
                    obj.Add("Status", false);
                    obj.Add("Message", "Invalid Retailer Aadhar Card");
                    return obj;
                }
                var token = Responsetoken.gettoken();
                var txnid = new DateTime().Millisecond.ToString() + RandomString(8);
                System.Net.ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                var client = new RestClient("http://api.vastbazaar.com/api/Web/aadharsendotp?aadharno=" + aadhar + "&txnid=" + txnid);
                client.Timeout = -1;
                var request = new RestRequest(Method.POST);
                request.AddHeader("Authorization", "Bearer " + token);
                IRestResponse response = client.Execute(request);
                if (response.Content.Contains("Invalid response"))
                {
                    obj.Add("Status", false);
                    obj.Add("Message", "Bad Request");
                }
                else
                {
                    dynamic res = JsonConvert.DeserializeObject(response.Content);
                    var status = (bool)res.Content.ADDINFO.success;
                    if (status)
                    {
                        var clientId = (string)res.Content.ADDINFO.data.client_id;
                        obj.Add("Status", true);
                        obj.Add("Message", "Aadhar Verification Otp Sent");
                        obj.Add("clientId", clientId);
                        obj.Add("txnid", txnid);
                        obj.Add("aadhar", aadhar);
                    }
                    else
                    {
                        var message = (string)res.Content.ADDINFO.message;
                        obj.Add("Status", false);
                        obj.Add("Message", message);
                    }
                }
            }
            return obj;
        }
        [HttpGet]
        public JObject AadharVerificationOtpVerify(string client_id, string otp, string txnid, string aadhar)
        {
            var obj = new JObject();
            using (VastwebmultiEntities db = new VastwebmultiEntities())
            {
                var userid = User.Identity.GetUserId();
                var retailer = db.Retailer_Details.Where(s => s.RetailerId == userid).Single();
                if (!String.IsNullOrEmpty(retailer.AadharCard))
                {
                    aadhar = retailer.AadharCard;
                }
                if (String.IsNullOrEmpty(aadhar) || aadhar.Length != 12)
                {
                    obj.Add("Status", false);
                    obj.Add("Message", "Invalid Retailer Aadhar Card");
                    return obj;
                }
                System.Data.Entity.Core.Objects.ObjectParameter output = new System.Data.Entity.Core.Objects.ObjectParameter("Output", typeof(string));
                var measge = db.PROCPANAADHARVERIFICATIONCHARGE(userid, "AADHARCARD", output).SingleOrDefault().msg;
                if (measge == "SUCCESS")
                {
                    var token = Responsetoken.gettoken();
                    System.Net.ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                    var client = new RestClient("http://api.vastbazaar.com/api/Web/validaadhar?client_id=" + client_id + "&otp=" + otp + "&txnid= " + txnid + "&aadhaar_number=" + aadhar);
                    client.Timeout = -1;
                    var request = new RestRequest(Method.POST);
                    request.AddHeader("Authorization", "Bearer " + token);
                    IRestResponse response = client.Execute(request);
                    if (response.Content.ToUpper().Contains("INVALID RESPONSE"))
                    {
                        obj.Add("Status", false);
                        obj.Add("Message", "Bad Request");
                    }
                    else
                    {
                        dynamic res = JsonConvert.DeserializeObject(response.Content);
                        var status = (bool)res.Content.ADDINFO.success;
                        if (status)
                        {
                            var full_name = (string)res.Content.ADDINFO.data.full_name;
                            var dob = (string)res.Content.ADDINFO.data.dob;
                            var profile_image = (string)res.Content.ADDINFO.data.profile_image;
                            var house = (string)res.Content.ADDINFO.data.address.house;
                            var street = (string)res.Content.ADDINFO.data.address.street;
                            var landmark = (string)res.Content.ADDINFO.data.address.landmark;
                            var loc = (string)res.Content.ADDINFO.data.address.loc;
                            var subdist = (string)res.Content.ADDINFO.data.address.subdist;
                            var dist = (string)res.Content.ADDINFO.data.address.dist;
                            var state = (string)res.Content.ADDINFO.data.address.state;
                            retailer.RetailerName = full_name;
                            retailer.aadhar_image = "data:image/png;base64," + profile_image;
                            retailer.residential_address = String.Format("{0} {1} {2} {3} {4} {5} {6}", house, street, landmark, loc, subdist, dist, state).Trim();
                            retailer.AadharCard = aadhar;
                            retailer.aadhar_verification = true;
                            retailer.aadhar_dob = dob;
                            db.SaveChanges();
                            obj.Add("Status", true);
                            obj.Add("Message", "Aadhar Verification Done");
                        }
                        else
                        {
                            var message = (string)res.Content.ADDINFO.message;
                            obj.Add("Status", false);
                            obj.Add("Message", message);
                        }
                    }
                }
                else
                {
                    obj.Add("Status", false);
                    obj.Add("Message", measge);
                    return obj;
                }
            }
            return obj;
        }
        [HttpPost]
        public JObject PanVerification(string pan)
        {
            var obj = new JObject();
            using (VastwebmultiEntities db = new VastwebmultiEntities())
            {
                var userid = User.Identity.GetUserId();
                var retailer = db.Retailer_Details.Where(s => s.RetailerId == userid).Single();
                if (!String.IsNullOrEmpty(retailer.PanCard))
                {
                    pan = retailer.PanCard;
                }
                else
                {
                    bool panExist = db.Retailer_Details.Any(s => s.PanCard == pan && s.RetailerId != userid);
                    if (panExist)
                    {
                        obj.Add("Status", false);
                        obj.Add("Message", "Pan Card Already Exist");
                        return obj;
                    }
                }
                if (String.IsNullOrEmpty(pan) || pan.Length != 10)
                {
                    obj.Add("Status", false);
                    obj.Add("Message", "Invalid Retailer Pancard");
                    return obj;
                }
                System.Data.Entity.Core.Objects.ObjectParameter output = new System.Data.Entity.Core.Objects.ObjectParameter("Output", typeof(string));
                var measge = db.PROCPANAADHARVERIFICATIONCHARGE(userid, "PANCARD", output).SingleOrDefault().msg;
                if (measge == "SUCCESS")
                {
                    var token = Responsetoken.gettoken();
                    var txnid = new DateTime().Millisecond.ToString() + RandomString(4);
                    System.Net.ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                    var client = new RestClient("http://api.vastbazaar.com/api/Web/PanCardVerify?pancardno=" + pan + "&txnid=" + txnid);
                    client.Timeout = -1;
                    var request = new RestRequest(Method.POST);
                    request.AddHeader("Authorization", "Bearer " + token);
                    IRestResponse response = client.Execute(request);
                    if (response.Content.ToUpper().Contains("INVALID RESPONSE"))
                    {
                        obj.Add("Status", false);
                        obj.Add("Message", "Bad Request");
                    }
                    else
                {
                    dynamic res = JsonConvert.DeserializeObject(response.Content);
                    var status = (bool)res.Content.ADDINFO.success;
                    var message = (string)res.Content.ADDINFO.message;
                    if (status)
                    {
                        retailer.PanCard = pan;
                        retailer.pan_verification = true;
                        db.SaveChanges();
                        obj.Add("Status", true);
                        obj.Add("Message", "Pan Verification Done");
                    }
                    else
                    {
                        obj.Add("Status", false);
                        obj.Add("Message", message);
                    }
                }
                }
                else
                {
                    obj.Add("Status", false);
                    obj.Add("Message", measge);
                    return obj;
                }
            }
            return obj;
        }
