        public ActionResult Excel_Micro_Atm_hold_Rem_Report()
        {
            var userid = User.Identity.GetUserId();
            var modelss = db.Show_MicroAtm_Unload_report(userid).ToList();
            DataTable dataTbl = new DataTable();
            dataTbl.Columns.Add("Status", typeof(string));
            dataTbl.Columns.Add("Bank RRN", typeof(string));
            dataTbl.Columns.Add("Transection Type", typeof(string));
            dataTbl.Columns.Add("Payment Method", typeof(string));
            dataTbl.Columns.Add("Amount ", typeof(string));
            dataTbl.Columns.Add("Card Payment Type ", typeof(string));
            dataTbl.Columns.Add("Masked Pan", typeof(string));
            dataTbl.Columns.Add("transtime ", typeof(string));
            dataTbl.Columns.Add("network", typeof(string));
            dataTbl.Columns.Add("Requestid", typeof(string));
            if (modelss.Any())
            {
                foreach (var item in modelss)
                {
                    dataTbl.Rows.Add(item.IsHold, item.rrn, item.transaction_type, item.payment_method, item.amount, item.card_payment_type, item.masked_pan, item.transtime, item.network, item.Requestid);
                }
            }
            else
            {
                dataTbl.Rows.Add("", "", "", "", "", "", "", "", "", "");
            }
            var grid = new GridView();
            grid.DataSource = dataTbl;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=Micro_Atm_hold_Rem_Report.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();
            return View();
        }
