        public ActionResult payucall(string OrderId, decimal Amount)
        {
            var userid = User.Identity.GetUserId();
            System.Net.ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12 | SecurityProtocolType.Tls11 | SecurityProtocolType.Tls;
            String strPathAndQuery = System.Web.HttpContext.Current.Request.Url.PathAndQuery;
            var reminfo = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
            var auth = db.Gateway_Auth.SingleOrDefault();
            String strUrl = System.Web.HttpContext.Current.Request.Url.AbsoluteUri.Replace(strPathAndQuery, "/");
            var url = strUrl + "Response/PayUGatewayRecharge";
            // var key = "CbR19P";
            var key = auth.merchantkey;
            var RetailerName = reminfo.RetailerName;
            var Email = reminfo.Email;
            //  var salt = "i0dSyipJyJAzKovgBSPhWfUQAsj1GGIZ";
            var salt = auth.merchantsalt;
            //decimal amtt = Convert.ToDecimal(Amount);
            string hashString = key + "|" + OrderId + "|" + Amount + "|" + "Recharge" + "|" + RetailerName + "|" + Email + "|||||||||||" + salt;
            //string hashString = "3Q5c3q|2590640|3053.00|OnlineBooking|vimallad|ladvimal@gmail.com|||||||||||mE2RxRwx";
            string hash = Generatehash512(hashString);
            RemotePost myremotepost = new RemotePost();
            // myremotepost.Url = "https://test.payu.in/_payment";
            myremotepost.Url = "https://secure.payu.in/_payment";
            myremotepost.Add("key", key);
            myremotepost.Add("txnid", OrderId);
            myremotepost.Add("amount", Amount.ToString());
            myremotepost.Add("productinfo", "Recharge");
            myremotepost.Add("firstname", RetailerName);
            myremotepost.Add("phone", reminfo.Mobile);
            myremotepost.Add("email", reminfo.Email);
            myremotepost.Add("surl", url);//Change the success url here depending upon the port number of your local system.
            myremotepost.Add("furl", url);//Change the failure url here depending upon the port number of your local system.
            myremotepost.Add("service_provider", "payu_paisa");
            myremotepost.Add("hash", hash);
            myremotepost.Post();
            return RedirectToAction("Index");
        }
        [HttpPost]
        public ActionResult viewbill(string OperatorName, string OptCode, string mobileno, string Amount, string optional1, string optional2, string optional3, string optional4)
        {
            try
            {
                var userid = User.Identity.GetUserId();
                if (OperatorName == "Bharti Axa Life Insurance")
                {
                    optional1 = DateTime.ParseExact(optional1, "dd-MM-yyyy", CultureInfo.InvariantCulture).ToString("yyyy-MM-dd");
                }
                //if (OperatorName.ToUpper().StartsWith("LIFE INSURANCE CORPORATION"))
                //{
                //    optional1 = db.Retailer_Details.Where(a => a.RetailerId == userid).Select(a => a.Email).SingleOrDefault();
                //}
                var responsemsg = "";
                var chk1 = db.SRS_API.Where(aa => aa.opt_code == OptCode && aa.api.ToUpper().Contains("ACENEOBANK.DEV") && aa.status == "Y").SingleOrDefault();
                if (chk1 != null)
                {
                    var optinfo = db.Operator_Code.Where(aa => aa.new_opt_code == OptCode).SingleOrDefault();
                    var resp = RadiantViewBill(optinfo.Operator_type, OptCode, mobileno, optional1, optional2, optional3);
                    responsemsg = JsonConvert.SerializeObject(resp);
                }
                else
                {
                    var chk = db.SRS_API.Where(aa => aa.opt_code == OptCode && aa.api.ToUpper().Contains("API.VASTBAZAAR.COM")).SingleOrDefault();

                    if (chk != null)
                    {
                        var api = chk.api;
                        if (api.ToUpper().Contains("API.VASTBAZAAR.COM"))
                        {
                            if (OptCode.ToUpper() == "EUH" || OptCode.ToUpper() == "EDH")
                            {
                                optional1 = "9999999999";
                            }
                            string CommonTranid = "E" + DateTime.Parse(DateTime.Now.ToString()).ToString("yyMMddHHmmss") + RandomString(4);
                            var apioptcode = db.SRS_API.Where(aa => aa.api.ToUpper().Contains("API.VASTBAZAAR.COM") && aa.opt_code == OptCode).SingleOrDefault().apioptcode;
                            var tokn = Responsetoken.gettoken();
                            Models.Vastbillpay vb = new Models.Vastbillpay();
                            var responsechk1 = vb.Viewbill(tokn, mobileno, apioptcode, Amount, optional1, optional2, CommonTranid);
                            var sts = responsechk1.StatusCode.ToString();
                            if (sts != "OK")
                            {
                                var data = new
                                {
                                    Message = "View Bill Response Error.",
                                    Response = "ERROR"
                                };
                                responsemsg = JsonConvert.SerializeObject(data);
                            }
                            else
                            {
                                var responsechk = responsechk1.Content.ToString();
                                dynamic json = JsonConvert.DeserializeObject(responsechk);
                                var respcode = json.Content.ResponseCode.ToString();
                                var ADDINFO = json.Content.ADDINFO.ToString();
                                dynamic json1 = JsonConvert.DeserializeObject(ADDINFO);
                                if (Convert.ToBoolean(json1.IsSuccess))
                                {
                                    if (json1.BillInfo.billAmount == null || json1.BillInfo.billAmount == "")
                                    {
                                        var des = JsonConvert.DeserializeObject<List<EBillInnerPrice>>(JsonConvert.SerializeObject(json1.BillInfo.displayValues));
                                        var Pricee = "";
                                        foreach (var item in des)
                                        {
                                            if (item.label == "Bill Amount")
                                            {
                                                Pricee = item.value;
                                            }
                                        }
                                        var dataInnerPrice = new
                                        {
                                            Response = "SUCCESS",
                                            Price = Pricee,
                                            DisplayValues = JsonConvert.SerializeObject(json1.BillInfo.displayValues)
                                        };
                                        responsemsg = JsonConvert.SerializeObject(dataInnerPrice);
                                    }
                                    else
                                    {
                                        var data = new
                                        {
                                            Response = "SUCCESS",
                                            Price = Convert.ToString(json1.BillInfo.billAmount),
                                            billduedate = Convert.ToString(json1.BillInfo.billDueDate),
                                            DisplayValues = JsonConvert.SerializeObject(json1.BillInfo.displayValues)
                                        };
                                        responsemsg = JsonConvert.SerializeObject(data);
                                    }
                                }
                                else if (json1.STATUS == "Failed")
                                {
                                    var opttype = db.Operator_Code.Where(a => a.new_opt_code == OptCode && a.status == "Y").SingleOrDefault();
                                    if (opttype != null)
                                    {
                                        if (opttype.Operator_type == "Broadband")
                                        {
                                            responsemsg = "{'Response':'SUCCESS','Type':'Broadband','Price':'" + Convert.ToString(json1.PRICE) + "','Message':'" + json1.ERRORMSG + "'}";
                                        }
                                        else if (opttype.Operator_type == "Water")
                                        {
                                            responsemsg = "{'Response':'SUCCESS','Type':'Water','Price':'" + Convert.ToString(json1.PRICE) + "','Message':'" + json1.ERRORMSG + "'}";
                                        }
                                        else if (opttype.Operator_type == "Insurance")
                                        {
                                            responsemsg = "{'Response':'SUCCESS','Type':'Insurance','Price':'" + Convert.ToString(json1.PRICE) + "','Message':'" + json1.ERRORMSG + "'}";
                                        }
                                        else
                                        {
                                            responsemsg = "{'Response':'SUCCESS','Type':'Gas','Price':'" + Convert.ToString(json1.PRICE) + "','Message':'" + json1.ERRORMSG + "'}";
                                        }
                                    }
                                    else
                                    {
                                        var data = new
                                        {
                                            Message = "Currently This Service Not Active.",
                                            Response = "ERROR"
                                        };
                                        responsemsg = JsonConvert.SerializeObject(data);
                                    }
                                    //var data = new
                                    //{
                                    //    Price = json1.PRICE,
                                    //    DisplayValues= json1.PRICE,
                                    //    Response = "SUCCESS"
                                    //};
                                    //responsemsg = JsonConvert.SerializeObject(data);
                                }
                                else if ((json1.Message == null) || (json1.Message == ""))
                                {
                                    var data = new
                                    {
                                        Message = "We are facing some issues on viewbill please wait or continue without viewbill.",
                                        Response = "ERROR"
                                    };
                                    responsemsg = JsonConvert.SerializeObject(data);
                                }
                                else
                                {
                                    var data = new
                                    {
                                        Message = json1["Message"],
                                        Response = "ERROR"
                                    };
                                    responsemsg = JsonConvert.SerializeObject(data);
                                }
                            }
                        }
                        else if(api.ToUpper().Contains("MOBIKWIK"))
                        {
                            string CommonTranid = "E" + DateTime.Parse(DateTime.Now.ToString()).ToString("yyMMddHHmmss") + RandomString(4);
                            var apioptcode = db.SRS_API.Where(aa => aa.api.ToUpper().Contains("MOBIKWIK") && aa.opt_code == OptCode).SingleOrDefault().apioptcode;
                            mobikwikRecharge vb = new mobikwikRecharge();
                            var responsechk1 = vb.Viewbill(mobileno, apioptcode, optional1, optional2);
                            if (responsechk1.StatusCode == HttpStatusCode.OK)
                            {
                                dynamic dyresp = JsonConvert.DeserializeObject(responsechk1.Content);
                                var apirespsts = dyresp.success;
                                if (apirespsts == true)
                                {
                                  var  CustomerName = dyresp.data.userName;
                                   var DueDate = dyresp.data.dueDate;
                                   var Amt = dyresp.data.billnetamount;
                                    var data = new
                                    {
                                        Response = "SUCCESS",
                                        Price = Convert.ToString(Amt),
                                        billduedate = Convert.ToString(DueDate),
                                        DisplayValues = JsonConvert.SerializeObject(CustomerName)
                                    };
                                    responsemsg = JsonConvert.SerializeObject(data);
