        public dynamic RadiantViewBill(string opttype, string optcode, string mobileno, string Optional1, string Optional2, string Optional3)
        {
            var userid = User.Identity.GetUserId();
            string filePath = Server.MapPath("~/Scripts/PageScript/Retailer/Radiantoptcode.json");
            // Read the JSON file
            string json = System.IO.File.ReadAllText(filePath);
            // Parse JSON data
            dynamic jsonObj = JsonConvert.DeserializeObject(json);
            dynamic jsonObj1 = jsonObj[opttype];
            string jsonoptlist = JsonConvert.SerializeObject(jsonObj1);
            List<dataradiantopt> electricityList = JsonConvert.DeserializeObject<List<dataradiantopt>>(jsonoptlist);
            var filteredData = electricityList.Where(x => x.Operator_code == optcode).ToList();
            var Response = "ERROR"; var msg = ""; var Price = ""; var billduedate = ""; var reference_id = ""; var custname = "";
            var radiantauthchk = db.radiantauths.SingleOrDefault();
            if (radiantauthchk != null)
            {
                var radiantresponse = db.rediantremtresponses.Where(aa => aa.userid == userid).SingleOrDefault();
                if (radiantresponse != null)
                {
                    if (radiantresponse.Sts == "Approved")
                    {
                        if (filteredData.Count > 0)
                        {
                            var billerid = filteredData[0].Radiant_code;
                            Radiantdmt radi = new Radiantdmt();
                            var tokenchk = db.radianttokens.SingleOrDefault();
                            if (tokenchk == null)
                            {
                                radi.Token(out radianttoken, out radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radiantresponse.username, radiantresponse.password);
                            }
                            else
                            {
                                radianttoken = tokenchk.accessToken;
                                radianagentid = tokenchk.agentID;
                            }
                            var respchk = radi.customerparamsAsync(radianagentid, radianttoken, radiantauthchk.clientID, radiantauthchk.clientSecret, billerid.ToString(), radiantauthchk.APIKey);
                            if (respchk.StatusCode == HttpStatusCode.NotAcceptable)
                            {
                                radi.Token(out radianttoken, out radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radiantresponse.username, radiantresponse.password);
                                respchk = radi.customerparamsAsync(radianagentid, radianttoken, radiantauthchk.clientID, radiantauthchk.clientSecret, billerid.ToString(), radiantauthchk.APIKey);
                            }
                            if (respchk.StatusCode == HttpStatusCode.OK)
                            {
                                dynamic dynamicrespchk = JsonConvert.DeserializeObject(respchk.Content);
                                var sts = dynamicrespchk.success;
                                if (sts == true)
                                {
                                    var jsonData = JsonConvert.SerializeObject(dynamicrespchk);
                                    JObject jsonObject = JObject.Parse(jsonData);
                                    // Extract parameter names
                                    JArray parameters = (JArray)jsonObject["param"];
                                    string[] parameterNames = new string[parameters.Count];
                                    for (int i = 0; i < parameters.Count; i++)
                                    {
                                        parameterNames[i] = (string)parameters[i]["name"];
                                    }
                                    var restt = "[" + string.Join(", ", parameterNames.Select(name => "\"" + name + "\"")) + "]";
                                    var respvalue = "";
                                    int countparameter = parameters.Count;
                                    if (countparameter == 1)
                                    {
                                        respvalue = "[\"" + mobileno + "\"]";
                                    }
                                    else if (countparameter == 2)
                                    {
                                        respvalue = "[\"" + Optional1 + "\",\"" + mobileno + "\"]";
                                    }
                                    else if (countparameter == 3)
                                    {
                                        respvalue = "[\"" + Optional2 + "\",\"" + Optional1 + "\",\"" + mobileno + "\"]";
                                    }
                                    else if (countparameter == 4)
                                    {
                                        respvalue = "[\"" + Optional3 + "\",\"" + Optional2 + "\",\"" + Optional1 + "\",\"" + mobileno + "\"]";
                                    }
                                    //   var respvalue = "[\"sikar\",\"654654654654\"]";
                                    var billfetchrespp = radi.BillFetch(radianagentid, radianttoken, radiantauthchk.clientID, radiantauthchk.clientSecret, "", billerid.ToString(), restt, respvalue, radiantauthchk.APIKey);
                                    if (billfetchrespp.StatusCode == HttpStatusCode.NotAcceptable)
                                    {
                                        radi.Token(out radianttoken, out radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radiantresponse.username, radiantresponse.password);
                                        radi.BillFetch(radianagentid, radianttoken, radiantauthchk.clientID, radiantauthchk.clientSecret, "", billerid.ToString(), restt, respvalue, radiantauthchk.APIKey);
                                    }
                                    if (billfetchrespp.StatusCode == HttpStatusCode.OK)
                                    {
                                        dynamic dynamicfetch = JsonConvert.DeserializeObject(billfetchrespp.Content);
                                        var fetchsts = dynamicfetch.success;
                                        if (fetchsts == true)
                                        {
                                            Price = dynamicfetch.amount;
                                            custname = dynamicfetch.custname;
                                            billduedate = dynamicfetch.dueDate;
                                            Response = "SUCCESS";
                                        }
                                        else
                                        {
                                            msg = dynamicrespchk.message;
                                        }
                                    }
                                    else
                                    {
                                        dynamic dynamicfetch = JsonConvert.DeserializeObject(billfetchrespp.Content);
                                        msg = dynamicfetch.message;
                                    }
                                }
                                else
                                {
                                    msg = dynamicrespchk.message;
                                    // Error Message 
                                }
                            }
                            else
                            {
                                dynamic dynamicrespchk = JsonConvert.DeserializeObject(respchk.Content);
                                msg = dynamicrespchk.message;
                                // Error Message 
                            }
                        }
                        else
                        {
                            msg = "Operator Not Found";
                            // Radiant Operator Not Found
                        }
                    }
                    else
                    {
                        msg = "EKYC is pending. Please wait for approval.";
                    }
                }
                else
                {
                    msg = "KYC not Done! Please go to your profile and Complete Ekyc Process.";
                }
            }
            else
            {
                msg = "Authentication is required! Please contact the administrator.";
            }
            var body = new
            {
                Response,
                Message = msg,
                Price,
                billduedate,
                reference_id,
                DisplayValues = "[{\"label\":\"Customer Name : \",\"value\":\"" + custname + "\"}]"

            };
            var bodyreq = JsonConvert.SerializeObject(body);
            dynamic respp = JsonConvert.DeserializeObject(bodyreq);
            return respp;
        }
