        public string View_Bill(string verifi, string code)
        {
            //var sts = "";
            //var traid = "";
            var checkverifiy = Verification(verifi, code);
            int start = checkverifiy.IndexOf("RESULT=") + 7;
            int end = checkverifiy.IndexOf("\r\n", start);
            string result = checkverifiy.Substring(start, end - start);
            start = checkverifiy.IndexOf("ERROR=") + 6;
            end = checkverifiy.IndexOf("\r\n", start);
            var errorcode = checkverifiy.Substring(start, end - start);
            var price = ""; var errormsg = "";
            if (result == "0")
            {
                if (checkverifiy.Contains("PRICE"))
                {
                    start = checkverifiy.IndexOf("PRICE=") + 6;
                    end = checkverifiy.IndexOf("\r\n", start);
                    price = checkverifiy.Substring(start, end - start);
                }
                if (result == "0" && errorcode == "0")
                {
                    int start2 = checkverifiy.IndexOf("TRANSID=") + 8;
                    int end2 = checkverifiy.IndexOf("\r\n", start2);
                    string transid = checkverifiy.Substring(start2, end2 - start2);
                    var dict = new Dictionary<string, string>
                                                                     {
                                                                       {"STATUS","Success"},
                                                                       {"PRICE", price},
                                                                       {"ERRORMSG", ""},
                                                                       {"TRANSID", transid},
                                                                       {"RESPONSE", checkverifiy}
                                                                     };
                    JavaScriptSerializer serializer = new JavaScriptSerializer();
                    return serializer.Serialize(dict);
                }
                else
                {
                    if (checkverifiy.Contains("ERRMSG"))
                    {
                        start = checkverifiy.IndexOf("ERRMSG=") + 7;
                        end = checkverifiy.IndexOf("\r\n", start);
                        errormsg = checkverifiy.Substring(start, end - start);
                    }
                    var dict = new Dictionary<string, string>
                                                                     {
                                                                       {"STATUS","Failed"},
                                                                       {"PRICE", price},
                                                                       {"ERRORMSG", errormsg},
                                                                       {"TRANSID", ""},
                                                                       {"RESPONSE", checkverifiy}
                                                                     };
                    JavaScriptSerializer serializer = new JavaScriptSerializer();
                    return serializer.Serialize(dict);
                }
            }
            else
            {
                if (checkverifiy.Contains("PRICE"))
                {
                    start = checkverifiy.IndexOf("PRICE=") + 6;
                    end = checkverifiy.IndexOf("\r\n", start);
                    price = checkverifiy.Substring(start, end - start);
                }
                if (checkverifiy.Contains("ERRMSG"))
                {
                    start = checkverifiy.IndexOf("ERRMSG=") + 7;
                    end = checkverifiy.IndexOf("\r\n", start);
                    errormsg = checkverifiy.Substring(start, end - start);
                }
                var dict = new Dictionary<string, string>
                                                                     {
                                                                       {"STATUS","Failed"},
                                                                       {"PRICE", price},
                                                                       {"ERRORMSG", errormsg},
                                                                       {"TRANSID", ""},
                                                                       {"RESPONSE", checkverifiy}
                                                                     };
                JavaScriptSerializer serializer = new JavaScriptSerializer();
                return serializer.Serialize(dict);
            }
        }
        private string Verification(String txtRequest, String code)
        {
            var response = "";
            var urlverify = "https://in.cyberplat.com/cgi-bin/bu/bu_pay_check.cgi/";
            var txtURL = urlverify + code;
            try
            {
                var password = "Abhijeet@12345";
                string pathchk = System.Web.Hosting.HostingEnvironment.MapPath("~/CERT/");
                string keyPath = pathchk + "mycertprivatekey.pfx";
                //keyPath = keyPath.Replace("\\TryMyEWallet", "");
                ssl.message = ssl.Sign_With_PFX(txtRequest, keyPath, password);
                ssl.htmlText = ssl.CallCryptoAPI(ssl.message, txtURL);
                response = "URL:\r\n" + txtURL + "\r\n\r\n" + "Request:\r\n" + ssl.message + "\r\n\r\nResponse:\r\n" + ssl.htmlText;
            }
            catch (Exception epx)
            {
                response = epx.ToString();
            }
            return response;
        }
