        [HttpPost]
        public ActionResult PrintSize_Slip_SettingSave(string[] ch)
        {
            try
            {
                var userid = User.Identity.GetUserId();
                foreach (string item in ch)
                {
                    var groupname1 = item.Split(',');
                    var name = groupname1[0].ToString();
                    var Status = groupname1[1].ToString();
                    Printer_paperSize_Changes obj = (from pp in db.Printer_paperSize_Changes
                                                     where pp.Print_Name == name && pp.Userid == userid
                                                     select pp).SingleOrDefault();
                    if (obj == null)
                    {
                        obj = new Printer_paperSize_Changes();
                        obj.Print_Name = name;
                        obj.status = Status;
                        obj.Userid = userid;
                        db.Printer_paperSize_Changes.Add(obj);
                    }
                    else
                    {
                        obj.status = Status;
                    }
                    db.SaveChanges();
                }
                return Json(new { status = true });
            }
            catch (Exception ex)
            {
                return Json(new { status = false, Message = ex.Message });
            }
        }
