        [HttpPost]
        public PartialViewResult FundTranferAllReportwithpart(string ddlfundTransfer, string ddlHeadType, string txt_frm_date, string txt_to_date)
        {
            string userid = User.Identity.GetUserId();
            //  DateTime frm = Convert.ToDateTime(DateTime.Now);
            //  DateTime to = Convert.ToDateTime(frm.AddDays(1));
            int pagesize = 50;
            DateTime frm = Convert.ToDateTime(txt_frm_date);
            DateTime to = Convert.ToDateTime(txt_to_date);
            txt_frm_date = frm.ToString("dd-MM-yyyy");
            txt_to_date = to.ToString("dd-MM-yyyy");
            string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy",
                        "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
            DateTime dt = !string.IsNullOrWhiteSpace(txt_frm_date) ? DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
            DateTime dt1 = !string.IsNullOrWhiteSpace(txt_to_date) ? DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
            DateTime frm_date = Convert.ToDateTime(dt).Date;
            DateTime to_date = Convert.ToDateTime(dt1).Date.AddDays(1);
            var result = db.fundTransferALLReports(pagesize, 1, frm_date, to_date, userid).ToList();
            if (ddlfundTransfer != "All")
            {
                result = result.Where(a => a.Role.ToLower() == ddlfundTransfer.ToLower()).ToList();
            }
            if (ddlHeadType == "Direct")
            {
                result = result.Where(a => a.Head == null || a.Head == "Direct").ToList();
            }
            else if (ddlHeadType == "FundReq" || ddlHeadType == "GetWay")
            {
                result = result.Where(a => a.Head == ddlHeadType).ToList();
            }
            TempData["res"] = result;
            return PartialView("_FundTransferReports", result);
        }
