                //{
                //    TempData["error"] = "This User Not Exist";
                //    return RedirectToAction("Retailer_to_retailer");
                //}
                var pin = Encrypt(txtRetailerdmtpin);
                var pin_check = (from pi in db.Retailer_Details where pi.RetailerId == userid select pi).Single().PIN;
                var chkstsotp = db.dmtpin_otp_status.SingleOrDefault();
                if (chkstsotp != null)
                {
                    if (chkstsotp.status == true)
                    {
                        var mobileotplist = db.MobileOtps.Where(a => a.Userid == userid && a.Type == "R2RPINOTP").OrderByDescending(a => a.Date).ToList();
                        var mobileotp = mobileotplist.FirstOrDefault();
                        if (mobileotp == null)
                        {
                            return Json("OTP Error!!! Please Generate New OTP!!!", JsonRequestBehavior.AllowGet);
                        }
                        var last5minute = DateTime.Now.AddMinutes(-5);
