                        {
                            if (mobileotp.Otp == txtRetailerdmtpin)
                            {
                                stspinotp = "OK";
                                db.MobileOtps.RemoveRange(mobileotplist);
                                db.SaveChanges();
                            }
                            else
                            {
                                return Json("Wrong OTP!!! Please Enter Correct OTP!!!", JsonRequestBehavior.AllowGet);
                            }
                        }
                        else
