                            {
                                int idval = db.Rem_to_rem_fund_transfer.Where(aa => aa.rem_from == userid).OrderByDescending(aa => aa.idno).Select(c => c.idno).FirstOrDefault();
                                var rchinforsss = db.Rem_to_rem_fund_transfer.Where(x => x.idno == idval).FirstOrDefault();
                                if (rchinforsss != null)
                                {
                                    rchinforsss.Devicetoken = null;
                                    rchinforsss.Latitude = latss;
                                    rchinforsss.Longitude = longloc;
                                    rchinforsss.ModelNo = null;
                                    rchinforsss.City = city;
                                    rchinforsss.PostalCode = null;
                                    rchinforsss.InternetTYPE = null;
                                    rchinforsss.IPaddress = externalip;
                                    rchinforsss.Address = address;
                                    db.SaveChanges();
                                }
                                smssend.sms_init(statusSendSmsREMToREMFundTransferRetailer.Status, statusSendSmsREMToREMFundTransferRetailer.Whatsapp_Status, "RETAILERTORETAILERFROMFUNDTRANSFER", RetailerDetails.Mobile, Retaileramount, useremail, remainbalretailer);
                                smssend.sms_init(statusSendSmsREMToREMFundTransfer.Status, statusSendSmsREMToREMFundTransfer.Whatsapp_Status, "RETAILERTORETAILERTOFUNDTRANSFER", RetailerDetails.Mobile, retaileremaillid, Retaileramount, remainbal);
                                if (statusSendMailREMToREMFundTransferRetailer == "Y")
                                {
                                    smssend.SendEmailAll(RetailerMobileRetailerDetails.Email, "Balance " + Retaileramount + " Transfer to " + useremail + " is Successfully Transfer. Remain Balance is " + remainbalretailer + "", "Fund Transfer", AdminEmail, 1000);
                                }
                                if (statusSendMailREMToREMFundTransfer == "Y")
                                {
                                    smssend.SendEmailAll(RetailerDetails.Email, "Balance Transfer Successfully To Retailer Id is " + retaileremaillid + " and Balance is " + Retaileramount + ", Remain Balance is " + remainbal + "", "Fund Transfer", AdminEmail, 1000);
                                }
                            }
                            else
                            {
                                TempData["error"] = ch;
                            }
                        }
                        else
                        {
                            return Json("Your Previous Request IN Process Please Try After SomeTime", JsonRequestBehavior.AllowGet);
                        }
                        return Json(ch, JsonRequestBehavior.AllowGet);
                    }
                    catch (Exception ex)
                    {
                        return Json(ex.Message, JsonRequestBehavior.AllowGet);
                    }
                }
                else
                {
                    return Json("Error!!! Please try after sometime!!!", JsonRequestBehavior.AllowGet);
                }
            }
            catch
            {
                return Json("Something went wromg.Please try again.", JsonRequestBehavior.AllowGet);
            }
        }
        public ActionResult Fundtransferfilter(string txt_frm_date = "", string txt_to_date = "", string ddtrnsfrom = "")
        {
            RetailerFundRequestViewmodel vmodel = new RetailerFundRequestViewmodel();
            DateTime fromdate;
            DateTime Todate;
            if (string.IsNullOrEmpty(txt_frm_date) && string.IsNullOrEmpty(txt_to_date))
            {
                fromdate = DateTime.Now.AddDays(-1);
                Todate = DateTime.Now.AddDays(1);
            }
            else
            {
                string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy",
                            "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
                DateTime dt = !string.IsNullOrWhiteSpace(txt_frm_date) ? DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
                DateTime dt1 = !string.IsNullOrWhiteSpace(txt_to_date) ? DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
                fromdate = Convert.ToDateTime(dt).Date;
                Todate = Convert.ToDateTime(dt1).Date.AddDays(1);
            }
            string userid = User.Identity.GetUserId();
            vmodel.ShowRem_to_Rem = db.show_rem_to_rem_bal(userid, "ALL", fromdate, Todate).ToList();
