            {
                vmodel.ShowRem_to_Rem = vmodel.ShowRem_to_Rem.Where(x => x.transfertofrmname.ToLower().StartsWith(ddtrnsfrom.ToLower()));
            }
            return PartialView("_Purchase_OrderReports", vmodel);
        }
