                string dealerid = db.Retailer_Details.Where(a => a.RetailerId == userid).Select(x => x.DealerId).FirstOrDefault();
                //My Credit Bal to Dealer
                var diff1 = db.total_count_Retailer_outstanding_by_dealer(userid).FirstOrDefault().totaloutstanding;
                var accunt1 = (from acc in db.bank_info.Where(a => a.userid == dealerid) select new { acno = acc.acno, acnooo = acc.banknm });
                var bank = new SelectList(accunt1, "acno", "acnooo", null);
