        [HttpGet]
        public ActionResult Bank_info()
        {
            var userid = User.Identity.GetUserId();
            var dealerid = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault().DealerId;
            var adminlist = db.creditchargeretailers.Where(aa => aa.userid == userid && aa.chargefrom == "Admin").ToList();
            var dealerlist = db.creditchargeretailers.Where(aa => aa.userid == userid && aa.chargefrom == dealerid).ToList();
            var admincash = adminlist.Where(aa => aa.type == "Cash").SingleOrDefault();
            var admincredit = adminlist.Where(aa => aa.type == "Credit").SingleOrDefault();
            var dealercash = dealerlist.Where(aa => aa.type == "Cash").SingleOrDefault();
            var dealercredit = dealerlist.Where(aa => aa.type == "Credit").SingleOrDefault();
            if (admincash == null)
            {
                ViewBag.admincash = 0;
            }
            else
            {
                ViewBag.admincash = admincash.charge;
            }
            if (admincredit == null)
            {
                ViewBag.admincredit = 0;
            }
            else
            {
                ViewBag.admincredit = admincredit.charge;
            }
            if (dealercash == null)
            {
                ViewBag.dealercash = 0;
            }
            else
            {
                ViewBag.dealercash = dealercash.charge;
            }
            if (dealercredit == null)
            {
                ViewBag.dealercredit = 0;
            }
            else
            {
                ViewBag.dealercredit = dealercredit.charge;
            }
            BankInfo bank = new BankInfo();
            bank.adminbank = db.bank_info.Where(aa => aa.userid == "Admin").ToList();
            bank.Dealerbank = db.bank_info.Where(aa => aa.userid == dealerid).ToList();
            bank.Dealerbank = db.bank_info.Where(aa => aa.userid == dealerid).ToList();
            bank.Walletinfoadmin = db.tblwallet_info.Where(aa => aa.userid == "Admin").ToList();
            bank.Walletinfodealer = db.tblwallet_info.Where(aa => aa.userid == dealerid).ToList();
            return View(bank);
        }
        public ActionResult Operator_info()
        {
            var userid = User.Identity.GetUserId();
            var dealerid = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
            var masterid = db.Dealer_Details.Where(aa => aa.DealerId == dealerid.DealerId).SingleOrDefault();
            Operater_Commission sb = new Operater_Commission();
            sb.AmountRange = (from p in db.Recharge_Amount_range
                              select new Recharge_Amount_range_info
                              {
                                  idno = p.idno,
                                  maximum1 = p.maximum1,
                                  maximum2 = p.maximum2
                              }).ToList();
            var info = db.Master_allow_commission.Where(aa => aa.masterid == masterid.SSId).SingleOrDefault().allowcommision;
            if (info == false)
            {
                sb.Prepaid = (from cust in db.prepaid_retailer_comm
                              join ord in db.Operator_Code
                              on cust.optcode equals ord.Operator_id.ToString()
                              where (cust.userid == userid)
                              select new Prepaid_Comm
                              {
                                  OperatorCode = ord.new_opt_code,
                                  Commission = cust.comm,
                                  Commission1 = cust.comm1,
                                  Commission2 = cust.comm2,
                                  BlockTime = ord.blocktime,
                                  Status = ord.status,
                                  OperatorType = ord.Operator_type,
                                  OperatorName = ord.operator_Name
                              }).OrderBy(aa => aa.OperatorName).ToList();
            }
            else
            {
                sb.Prepaid = (from cust in db.prepaid_retailer_comm_by_dealer.Where(aa => aa.dealerid == dealerid.DealerId)
                              join ord in db.Operator_Code
                              on cust.optcode equals ord.Operator_id.ToString()
                              where (cust.userid == userid)
                              select new Prepaid_Comm
                              {
                                  OperatorCode = ord.new_opt_code,
                                  Commission = cust.comm,
                                  Commission1 = cust.comm1,
                                  Commission2 = cust.comm2,
                                  BlockTime = ord.blocktime,
                                  Status = ord.status,
                                  OperatorType = ord.Operator_type,
                                  OperatorName = ord.operator_Name
                              }).OrderBy(aa => aa.OperatorName).ToList();
            }
            sb.microatmcash = (from cust in db.mtm_Comm_User_Wise
                               where (cust.Userid == userid)
                               select new MicroAtmCash_comm
                               {
                                   cash_0_1000_per = cust.cash_0_1000_per,
                                   cash_1001_2000_per = cust.cash_1001_2000_per,
                                   cash_0_1000_rs = cust.cash_0_1000_rs,
                                   cash_1001_2000_rs = cust.cash_1001_2000_rs,
                                   cash_0_1000_maxrs = cust.cash_0_1000_maxrs,
                                   cash_1001_2000_maxrs = cust.cash_1001_2000_maxrs,
                                   cash_0_1000_Type = cust.cash_0_1000_Type,
                                   cash_1001_2000_Type = cust.cash_1001_2000_Type,
