        public virtual ActionResult ExcelRechargereport(DateTime txt_frm_date, DateTime txt_to_date, string ddl_status, string Operator, string txtmob)
        {
            txt_to_date = txt_to_date.AddDays(1);
            DataTable dt = new DataTable();
            dt.Columns.Add("Status", typeof(string));
            dt.Columns.Add("Recharge No", typeof(string));
            dt.Columns.Add("Operator", typeof(string));
            dt.Columns.Add("Opt Type", typeof(string));
            dt.Columns.Add("Rch Amt", typeof(string));
            dt.Columns.Add("Debit/Credit", typeof(string));
            dt.Columns.Add("Income", typeof(string));
            dt.Columns.Add("Remain Pre", typeof(string));
            dt.Columns.Add("Remainv Pos", typeof(string));
            dt.Columns.Add("Type", typeof(string));
            dt.Columns.Add("Rch Date", typeof(string));
            dt.Columns.Add("Operator ID", typeof(string));
            dt.Columns.Add("Resp Date", typeof(string));
            dt.Columns.Add("Bill Due Date", typeof(string));
            dt.Columns.Add("Circle", typeof(string));
            string userid = User.Identity.GetUserId();
            var respo = db.Sp_Recharge_info_LazyLoad(1, 10000000, "Retailer", userid, txt_frm_date, txt_to_date, Operator, txtmob, ddl_status).ToList();
            if (respo.Count > 0)
            {
                foreach (var item in respo)
                {
                    DateTime Rch_time = Convert.ToDateTime(item.Rch_time);
                    Rch_time.ToString("d-MMM-yyyy HH:mm:ss");
                    dynamic Resp_time = "";
                    if (item.Resp_time != null)
                    {
                        Resp_time = Convert.ToDateTime(item.Resp_time);
                        Resp_time.ToString("d-MMM-yyyy HH:mm:ss");
                    }
                    else
                    {
                        Resp_time = item.Resp_time;
                    }
                    var sts = item.Rstaus;
                    if (item.Rstaus.ToUpper().Contains("REQ"))
                    {
                        sts = "Pending";
                    }
                    var amt = item.amount;
                    var amtde = item.income;
                    decimal? amtdec = 0;
                    if (sts.ToUpper().Contains("REFUND"))
                    {
                        amtdec = amt - amtde;
                        amtdec = +amtdec;
                    }
                    else
                    {
                        amtdec = amt - amtde;
                        amtdec = -amtdec;
                    }
                    dt.Rows.Add(sts, item.Mobile, item.operator_Name, item.Operator_type, item.amount, amtdec,
                        item.income, item.user_remain_pre, item.Remain,
                    item.rch_type, Rch_time, item.OPt_id, Resp_time, item.BillDueDate, item.Circle);
                }
            }
            else
            {
                dt.Rows.Add("", "", "", "", "", "", "", "", "", "", "", "", "", "");
            }
            var grid = new GridView();
            grid.DataSource = dt;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=RCH_Report.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();
            return View();
        }
