        public JsonResult FindCurrentTotal(string txt_frm_date, string txt_to_date, string ddl_status, string ddl_Type)
        {
            using (VastwebmultiEntities db = new VastwebmultiEntities())
            {
                if (txt_frm_date == null && txt_to_date == null && ddl_status == null)
                {
                    txt_frm_date = DateTime.Now.ToString();
                    txt_to_date = DateTime.Now.ToString();
                    ddl_status = "ALL";
                }
                if (ddl_status == "Status")
                {
                    ddl_status = "ALL";
                }
                if (ddl_Type == null || ddl_Type == "")
                {
                    ddl_Type = "ALL";
                }
                DateTime frm1 = Convert.ToDateTime(txt_frm_date);
                DateTime to1 = Convert.ToDateTime(txt_to_date);
                txt_frm_date = frm1.ToString("dd-MM-yyyy");
                txt_to_date = to1.ToString("dd-MM-yyyy");
                string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy", "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
                DateTime dt = DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
                DateTime dt1 = DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
                DateTime frm_date = dt.Date;
                DateTime to_date = dt1.AddDays(1);
                var userid = User.Identity.GetUserId();
                ddl_status = string.IsNullOrWhiteSpace(ddl_status) ? null : ddl_status;
                int pagesize = 5000;
                var proc_Response = db.money_transfer_report_paging("Retailer", userid, ddl_status, "ALL", Convert.ToDateTime(frm_date), Convert.ToDateTime(to_date), ddl_Type, 1, pagesize).ToList();
                var totalsuccess = proc_Response.Where(x => x.status == "SUCCESS").Sum(x => x.amount);
                var totalfailed = proc_Response.Where(x => x.status == "FAILED").Sum(x => x.amount);
                var totalPending = proc_Response.Where(x => x.status == "Pending").Sum(x => x.amount);
                return Json(new { success = totalsuccess, failed = totalfailed, pending = totalPending }, JsonRequestBehavior.AllowGet);
            }
        }
        public ActionResult PaysprintRefundOTP(string txnid)
        {

            VastBazaar cb = new VastBazaar();
            var responsechk = "";
            var responsecode1 = "";
            var tokn = Responsetoken.gettoken();
            var responseall = cb.Paysprint_RefundOTP(tokn, txnid);
            responsechk = responseall.Content.ToString();
            responsecode1 = responseall.StatusCode.ToString();
            if (responsecode1 == "OK")
            {
                dynamic json = JsonConvert.DeserializeObject(responsechk);
                var respcode = json.Content.ADDINFO.response_code.ToString();
                if (respcode == "1")
                {
                    var ADDINFO = json.Content.ADDINFO;
                    var results = JsonConvert.SerializeObject(ADDINFO);
                    var jss = new JavaScriptSerializer();
                    var dict = jss.Deserialize<dynamic>(results);
                    return Json(dict, JsonRequestBehavior.AllowGet);
                }
                else
                {
                    var error = json.Content.ADDINFO.message.ToString();
                    var error_decribe = false;
                    var results = "{'status':'" + error_decribe + "','message':'" + error + "','response_code':'" + respcode + "'}";
                    var jss = new JavaScriptSerializer();
                    var dict = jss.Deserialize<dynamic>(results);
                    return Json(dict, JsonRequestBehavior.AllowGet);
                }
            }
            else
            {
                dynamic json = JsonConvert.DeserializeObject(responsechk);
                var error = json.error.ToString();
                var error_decribe = false;
                var results = "{'status':'" + error_decribe + "','message':'Please Try After Sometime','response_code':'40'}";
                var jss = new JavaScriptSerializer();
                var dict = jss.Deserialize<dynamic>(results);
                return Json(dict, JsonRequestBehavior.AllowGet);
            }
        }
