        public ActionResult Excel_Money_Transfer_Report(string txt_frm_date, string txt_to_date, string ddl_status, string ddl_Type, string txtnumberfind)
        {
            DateTime frm1 = Convert.ToDateTime(txt_frm_date);
            DateTime to1 = Convert.ToDateTime(txt_to_date);
            txt_frm_date = frm1.ToString("dd-MM-yyyy");
            txt_to_date = to1.ToString("dd-MM-yyyy");
            string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy", "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
            DateTime dt = DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
            DateTime dt1 = DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
            DateTime frm_date = dt.Date;
            DateTime to_date = dt1.AddDays(1);
            var userid = User.Identity.GetUserId();
            #region Auto credit transfer Calling
            CallAutofundtransfer(userid);
            #endregion calling
            ddl_status = string.IsNullOrWhiteSpace(ddl_status) ? null : ddl_status;
            int pagesize = 5000;
            var proc_Response = db.money_transfer_report_paging("Retailer", userid, ddl_status, "ALL", Convert.ToDateTime(frm_date), Convert.ToDateTime(to_date), ddl_Type, 1, pagesize).ToList();
            DataTable dataTbl = new DataTable();
            dataTbl.Columns.Add("Status", typeof(string));
            dataTbl.Columns.Add("Sender No", typeof(string));
            dataTbl.Columns.Add("Beneficiary A/C", typeof(string));
            dataTbl.Columns.Add("Beneficiary Name", typeof(string));
            dataTbl.Columns.Add("Net T/F ", typeof(string));
            dataTbl.Columns.Add("Charge", typeof(string));
            //dataTbl.Columns.Add("Tax", typeof(string));
            dataTbl.Columns.Add("Debit", typeof(string));
            dataTbl.Columns.Add("Pre ", typeof(string));
            dataTbl.Columns.Add("Post", typeof(string));
            //dataTbl.Columns.Add("Earn", typeof(string));
            dataTbl.Columns.Add("Request Time", typeof(string));
            dataTbl.Columns.Add("Response Time ", typeof(string));
            dataTbl.Columns.Add("RRN (utr) No", typeof(string));
            if (proc_Response.Any())
            {
                foreach (var item in proc_Response)
                {
                    var sts = item.status;
                    if (item.status.ToUpper().Contains("PENDING"))
                    {
                        double difftime = DateTime.Now.Subtract(item.trans_time.Value).TotalMinutes;
                        if (difftime < 2)
                        {
                            sts = "In Process";
                        }
                    }
                    decimal amount = 0;
                    decimal customerfee = 0;
                    decimal total = 0;
                    decimal debit = 0;
                    decimal remcomm = 0;
                    if (item.Trans_type.Contains("IMPS_VERIFY"))
                    {
                        amount = Convert.ToDecimal(item.amount);
                        customerfee = Convert.ToDecimal(item.rem_comm);
                        customerfee = customerfee - amount;
                        total = amount + customerfee;
                        debit = Convert.ToDecimal(item.rem_comm);
                    }
                    else
                    {
                        amount = Convert.ToDecimal(item.amount);
                        customerfee = Convert.ToDecimal(item.customer_fee);
                        total = amount + customerfee;
                        remcomm = Convert.ToDecimal(item.rem_comm);
                        debit = amount + remcomm;
                    }
                    dataTbl.Rows.Add(sts, item.senderno, item.accountno, item.recivername, item.amount, item.rem_comm_include_gst, debit, item.user_remain_pre, item.user_remain, item.trans_time, item.response_time, item.bank_trans_id);
                }
            }
            else
            {
                dataTbl.Rows.Add("", "", "", "", "", "", "", "", "", "", "", "");
            }
            var grid = new GridView();
            grid.DataSource = dataTbl;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=Excel_Money_Transfer_Report.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();
            return View();
        }
        [HttpPost]
        public ActionResult InfiniteScroll_money(int pageindex, string txt_frm_date, string txt_to_date, string ddl_status, string ddl_Type, string txtnumberfind)
        {
            string userid = User.Identity.GetUserId();
            System.Threading.Thread.Sleep(1000);
            int pagesize = 50;
            if (ddl_status == "Status")
            {
                ddl_status = "ALL";
            }
            if (ddl_Type == null || ddl_Type == "")
            {
                ddl_Type = "ALL";
            }
            ViewBag.checkdata = null;
            var checkdata = db.IMPS_transtion_detsils_old.Where(a => a.rch_from == userid).FirstOrDefault();
            if (checkdata != null)
            {
                ViewBag.checkdata = "Data";
            }
            else
            {
                var checkdata1 = db.IMPS_transtion_detsils.Where(a => a.rch_from == userid).FirstOrDefault();
                if (checkdata1 != null)
                {
                    ViewBag.checkdata = "Data";
                }
            }
            var tbrow = db.money_transfer_report_paging("Retailer", userid, ddl_status, "ALL", Convert.ToDateTime(txt_frm_date), Convert.ToDateTime(txt_to_date), ddl_Type, pageindex, pagesize).ToList();
            if (!string.IsNullOrEmpty(txtnumberfind))
            {
                tbrow = tbrow.Where(x => x.senderno == txtnumberfind || x.accountno == txtnumberfind).ToList();
            }
            JsonModel jsonmodel = new JsonModel();
            jsonmodel.NoMoredata = tbrow.Count < pagesize;
            if (tbrow.Any())
            {
                jsonmodel.HTMLString = renderPartialViewtostring("_Money_Transfer_Report", tbrow);
            }
            else
            {
                jsonmodel.HTMLString = "";
            }
            return Json(jsonmodel);
        }
