        public ActionResult ClearallMTM(DateTime fromdate, DateTime todate)
        {
            var token = string.Empty;
            token = getAuthToken();
            todate = todate.AddDays(1);
            var userid = User.Identity.GetUserId();
            var clientinfochk = db.MicroAtm_Trans_info.Where(aa => aa.status == "Pending" && aa.retailerid == userid && aa.transtime >= fromdate && aa.transtime <= todate).ToList();
            foreach (var item in clientinfochk)
            {
                try
                {
                    string reqid = item.Requestid;
                    var client = new RestClient("http://api.vastbazaar.com/api/MicroATM/StatusCheck?uniqueid=" + reqid + "");
                    var request = new RestRequest(Method.POST);
                    request.AddHeader("Authorization", "Bearer " + token);
                    IRestResponse response = client.Execute(request);
                    var resp = response.Content;
                    dynamic respchk = JsonConvert.DeserializeObject(resp);
                    string transaction_id = respchk.Content.ADDINFO.transaction_id;
                    string rrn = respchk.Content.ADDINFO.rrn;
                    string status = respchk.Content.ADDINFO.status;
                    DateTime created_at = respchk.Content.ADDINFO.created_at;
                    string merchant_id = respchk.Content.ADDINFO.merchant_id;
                    string transaction_type = respchk.Content.ADDINFO.transaction_type;
                    string tid = respchk.Content.ADDINFO.tid;
                    string payment_method = respchk.Content.ADDINFO.payment_method;
                    decimal amount = respchk.Content.ADDINFO.amount;
                    string card_payment_type = respchk.Content.ADDINFO.card_payment_type;
                    string card_usage_type = respchk.Content.ADDINFO.card_usage_type;
                    string masked_pan = respchk.Content.ADDINFO.masked_pan;
                    string response_description = respchk.Content.ADDINFO.response_description;
                    string aggregator_id = respchk.Content.ADDINFO.aggregator_id;
                    string network = respchk.Content.ADDINFO.network;
                    System.Data.Entity.Core.Objects.ObjectParameter output = new
                System.Data.Entity.Core.Objects.ObjectParameter("Output", typeof(string));
                    db.updatemicroatm(reqid, transaction_id, rrn, status, created_at, merchant_id, transaction_type, tid, payment_method, amount, card_payment_type, card_usage_type, masked_pan, response_description, aggregator_id, network, resp, output);
                    try
                    {
                        var retailerdetails = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
                        var dealerdetails = db.Dealer_Details.Where(aa => aa.DealerId == retailerdetails.DealerId).SingleOrDefault();
                        var masterdetails = db.Superstokist_details.Where(aa => aa.SSId == dealerdetails.SSId).SingleOrDefault();

                        var remdetails = db.Remain_reteller_balance.Where(aa => aa.RetellerId == userid).SingleOrDefault();
                        var dlmdetails = db.Remain_dealer_balance.Where(aa => aa.DealerID == retailerdetails.DealerId).SingleOrDefault();
                        var Masterdetails = db.Remain_superstokist_balance.Where(aa => aa.SuperStokistID == dealerdetails.SSId).SingleOrDefault();

                        var admininfo = db.Admin_details.SingleOrDefault();
                        Backupinfo back = new Backupinfo();
                        var model = new Backupinfo.Addinfo
                        {
                            Websitename = admininfo.WebsiteUrl,
                            RetailerID = userid,
                            Email = retailerdetails.Email,
                            Mobile = retailerdetails.Mobile,
                            Details = "Microatm ",
                            RemainBalance = (decimal)remdetails.Remainamount,
                            Usertype = "Retailer"
                        };
                        back.Microatm(model);

                        var model1 = new Backupinfo.Addinfo
                        {
                            Websitename = admininfo.WebsiteUrl,
                            RetailerID = dealerdetails.DealerId,
                            Email = dealerdetails.Email,
                            Mobile = dealerdetails.Mobile,
                            Details = "Microatm ",
                            RemainBalance = Convert.ToDecimal(dlmdetails.Remainamount),
                            Usertype = "Dealer"
                        };
                        back.Microatm(model1);

                        var model2 = new Backupinfo.Addinfo
                        {
                            Websitename = admininfo.WebsiteUrl,
                            RetailerID = masterdetails.SSId,
                            Email = masterdetails.Email,
                            Mobile = masterdetails.Mobile,
                            Details = "Microatm ",
                            RemainBalance = Convert.ToDecimal(Masterdetails.Remainamount),
                            Usertype = "Master"
                        };
                        back.Microatm(model2);
                    }
                    catch { }

                }
                catch { }
            }
            return Json("", JsonRequestBehavior.AllowGet);
        }
        public ActionResult MicroAtmslip(int? idno = 0)
        {
            try
            {
                var userid = User.Identity.GetUserId();
                var info = db.MicroAtm_Trans_info.Where(aa => aa.idno == idno).SingleOrDefault();
                if (info != null)
                {
                    if (userid == info.retailerid)
                    {
                        var userinfo = db.Retailer_Details.Where(aa => aa.RetailerId == info.retailerid).SingleOrDefault();
                        ViewBag.firmname = userinfo.Frm_Name;
                        ViewBag.address = userinfo.Address;
                        ViewBag.mobile = userinfo.Mobile;
                        ViewBag.email = userinfo.Email;
                        ViewBag.transfdate = Convert.ToDateTime(info.transtime).ToString("yyyy-MM-dd");
                        ViewBag.transftime = Convert.ToDateTime(info.transtime).ToString("HH:mm:ss");
                        ViewBag.invoiceno = idno;
                        ViewBag.type = info.transaction_type;
                        ViewBag.cardpaymenttype = info.card_payment_type;
                        ViewBag.status = info.status.ToUpper();
                        ViewBag.cardnumber = info.masked_pan;
                        ViewBag.network = info.network;
                        ViewBag.rrn = info.rrn;
                        ViewBag.amount = info.amount;
                        ViewBag.websitename = db.Admin_details.SingleOrDefault().WebsiteUrl;
                        ViewBag.cusomercare = db.Admin_details.SingleOrDefault().mobile1;
                        ViewBag.logo = db.tblHeaderLogoes.Where(aa => aa.Role == "ADMIN").SingleOrDefault().LogoImage;
                    }
                    else
                    {
                        ViewBag.notfound = "OK";
                    }
                }
                else
                {
                    ViewBag.notfound = "OK";
                }
            }
            catch (Exception ex)
            {
                ViewBag.notfound = "OK";
            }
            return new ViewAsPdf();
            // return new ViewAsPdf("MicroAtmslip");
        }
