                totalconvencefees = 0;
            }
            // var totalamount = netsurchargefees + tranamount + customer_fee_gst + totalconvencefees;
            //var totalamount = netservicefees + tranamount + customer_fee_gst + totalconvencefees;
            var totalamount = netservicefees + tranamount + totalconvencefees;
