        public ActionResult ExcelRetailerposreport(DateTime txt_frm_date, DateTime txt_to_date)
        {
            ViewBag.chk = "post";
            var userid = User.Identity.GetUserId();
            DateTime to = txt_to_date.AddDays(1);
            var ch = db.pos_ledger_report(userid, txt_frm_date, to).ToList();
            DataTable dataTbl = new DataTable();
            dataTbl.Columns.Add("Details", typeof(string));
            dataTbl.Columns.Add("Amount", typeof(string));
            dataTbl.Columns.Add("Remain POS Bal Pre", typeof(string));
            dataTbl.Columns.Add("Remain POS Bal Post", typeof(string));
            dataTbl.Columns.Add("Transaction Date", typeof(string));
            dataTbl.Columns.Add("Credit", typeof(string));
            dataTbl.Columns.Add("Debit", typeof(string));
            dataTbl.Columns.Add("Comm", typeof(string));
            dataTbl.Columns.Add("GST", typeof(string));
            dataTbl.Columns.Add("TDS", typeof(string));
            if (ch.Count > 0)
            {
                decimal? totalamt = 0;
                decimal? totalcr = 0;
                decimal? totaldr = 0;
                decimal? totalcomm = 0;
                decimal? totalgst = 0;
                decimal? totaltds = 0;
                foreach (var item in ch)
                {
                    totalamt += item.Amount;
                    totalcr += item.cr;
                    totaldr += item.dr;
                    totalcomm += item.comm;
                    totalgst += item.gst;
                    totaltds += item.tds;
                    dataTbl.Rows.Add(item.Details, item.Amount, item.remainpre, item.remainpost, item.ledgerdate, item.cr, item.dr, item.comm, item.gst, item.tds);
                }
                dataTbl.Rows.Add("Total", totalamt, "", "", "", totalcr, totaldr, totalcomm, totalgst, totaltds);
            }
            else
            {
                dataTbl.Rows.Add("", "", "", "", "", "", "", "", "", "");
            }
            var grid = new GridView();
            grid.DataSource = dataTbl;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=Pos_Ledger.xls");
