        [HttpPost]
        public ActionResult UpdateBankinfromation(string txtid3, string txtaccholder, string txtbankaccountno, string txtifsc, string txtbankname, string txtbranchaddress, HttpPostedFileBase cancelcheckfile, string latss, string longloc)
        {
            try
            {
                string userid = User.Identity.GetUserId();
                string externalip = new WebClient().DownloadString("http://ipv4.icanhazip.com/");
                externalip = externalip.Replace("\n", "");
                string city = null;
                string address = null;
                string remlocationstatus = null;
                RetailerRemloclogic.checklocationbyRem(userid, "CHECK", out remlocationstatus, latss, longloc, ref city, ref address);
                if (remlocationstatus == "NOTALLOW")
                {
                    var results = "{'message':'Bank Request not allowed at this location','status':'Failed' }";
                    var jss1 = new JavaScriptSerializer();
                    var dict1 = jss1.Deserialize<dynamic>(results);
                    return Json(dict1, JsonRequestBehavior.AllowGet);
                }
                var isEmailAlreadyExists = db.UpdateREMAccounts.Where(x => x.UserId == userid).ToList();
                var isPendingExists = db.UpdateREMAccounts.Where(x => x.UserId == userid && x.Status.ToUpper() == "PENDING").FirstOrDefault();
                var isAccountExists = db.UpdateREMAccounts.Where(x => x.BankAccountNo == txtbankaccountno).ToList();
                if (isAccountExists.Any() && string.IsNullOrEmpty(txtid3))
                {
                    TempData["success"] = "This Account is Already Added.";
                    return RedirectToAction("Profile");
                }
                else if (isEmailAlreadyExists.Count() >= 8 && string.IsNullOrEmpty(txtid3))
                {
                    TempData["success"] = "You Already Added 8 Accounts.";
                    return RedirectToAction("Profile");
                }
                else if (isPendingExists != null && string.IsNullOrEmpty(txtid3))
                {
                    TempData["success"] = "You Already have Pending Account Request";
                    return RedirectToAction("Profile");
                }
                else
                {
                    string imagePath = "";
                    string newFileName = "";
                    if (cancelcheckfile != null)
                    {
                        var fileName = Guid.NewGuid().ToString() + System.IO.Path.GetExtension(cancelcheckfile.FileName);
                        WebImage photo = WebImage.GetImageFromRequest("cancelcheckfile");
                        newFileName = Guid.NewGuid().ToString() + "_" +
                              Path.GetFileName(photo.FileName);
                        newFileName = Regex.Replace(newFileName, "[^a-zA-Z0-9_.]+", "", RegexOptions.Compiled);
                        imagePath = @"\Retailer_image\" + newFileName;
                        photo.Save(@"~\" + imagePath);
                    }
                    var Mail_Firm = db.Retailer_Details.Where(a => a.RetailerId == userid).SingleOrDefault();
                    if (string.IsNullOrEmpty(txtid3))
                    {
                        UpdateREMAccount ac = new UpdateREMAccount();
                        ac.UserId = userid;
                        ac.AcconutHolderName = txtaccholder;
                        ac.BankAccountNo = txtbankaccountno;
                        ac.IFSC_CODE = txtifsc;
                        ac.Bank_Name = txtbankname;
                        ac.Bank_Address = txtbranchaddress;
                        ac.Status = "Pending";
                        ac.Date = DateTime.Now;
                        ac.Email = Mail_Firm.Email;
                        ac.Firm_Name = Mail_Firm.Frm_Name;
                        ac.CancelCheckFile = imagePath;
                        ac.Devicetoken = null;
                        ac.Latitude = latss;
                        ac.Longitude = longloc;
                        ac.ModelNo = null;
                        ac.City = city;
                        ac.PostalCode = null;
                        ac.InternetTYPE = null;
                        ac.IPaddress = externalip;
                        ac.Address = address;
                        db.UpdateREMAccounts.Add(ac);
                        db.SaveChanges();
                    }
                    else
                    {
                        int id = Convert.ToInt32(txtid3);
                        var ac = db.UpdateREMAccounts.Where(a => a.UserId == userid && a.Idno == id && a.Status == "Pending").SingleOrDefault();
                        if (cancelcheckfile == null)
                        {
                            imagePath = ac.CancelCheckFile;
                        }
                        ac.AcconutHolderName = txtaccholder;
                        ac.BankAccountNo = txtbankaccountno;
                        ac.IFSC_CODE = txtifsc;
                        ac.Bank_Name = txtbankname;
                        ac.Bank_Address = txtbranchaddress;
                        ac.CancelCheckFile = imagePath;
                        ac.Latitude = latss;
                        ac.Longitude = longloc;
                        ac.City = city;
                        ac.IPaddress = externalip;
                        ac.Address = address;
                        db.SaveChanges();
                    }
                    TempData["success"] = "After adding and changing the account, call customer care from registered mobile, customer care will be able to make your new bank account live only after that.";
                    TempData["success1"] = "खाता जोड़ने और बदलने के बाद, पंजीकृत मोबाइल से ग्राहक देखभाल पर कॉल करें, ग्राहक देखभाल आपके नए बैंक खाते को उसके बाद ही लाइव करने में सक्षम होगी।";
                    return RedirectToAction("Profile");
                }
            }
            catch (Exception ex)
            {
                TempData["success"] = "Something Went Wrong !!!";
                return RedirectToAction("Profile");
            }
        }
