        public JsonResult DelereprofileDoc(string SSID, string Docname)
        {
            if (SSID != null && Docname == "Aadhaar")
            {
                var ad = db.Retailer_Details.Single(a => a.RetailerId == SSID);
                string path = Server.MapPath("~/" + ad.aadharcardPath);
                string path2 = Server.MapPath("~/" + ad.BackSideAadharcardphoto);
                if (System.IO.File.Exists(path))
                {
                    System.IO.File.Delete(path);
                }
                if (System.IO.File.Exists(path2))
                {
                    System.IO.File.Delete(path2);
                }
                ad.aadharcardPath = null;
                ad.BackSideAadharcardphoto = null;
