                return Json("Success", JsonRequestBehavior.AllowGet);
            }
            if (SSID != null && Docname == "RegistractionCertificate")
            {
                var ad = db.Retailer_Details.Single(a => a.RetailerId == SSID);
                string path = Server.MapPath("~/" + ad.Registractioncertificatepath);
