        public ActionResult Excel_Aeps_Report(string txt_frm_date, string txt_to_date, string ddl_status, int? amount, string BankId, string aadhar)
        {
            string userid = User.Identity.GetUserId();
            DateTime frm1 = Convert.ToDateTime(txt_frm_date);
            DateTime to1 = Convert.ToDateTime(txt_to_date);
            txt_frm_date = frm1.ToString("dd-MM-yyyy");
            txt_to_date = to1.ToString("dd-MM-yyyy");
            string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy",
                            "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
            DateTime dt = !string.IsNullOrWhiteSpace(txt_frm_date) ? DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
            DateTime dt1 = !string.IsNullOrWhiteSpace(txt_to_date) ? DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
            DateTime frm_date = Convert.ToDateTime(dt).Date;
            DateTime to_date = Convert.ToDateTime(dt1).Date.AddDays(1);
            int pagesize = 5000;
            var rowdata = db.Aeps_Report_New("Retailer", userid, ddl_status, amount, "", BankId, aadhar, "ALL", Convert.ToDateTime(frm_date), Convert.ToDateTime(to_date), 1, pagesize).ToList();
            DataTable dataTbl = new DataTable();
            dataTbl.Columns.Add("Transaction Status", typeof(string));
            dataTbl.Columns.Add("User Bank", typeof(string));
            dataTbl.Columns.Add("User A/C", typeof(string));
            dataTbl.Columns.Add("User Aadhaar", typeof(string));
            dataTbl.Columns.Add("User Mobile", typeof(string));
            dataTbl.Columns.Add("User Name ", typeof(string));
            dataTbl.Columns.Add("Net Amount", typeof(string));
            dataTbl.Columns.Add("User Fee ", typeof(string));
            dataTbl.Columns.Add("Earn", typeof(string));
            dataTbl.Columns.Add("GST IN", typeof(string));
            dataTbl.Columns.Add("TDS", typeof(string));
            dataTbl.Columns.Add("Pre", typeof(string));
            dataTbl.Columns.Add("Cr/Dr", typeof(string));
            dataTbl.Columns.Add("Post", typeof(string));
            dataTbl.Columns.Add("Bank RRN & Error Info", typeof(string));
            dataTbl.Columns.Add("Request Time", typeof(string));
            if (rowdata.Any())
            {
                foreach (var item in rowdata)
                {
                    var maskedaadhar = "";
                    if (!string.IsNullOrEmpty(item.AccountHolderAadhaar))
                    {
                        var aadharchk = item.AccountHolderAadhaar;
                        var len = aadharchk.Length;
                        var last = aadharchk.Substring(len - 4, 4);
                        var first = new String('x', 8);
                        maskedaadhar = first + last;
                    }
                    dataTbl.Rows.Add(item.Status, item.BankName, item.customerremain, maskedaadhar, item.Mobile, item.username, item.Amount, item.charge, item.RemIncome, item.RemGST, "0", item.RemGST, item.RemPost, Convert.ToDecimal(item.Amount) + Convert.ToDecimal(item.RemIncome), item.BankRRN, item.Txn_Date);
                }
            }
            else
            {
                dataTbl.Rows.Add("", "", "", "", "", "", "", "", "", "", "", "", "", "", "", "");
            }
            var grid = new GridView();
            grid.DataSource = dataTbl;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=Aeps_Report.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();
            return View();
        }
