        #region Travel
        public ActionResult Travel(string tabvalue)
        {
            var userid = User.Identity.GetUserId();
            var ChkKYC = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
            if (ChkKYC.PSAStatus == "Y" && ChkKYC.AadhaarStatus == "Y" && ChkKYC.ShopwithSalfieStatus == "Y")
            {
                ViewBag.tab = tabvalue;
                //show comm and opertorwise image
                var ch = db.Operator_Blocking_Status_And_CommissionFor_Retailer(userid).ToList();
                var postfixName = Path.Combine(Server.MapPath("~/RetailerRechargeimg/"));
                var virtualpath = postfixName.Replace(postfixName, "/");
                List<operatorlist> jj = (from p in ch
                                         select new operatorlist { img = virtualpath + p.operator_Name + ".png", comm = p.Commission }).ToList();
                ViewBag.show = jj;
                recenttravels recrnt = new recenttravels();
                recrnt.recentflight = db.recent_flight_report(userid).ToList();
                recrnt.recentHotel = db.recent_hotel_report(userid).ToList();
                recrnt.recentBus = db.recent_Bus_report(userid).ToList();
                recrnt.IRCTC_reports = db.Rem_IRCTC_TokenPurchase_reports(userid, DateTime.Now, DateTime.Now.AddDays(1)); //db.Rem_IRCTC_Txninfo.Where(x => x.remid == userid).OrderByDescending(x => x.idno).FirstOrDefault();
                return View(recrnt);
            }
            else
            {
                ViewBag.ChkKYC = "Firstly Complete Your Full KYC !";
                return RedirectToAction("Profile");
            }
        }
        //[OutputCache(Duration = 2000, VaryByParam = "term")]
        public JsonResult GetHotelName(string term)
        {
            try
            {
                string filepath = Server.MapPath("~/Doc/AllHotelCityCodes.json");
                using (StreamReader r = new StreamReader(filepath))
                {
                    string json = r.ReadToEnd();
                    var items = JsonConvert.DeserializeObject<List<HotelsModel>>(json);
                    List<string> planets = items.Where(aa => aa.Destination.StartsWith(term, true, null) || aa.Country.StartsWith(term, true, null)).OrderByDescending(aa => aa.Countrycode == "IN").ThenBy(aa => aa.Countrycode).Select(p => p.Destination + "," + p.Country + "(" + p.Countrycode + ")--" + p.CityId).Take(10).ToList<string>();
                    return Json(planets, JsonRequestBehavior.AllowGet);
                }
            }
            catch
            {
                return Json(new List<string>(), JsonRequestBehavior.AllowGet);
            }
        }
