        public ActionResult ShowtravlesstsIRCTC()
        {
            var userid = User.Identity.GetUserId();
            db.Configuration.ProxyCreationEnabled = false;
            //var userdetails = (from tbl in db.State_Desc join tbl1 in db.District_Desc on tbl.State_id equals tbl1.State_id
            //               join tbl2 in db.Retailer_Details on tbl1.State_id equals tbl2.State
            //                   where tbl2.RetailerId == userid
            //                   select new {
            //                   RetailerName = tbl2.RetailerName,
            //                   Frm_Name = tbl2.Frm_Name,
            //                   statename = tbl.State_name,
            //                   district = tbl1.Dist_Desc,
            //               }
            //             ).FirstOrDefault();
            var userdetails = (from tbl in db.Retailer_Details
                               join tbl1 in db.State_Desc
                                 on tbl.State equals tbl1.State_id
                               join tbl2 in db.District_Desc
                                 on tbl.District equals tbl2.Dist_id
                               where tbl.RetailerId == userid && tbl2.State_id == tbl.State
                               select new
                               {
                                   tbl,
                                   statename = tbl1.State_name,
                                   district = tbl2.Dist_Desc,
                               }).FirstOrDefault();
            string name = string.Empty;
            string lastName = string.Empty;
            var splitfulname = userdetails.tbl.RetailerName.Split(new char[] { ' ' }, 2);
            if (splitfulname.Length > 1)
            {
                name = userdetails.tbl.RetailerName.Substring(0, userdetails.tbl.RetailerName.LastIndexOf(" "));
                lastName = userdetails.tbl.RetailerName.Substring(userdetails.tbl.RetailerName.LastIndexOf(" ") + 1);
            }
            else
            {
                name = userdetails.tbl.RetailerName;
                lastName = null;
            }
            var IRCTCTOKEN = db.IRCTC_retailer_Common_comm.Where(x => x.userid == userid).SingleOrDefault().tokenval;
            var irctc = db.Rem_IRCTC_Txninfo.Where(x => x.remid == userid).OrderByDescending(x => x.idno).FirstOrDefault();
            string sts;
            if (irctc != null)
            {
                sts = irctc.status;
                if (sts == "Pending" || sts == "Approved" || sts == "SUCCESS")
                {
                    sts = irctc.status;
                }
                else
                {
                    sts = "NOTDONE";
                }
            }
            else
            {
                sts = "NOTDONE";
                irctc = null;
            }
            //JsonModel jsonmodel = new JsonModel();
            //jsonmodel.HTMLString = renderPartialViewtostring("_Rechargereport", irctc);
            //return Json(new { data = sts, userdetails = userdetails.FirstOrDefault(), name = name, lastName = lastName, IRCTCTOKEN = IRCTCTOKEN,ALLDATA= jsonmodel }, JsonRequestBehavior.AllowGet);
            return Json(new { data = sts, userdetails = userdetails, name = name, lastName = lastName, IRCTCTOKEN = IRCTCTOKEN }, JsonRequestBehavior.AllowGet);
        }
        public ActionResult Status_IRCTC_CHECK(string idno)
        {
            IRCTC_MODEL ircmodel = new IRCTC_MODEL();
            var userid = User.Identity.GetUserId();
            var token = getAuthToken();
            var txnids = db.Rem_IRCTC_Txninfo.Where(x => x.TxnID == idno && x.status == "Pending").SingleOrDefault().TxnID;
            var response = ircmodel.IRCTC_Request_Status_check(txnids, token);
            dynamic desriliseresponse = JsonConvert.DeserializeObject(response);
            var responsess = desriliseresponse.Content["ADDINFO"];
            dynamic stst = responsess.status;
            dynamic tokensts = responsess.Tokenstatus;
            if (stst == true)
            {
                return Json(tokensts, JsonRequestBehavior.AllowGet);
            }
            return Json(tokensts, JsonRequestBehavior.AllowGet);
        }
