        public string Base64Encode(string plainText)
        {
            if (!string.IsNullOrEmpty(plainText))
            {
                var file = Server.MapPath(@"~/" + plainText); //System.IO.File.ReadAllBytes(Server.MapPath("~"+ plainText));
                using (System.Drawing.Image image = System.Drawing.Image.FromFile(file))
                {
                    using (MemoryStream m = new MemoryStream())
                    {
                        image.Save(m, image.RawFormat);
                        byte[] imageBytes = m.ToArray();
                        // Convert byte[] to Base64 String
                        string base64String = Convert.ToBase64String(imageBytes);
                        return base64String;
                    }
                }
                // return imageArray.ToString();
                //  var plainTextBytes =  System.Text.Encoding.UTF8.GetBytes(plainText);
                // return System.Convert.ToBase64String(file);
            }
            else
            {
                return null;
            }
        }
