        [HttpPost]
        public ActionResult microATMSnNo(string DeviceSnNo)
        {
            var userid = User.Identity.GetUserId();
            var dvc = db.MIcroatm_admin_device_info.Where(a => a.userid == userid).SingleOrDefault();
            if (/*DeviceSnNo != ""||*/ DeviceSnNo == dvc.deviceid)
            {
                try
                {
                    // var userid = User.Identity.GetUserId();
                    var token = string.Empty;
                    token = getAuthToken();
                    var chkk = db.microATM_merch_termi_Info.Where(a => a.Userid == userid && a.status == "APPROVED").OrderByDescending(aa => aa.Date).FirstOrDefault();
                    var merchantId = chkk.TerminalId;
                    var deviceCHK = db.microATM_Device_Info.Where(a => a.userid == userid).SingleOrDefault();
                    if (deviceCHK == null)
                    {
                        microATM micro = new microATM();
                        var SnNoSubmitResp = micro.ActivateDevice(merchantId, DeviceSnNo, token);
                        if (SnNoSubmitResp != null)
                        {
                            dynamic json = JsonConvert.DeserializeObject(SnNoSubmitResp);
                            string status = json.Content.ADDINFO["status"] == null ? json.Content.ADDINFO["message"] : json.Content.ADDINFO["status"];
                            if (status.ToUpper() == "SUCCESS")
                            {
                                microATM_Device_Info dvcInfo = new microATM_Device_Info();
                                dvcInfo.userid = userid;
                                dvcInfo.Serialno = DeviceSnNo;
                                dvcInfo.Merchantid = merchantId;
                                dvcInfo.Status = "Y";
                                dvcInfo.Date = DateTime.Now;
                                db.microATM_Device_Info.Add(dvcInfo);
                                db.SaveChanges();
                                var results = "{'status':'Success','msg':'Device Serial Number Registered Successfully.'}";
                                var TerSubRes = JsonConvert.DeserializeObject(results);
                                var jsonResp = JsonConvert.SerializeObject(TerSubRes);
                                return Json(jsonResp, JsonRequestBehavior.AllowGet);
                            }
                            else
                            {
                                string msg = "";
                                try
                                {
                                    msg = json.Content.ADDINFO.errors.device_serial_number;
                                }
                                catch { }
                                var results = "{'status':'Failed','msg':'" + msg + "'}";
                                var TerSubRes = JsonConvert.DeserializeObject(results);
                                var jsonResp = JsonConvert.SerializeObject(TerSubRes);
                                return Json(jsonResp, JsonRequestBehavior.AllowGet);
                            }
                        }
                        else
                        {
                            var results = "{'status':'error','msg':'error.'}";
                            var TerSubRes = JsonConvert.DeserializeObject(results);
                            var jsonResp = JsonConvert.SerializeObject(TerSubRes);
                            return Json(jsonResp, JsonRequestBehavior.AllowGet);
                        }
                    }
                    else
                    {
                        var results = "{'status':'Failed','msg':'Device Serialno Already Registered.'}";
                        var TerSubRes = JsonConvert.DeserializeObject(results);
                        var jsonResp = JsonConvert.SerializeObject(TerSubRes);
                        return Json(jsonResp, JsonRequestBehavior.AllowGet);
                    }
                }
                catch
                {
                    var results = "{'status':'error','msg':'error.'}";
                    var TerSubRes = JsonConvert.DeserializeObject(results);
                    var jsonResp = JsonConvert.SerializeObject(TerSubRes);
                    return Json(jsonResp, JsonRequestBehavior.AllowGet);
                }
            }
            else
            {
                var results = "{'status':'','msg':'device not allocate.'}";
                var TerSubRes = JsonConvert.DeserializeObject(results);
                var jsonResp = JsonConvert.SerializeObject(TerSubRes);
                return Json(jsonResp, JsonRequestBehavior.AllowGet);
            }
        }
