        public ActionResult Gift_Card()
        {
            var userid = User.Identity.GetUserId();
            var ChkKYC = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
            if (ChkKYC.PSAStatus == "Y" && ChkKYC.AadhaarStatus == "Y" && ChkKYC.ShopwithSalfieStatus == "Y")
            {
                var sts = db.Retailer_Details.Where(a => a.RetailerId == userid && a.giftcardsts == "Y" && a.giftcardsts != null).Any();
                if (sts == true)
                {
                    return View();
                }
                else
                {
                    TempData["msg"] = "Your Giftcard Status Inactive Please Contact Admin";
                    return RedirectToAction("Dashboard", "Home");
                }
            }
            else
            {
                ViewBag.ChkKYC = "Firstly Complete Your Full KYC !";
                return RedirectToAction("Profile");
            }
        }
