                request.AddHeader("Authorization", "Bearer " + token);
                IRestResponse response = client.Execute(request);
                dynamic req = JsonConvert.DeserializeObject(response.Content);
                var addinfo = req.Content.ADDINFO;
                var optinfo = db.Operator_Code;
                string optcodechk = "";
                int i = 0;
                foreach (var item in addinfo)
                {
                    optcodechk = item.OptCode.ToString();
                    var optidinfochk = optinfo.Where(aa => aa.new_opt_code == optcodechk).SingleOrDefault();
                    if (optidinfochk != null)
                    {
                        var optid = optidinfochk.Operator_id.ToString();
                        var commchk = db.giftcard_retailer_comm.Where(aa => aa.optcode == optid && aa.retailerid == userid).SingleOrDefault();
                        if (commchk != null)
                        {
                            var comm = commchk.comm;
                            req.Content.ADDINFO[i].comm = comm;
                        }
                        else
                        {
                            req.Content.ADDINFO[i].comm = 0;
                        }
                    }
                    else
                    {
                        req.Content.ADDINFO[i].comm = 1;
                    }
                    i++;
                }
                var respp = JsonConvert.SerializeObject(req);
                return Json(respp, JsonRequestBehavior.AllowGet);
            }
            var respp1 = JsonConvert.SerializeObject(check);
            //return Json(respp, JsonRequestBehavior.AllowGet);
            return Json(respp1, JsonRequestBehavior.AllowGet);
        }
