                        }
                        catch { }
                    }
                    var viewresponse1 = new { Status = status, Message = msg1 };
                    return Json(viewresponse1, JsonRequestBehavior.AllowGet);
                }
                else
                {
                    var viewresponse1 = new { Status = "Failed", Message = "Retailer remain balance is low." };
                    return Json(viewresponse1, JsonRequestBehavior.AllowGet);
                }
