                                    };
                                    return Json(result, JsonRequestBehavior.AllowGet);
                                }
                            }
                            else
                            {
                                var result = new
                                {
                                    Response = errormsg,
                                    statuscode = "ERR"
                                };
                                return Json(result, JsonRequestBehavior.AllowGet);
                            }
                        }
                        else
