        public static IRestResponse payout_pool2(string number, string accountno, string ifsccode, string agentid, string authcode, string clientid, string clientsecret, string endpointip)
        {
            System.Net.ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12 | SecurityProtocolType.Tls11 | SecurityProtocolType.Tls;
            var client = new RestClient("https://api.instantpay.in/identity/verifyBankAccount");
            var instantpayauth =
            client.Timeout = -1;
            var request = new RestRequest(Method.POST);
            request.AddHeader("X-Ipay-Auth-Code", authcode);
            request.AddHeader("X-Ipay-Client-Id", clientid);
            request.AddHeader("X-Ipay-Client-Secret", clientsecret);
            request.AddHeader("X-Ipay-Endpoint-Ip", endpointip);
            request.AddHeader("Content-Type", "application/json");
            var req = new
            {
                payee = new
                {
                    accountNumber = accountno,
                    bankIfsc = ifsccode
                },
                externalRef = agentid,
                consent = "Y",
                pennyDrop = "YES",
                latitude = "20.5936",
                longitude = "78.9628",
            };
            var body = JsonConvert.SerializeObject(req);
            request.AddParameter("application/json", body, ParameterType.RequestBody);
            IRestResponse response = client.Execute(request);
            InstantPayLog("Response Content: " + response.Content);
            InstantPayLog2("Response Content: " + response.Content);
            return response;
        }
        public static void InstantPayLog(string strMessage, string filename = "INSTANTPAY_PAY")
        {
            try
            {
                StreamWriter log;
                FileStream fileStream = null;
                DirectoryInfo logDirInfo = null;
                FileInfo logFileInfo;
                string logFilePath = "C:\\Logs\\";
                logFilePath = logFilePath + filename + System.DateTime.Today.ToString("MM-dd-yyyy") + "." + "txt";
                logFileInfo = new FileInfo(logFilePath);
                logDirInfo = new DirectoryInfo(logFileInfo.DirectoryName);
                if (!logDirInfo.Exists) logDirInfo.Create();
                if (!logFileInfo.Exists)
                {
                    fileStream = logFileInfo.Create();
                }
                else
                {
                    fileStream = new FileStream(logFilePath, FileMode.Append);
                }
                log = new StreamWriter(fileStream);
                log.WriteLine(strMessage);
                log.Close();
            }
            catch (Exception ex)
            {
            }
        }
