        public object activate_customer_account()
        {
            JObject obj = new JObject();
            try
            {
                string userid = User.Identity.GetUserId();
                var retailer = db.Retailer_Details.Single(s => s.RetailerId == userid);
                string token = Responsetoken.gettoken();
                if (token == null)
                {
                    throw new Exception("Token Null");
                }
                var client = new RestClient("http://api.vastbazaar.com/api/CASHFREE/CREATECUSTOMER");
                client.Timeout = -1;
                var request = new RestRequest(Method.POST);
                request.AddHeader("Authorization", "Bearer " + token);
                request.AddHeader("Content-Type", "application/json");
                var body = new
                {
                    type = "BUSINESS",
                    Name = retailer.RetailerName,
                    email = retailer.Email,
                    phone = retailer.Mobile,
                    firmname = retailer.Frm_Name,
                };
                request.AddParameter("application/json", JsonConvert.SerializeObject(body), ParameterType.RequestBody);
                IRestResponse response = client.Execute(request);
                string result = response.Content;
                if (response.StatusCode != HttpStatusCode.OK || result.ToUpper().Contains("INVALID RESPONSE"))
                {
                    throw new Exception("Invalid Response");
                }
                dynamic res = JsonConvert.DeserializeObject(result);
                string type = "";
                try
                {
                    type = (string)res.Content.ADDINFO.customer.type;
                }
                catch
                {
                    type = (string)res.Content.ADDINFO.type;
                }
                if (type == "BUSINESS")
                {
                    string cust_id = (string)res.Content.ADDINFO.customer.customer_id;
                    retailer.axis_customer_id = cust_id;
                    db.SaveChanges();
                    obj.Add("status", true);
                }
                else if (type == "Duplicate")
                {
                    var client1 = new RestClient("http://api.vastbazaar.com/api/CASHFREE/GETCUSTOMER?phoneno=" + retailer.Mobile);
                    client1.Timeout = -1;
                    var request1 = new RestRequest(Method.POST);
                    request1.AddHeader("Authorization", "Bearer " + token);
                    IRestResponse response1 = client1.Execute(request1);
                    string result1 = response1.Content;
                    dynamic res1 = JsonConvert.DeserializeObject(result1);
                    string cust_id = (string)res1.Content.ADDINFO.customer.customer_id;
                    retailer.axis_customer_id = cust_id;
                    db.SaveChanges();
                    obj.Add("status", true);
                }
                else
                {
                    string message = (string)res.Content.ADDINFO.message;
                    obj.Add("status", false);
                    obj.Add("message", message);
                }
            }
            catch (Exception ex)
            {
                obj.Add("status", false);
                obj.Add("message", ex.Message);
            }
            return obj;
        }
        [HttpPost]
        public object submit_saving_account(AccountOpening model)
        {
            JObject obj = new JObject();
            try
            {
                var ao = db.AccountOpenings.Where(s => s.mobile == model.mobile).SingleOrDefault();
                if (ao != null)
                {
                    obj.Add("status", true);
                    obj.Add("url", ao.url);
                    return obj;
                }
                model.req_time = DateTime.Now;
                var userid = User.Identity.GetUserId();
                var retailer = db.Retailer_Details.Single(s => s.RetailerId == userid);
                model.userid = userid;
                model.firmname = retailer.Frm_Name;
                if (String.IsNullOrEmpty(retailer.axis_customer_id))
                {
                    throw new Exception("Retailer is not registered for account opening.");
                }
                if (String.IsNullOrEmpty(model.fname) || String.IsNullOrEmpty(model.lname) || String.IsNullOrEmpty(model.email) || String.IsNullOrEmpty(model.mobile) || String.IsNullOrEmpty(model.pincode) || model.dob == null)
                {
                    throw new Exception("Validation Error");
                }
                if (!ModelState.IsValid)
                {
                    throw new Exception("Validation Error");
                }
                string date = Convert.ToDateTime(model.dob).ToString("yyyy-MM-dd");
                string token = Responsetoken.gettoken();
                if (token == null)
                {
                    throw new Exception("Token Null");
                }
                var client = new RestClient("http://api.vastbazaar.com/api/CASHFREE/SavingAccount");
                client.Timeout = -1;
                var request = new RestRequest(Method.POST);
                request.AddHeader("Authorization", "Bearer " + token);
                request.AddHeader("Content-Type", "application/json");
                string uniqueid = DateTime.Parse(DateTime.Now.ToString()).ToString("yyMMddHHmmss") + RandomString(4);
                var body = new
                {
                    Customerid = retailer.axis_customer_id,
                    fname = model.fname,
                    lname = model.lname,
                    email = model.email,
                    phone = model.mobile,
                    dob = date,
                    pincode = model.pincode,
                    firmanme = retailer.Frm_Name,
                    uniqueid = uniqueid
                };
                model.request = "http://api.vastbazaar.com/api/CASHFREE/SavingAccount" + ", " + JsonConvert.SerializeObject(body);
                request.AddParameter("application/json", JsonConvert.SerializeObject(body), ParameterType.RequestBody);
                IRestResponse response = client.Execute(request);
                string result = response.Content;
                model.uniqueid = uniqueid;
                model.response = result;
                model.res_time = DateTime.Now;
                if (response.StatusCode != HttpStatusCode.OK || result.ToUpper().Contains("INVALID RESPONSE"))
                {
                    throw new Exception("Invalid Response");
                }
                dynamic res = JsonConvert.DeserializeObject(result);
                string bank_url = (string)res.Content.ADDINFO.instrument.bank_url;
                string account_type = (string)res.Content.ADDINFO.instrument.account_type;
                model.res_time = DateTime.Now;
                model.url = bank_url;
                model.status = "pending";
                model.account_type = account_type;
                db.AccountOpenings.Add(model);
                db.SaveChanges();
                obj.Add("status", true);
                obj.Add("url", bank_url);
            }
            catch (Exception ex)
            {
                obj.Add("status", false);
                obj.Add("message", ex.Message);
            }
            return obj;
        }
        public ActionResult account_axis_report(string search = null, DateTime? from = null, DateTime? to = null)
        {
            AccountOpeningRecentReport report = new AccountOpeningRecentReport();
            string userid = User.Identity.GetUserId();
            if (from == null && to == null)
            {
                from = DateTime.Now.AddDays(-1);
                to = DateTime.Now.AddDays(1);
            }
            else
            {
                to = Convert.ToDateTime(to).AddDays(1);
            }
            if (String.IsNullOrEmpty(search))
            {
                report.Recent_report_axis = db.AccountOpenings.Where(s => s.userid == userid && s.req_time >= from && s.req_time < to).ToList();
            }
            else
            {
                report.Recent_report_axis = db.AccountOpenings.Where(s => s.userid == userid && (s.fname.Contains(search) || s.lname.Contains(search) || s.email.Contains(search) || s.mobile.Contains(search)) && s.req_time >= from && s.req_time < to).ToList();
            }
            report.Recent_report_icici = null;
            return PartialView("_AccountOpeningReport", report);
        }
        public object account_status_check(string uniqueid)
        {
            JObject obj = new JObject();
            try
            {
                string token = Responsetoken.gettoken();
                if (token == null)
                {
                    throw new Exception("Token Null");
                }
                var client = new RestClient("http://api.vastbazaar.com/api/CASHFREE/StatusCheck?uniqueid=" + uniqueid);
                client.Timeout = -1;
                var request = new RestRequest(Method.POST);
                request.AddHeader("Authorization", "Bearer " + token);
                IRestResponse response = client.Execute(request);
                string result = response.Content;
                if (response.StatusCode != HttpStatusCode.OK || result.ToUpper().Contains("INVALID RESPONSE"))
                {
                    throw new Exception("Invalid Response");
                }
                dynamic res = JsonConvert.DeserializeObject(result);
                string status = (string)res.Content.ADDINFO.Status;
                if (status.ToUpper() == "SUCCESS")
                {
                    var ac_opening = db.AccountOpenings.Single(s => s.uniqueid == uniqueid);
                    ac_opening.status = "Success";
                    ac_opening.res_time = DateTime.Now;
                    db.SaveChanges();
                    obj.Add("status", true);
                    obj.Add("message", "");
                }
                else
                {
                    obj.Add("status", false);
                    obj.Add("message", "Status Pending");
                }
            }
            catch (Exception ex)
            {
                obj.Add("status", false);
                obj.Add("message", ex.Message);
            }
            return obj;
        }
