        public object sendOtpForOutlet()
        {
            try
            {
                var userid = User.Identity.GetUserId();
                var rem = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
                var token = getAuthToken();
                if (string.IsNullOrEmpty(token))
                {
                    throw new Exception("Failed at provider server.");
                }
                var rem_location = db.UserLocations.Where(s => s.RetailerId == userid).Single();
                string lattitude = string.Empty;
                string longitude = string.Empty;
                if (rem.UserLocation == null)
                {
                    insertGeoLocation(rem.RetailerId, out lattitude, out longitude);
                }
                else
                {
                    lattitude = rem.UserLocation.Lattitude;
                    longitude = rem.UserLocation.Longitute;
                }
                var latLong = db.Update_Aeps_Info.Where(x => x.UserId == userid).FirstOrDefault();
                if (latLong != null)
                {
                    lattitude = latLong.latitude;
                    longitude = latLong.longitude;
                }
                else
                {
                    string Aeps_Update = UpdateAeps(lattitude, longitude);
                    if (Aeps_Update == "TXN")
                    {
                        var data = new Update_Aeps_Info()
                        {
                            UserId = userid,
                            latitude = lattitude,
                            longitude = longitude,
                            UpdateTime = DateTime.Now,
                            status = true,
                            RequestFrom = "Web"
                        };
                        db.Update_Aeps_Info.Add(data);
                        db.SaveChanges();
                    }
                }
                var client = new RestClient("http://api.vastbazaar.com/api/AEPSINSTANT/Register");
                client.Timeout = -1;
                var request = new RestRequest(Method.POST);
                request.AddHeader("aadhar", rem.AadharCard);
                request.AddHeader("pancard", rem.PanCard);
                request.AddHeader("Authorization", "Bearer " + token);
                var body = new
                {
                    mobile = rem.Mobile,
                    email = rem.Email,
                    latitude = lattitude,
                    longitude = longitude
                };
                var requ = JsonConvert.SerializeObject(body);
                request.AddParameter("application/json", requ, ParameterType.RequestBody);
                IRestResponse response = client.Execute(request);
                if (response.Content == "Invalid response..")
                {
                    throw new Exception("Bad Request");
                }
                dynamic resp = JsonConvert.DeserializeObject(response.Content);
                var json = resp.Content.ADDINFO;
                var stscode = resp.Content.ADDINFO.stscode.ToString();
                var message = (string)json.msg;
                var otpReferenceID = (string)json.otpReferenceID;
                var hash = (string)json.hash;
                if (stscode.ToUpper() != "TXN")
                {
                    throw new Exception(message);
                }
                return Json(new { status = true, message, otpReferenceID, hash }, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                return Json(new { status = false, message = ex.Message }, JsonRequestBehavior.AllowGet);
            }
        }
        public object Aeps2VerifyOtp(string otp, string otpReferenceID, string hash)
        {
            try
            {
                if (String.IsNullOrEmpty(otp) || String.IsNullOrEmpty(otpReferenceID) || String.IsNullOrEmpty(hash))
                {
                    throw new Exception("all parameter required");
                }
                var userid = User.Identity.GetUserId();
                var rem = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
                var token = getAuthToken();
                if (string.IsNullOrEmpty(token))
                {
                    throw new Exception("Failed at provider server.");
                }
                var client = new RestClient("http://api.vastbazaar.com/api/AEPSINSTANT/ValidateOtp");
                client.Timeout = -1;
                var request = new RestRequest(Method.POST);
                request.AddHeader("Authorization", "Bearer " + token);
                var body = new
                {
                    otpReferenceID,
                    otp,
                    hash,
                    rememail = rem.Email
                };
                var requ = JsonConvert.SerializeObject(body);
                request.AddParameter("application/json", requ, ParameterType.RequestBody);
                IRestResponse response = client.Execute(request);
                if (response.Content == "Invalid response..")
                {
                    throw new Exception("Bad Request");
                }
                dynamic resp = JsonConvert.DeserializeObject(response.Content);
                var json = resp.Content.ADDINFO;
                var stscode = resp.Content.ADDINFO.statuscode.ToString();
                var message = (string)json.msg;
                var outletid = (string)json.outletid;
                if (stscode.ToUpper() != "TXN")
                {
                    throw new Exception(message);
                }
                var isUser = db.Retailer_Outlet2.Any(s => s.userid == userid);
                if (isUser == false)
                {
                    Retailer_Outlet2 rt = new Retailer_Outlet2();
                    rt.outletId = outletid;
                    rt.response = json.ToString();
                    rt.userid = userid;
                    db.Retailer_Outlet2.Add(rt);
                    db.SaveChanges();
                }
                return Json(new { status = true, message }, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                return Json(new { status = false, message = ex.Message }, JsonRequestBehavior.AllowGet);
            }
        }
