            return Json(json, JsonRequestBehavior.AllowGet);
        }
        public ActionResult CashdepositeGenrateOtp(string mobile, string account, double amount, string iin)
        {
            var userid = User.Identity.GetUserId();
            var token = string.Empty;
            token = getAuthToken();
            var seceretkey = "b25a76d700f6066e77c095e7097d11e9e5cf96f1bbc2a28eb919e2b950449b6d";
            if (string.IsNullOrWhiteSpace(token))
            {
                var viewresponse = new { Status = "Failed", Message = "Failed at provider server." };
                return Json(viewresponse, JsonRequestBehavior.AllowGet);
            }
            var retailer = db.Retailer_Details.SingleOrDefault(a => a.RetailerId == userid);
            var client1 = new RestClient("http://api.vastbazaar.com/api/AEPS/supermerchant?merchant=" + retailer.AepsMerchandId + "");
            var request1 = new RestRequest(Method.POST);
            request1.AddHeader("Authorization", "Bearer " + token);
            IRestResponse response1 = client1.Execute(request1);
            var respsuper = response1.Content;
            dynamic chkresp = JsonConvert.DeserializeObject(respsuper);
            var stscode = chkresp.Content.ADDINFO.stscode.ToString();
            if (stscode == "0")
            {
                var msg = chkresp.Content.ADDINFO.message.ToString();
                var viewresponse = new { Status = "Failed", Message = msg };
                return Json(viewresponse, JsonRequestBehavior.AllowGet);
            }
            var superid = chkresp.Content.ADDINFO.data.superid.ToString();
            var superusername = chkresp.Content.ADDINFO.data.superusername.ToString();
            string lattitude = string.Empty;
            string longitude = string.Empty;
            if (retailer.UserLocation == null)
            {
                insertGeoLocation(retailer.RetailerId, out lattitude, out longitude);
            }
            else
            {
                lattitude = retailer.UserLocation.Lattitude;
                longitude = retailer.UserLocation.Longitute;
            }
            var latLong = db.Update_Aeps_Info.Where(x => x.UserId == userid).FirstOrDefault();
            if (latLong != null)
            {
                lattitude = latLong.latitude;
                longitude = latLong.longitude;
            }
            else
            {
                string Aeps_Update = UpdateAeps(lattitude, longitude);
                if (Aeps_Update == "TXN")
                {
                    var data = new Update_Aeps_Info()
                    {
                        UserId = userid,
                        latitude = lattitude,
                        longitude = longitude,
                        UpdateTime = DateTime.Now,
                        status = true,
                        RequestFrom = "Web"
                    };
                    db.Update_Aeps_Info.Add(data);
                    db.SaveChanges();
                }
            }
            CashDepositModel model = new CashDepositModel();
            model.superMerchantId = Convert.ToInt32(superid);
            model.merchantUserName = retailer.AepsMerchandId;
            model.merchantPin = CreateMD5(retailer.AepsMPIN);
            model.secretKey = seceretkey;
            model.mobileNumber = mobile;
            model.iin = iin;
            model.transactionType = "CDO";
            model.latitude = Convert.ToDouble(lattitude);
            model.longitude = Convert.ToDouble(longitude);
            model.merchantTranId = DateTime.Now.ToString("dd-MM-yyy hh-mm-ss").Replace("-", "").Replace(" ", "");
            model.accountNumber = account;
            model.amount = amount;
            model.fingpayTransactionId = "";
            model.otp = "";
            model.cdPkId = 0;
            model.timestamp = DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss", CultureInfo.InvariantCulture);//"dd/MM/yyyy HH:mm:ss"
            var agentid = DateTime.Now.ToString("dd-MM-yyy hh-mm-ss").Replace("-", "").Replace(" ", "");
            var RequestJson = JsonConvert.SerializeObject(model);
            byte[] hash = Main.generateSha256Hash(Encoding.ASCII.GetBytes(RequestJson + seceretkey));
            byte[] skey = Main.generateSessionKey();
            string encryptUsingSessionKey = Main.encryptUsingSessionKey(skey, Encoding.ASCII.GetBytes(RequestJson));
            string encryptUsingPublicKey = Main.encryptUsingPublicKey(skey);
            if (string.IsNullOrWhiteSpace(encryptUsingSessionKey) || string.IsNullOrWhiteSpace(encryptUsingPublicKey))
            {
                var viewresponse = new { Status = "Failed", Message = "Failed to initiate request." };
                return Json(viewresponse, JsonRequestBehavior.AllowGet);
            }
            var fingpayTransactionId = ""; var cdPkId = ""; var status = ""; var msg1 = "";
            var client = new RestClient();
            var request = new RestRequest(Method.POST);
            client = new RestClient(VastbazaarBaseUrl + "api/Deposit/CashDepositeWithOtp");
            request.AddHeader("superid", superid);
            request.AddHeader("content-type", "text/plain");
            request.AddHeader("cache-control", "no-cache");
            request.AddHeader("authorization", "bearer " + token);//OAUTH token
            request.AddHeader("eskey", encryptUsingPublicKey);
            request.AddHeader("deviceIMEI", string.IsNullOrWhiteSpace("3171153") ? "352801082418919" : "3171153"); //can pass Unique device Id
            request.AddHeader("hash", Convert.ToBase64String(hash));
            request.AddHeader("trnTimestamp", model.timestamp);
            request.AddHeader("agentid", agentid);
            request.AddHeader("amount", amount.ToString());
            request.AddHeader("MerchantId", retailer.AepsMerchandId);
            request.AddHeader("requestjson", RequestJson);
            request.AddParameter("text/plain",
                encryptUsingSessionKey, ParameterType.RequestBody);
            try
            {
                IRestResponse response = client.Execute(request);
                if (response.StatusCode == HttpStatusCode.BadRequest)
                {
                    TryLogin();
                }
                dynamic respoJson = JsonConvert.DeserializeObject(response.Content);
                var statusCode = respoJson.Content.ADDINFO.statusCode;
                if (statusCode == 10000)
                {
                    var sts = respoJson.Content.ADDINFO.data.responseCode;
                    if (sts == "00")
                    {
                        status = "Success";
                        fingpayTransactionId = respoJson.Content.ADDINFO.data.fingpayTransactionId;
                        cdPkId = respoJson.Content.ADDINFO.data.cdPkId;
                        msg1 = respoJson.Content.ADDINFO.message;
                    }
                    else
                    {
                        status = "Failed";
                        msg1 = respoJson.Content.ADDINFO.message;
                    }
                }
                else
                {
                    status = "Failed";
                    msg1 = respoJson.Content.ADDINFO.message;
                }
            }
            catch
            {
                status = "Failed";
                msg1 = "Please Try Again";
            }
            var viewresponse1 = new { Status = status, Message = msg1, fingpayTransactionId = fingpayTransactionId, cdPkId = cdPkId };
            return Json(viewresponse1, JsonRequestBehavior.AllowGet);
        }
        public ActionResult PaytmWalletGenrateOtp(string mobile, double amount)
        {
            try
            {
                var token = getAuthToken();
                if (string.IsNullOrWhiteSpace(token))
                {
                    throw new Exception("Failed at provider server.");
                }
                var obj = new
                {
                    mobile,
                    amount
                };
                string body = JsonConvert.SerializeObject(obj);
                var client1 = new RestClient("http://api.vastbazaar.com/api/Deposit/PayTM/SendOTP");
                var request1 = new RestRequest(Method.POST);
                request1.AddHeader("Authorization", "Bearer " + token);
                request1.AddHeader("Content-Type", "application/json");
                request1.AddParameter("application/json", body, ParameterType.RequestBody);
                IRestResponse response1 = client1.Execute(request1);
                var respsuper = response1.Content;
                dynamic chkresp = JsonConvert.DeserializeObject(respsuper);
                bool stscode = (bool)chkresp.Content.ADDINFO.status;
                var msg = (string)chkresp.Content.ADDINFO.message;
                if (!stscode)
                {
                    throw new Exception(msg);
                }
                var viewresponse = new { Status = "Success", Message = msg };
                return Json(viewresponse, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                var viewresponse = new { Status = "Failed", Message = ex.Message };
                return Json(viewresponse, JsonRequestBehavior.AllowGet);
            }
        }
