        public dynamic CashDepositWithotp(string otp, int cdPkId, string fingpayTransactionId, string mobile, string account, string iin, double amount, string benname, string bankname)
        {
            var userid = User.Identity.GetUserId();
            var admin_details = db.Admin_details.SingleOrDefault();
            System.Random _random = new System.Random();
            string ran = _random.Next(1111, 9999).ToString();
            var agentid = DateTime.Now.ToString("dd-MM-yyy hh-mm-ss").Replace("-", "").Replace(" ", "") + ran;
            var token = string.Empty;
            token = getAuthToken();
            var seceretkey = "b25a76d700f6066e77c095e7097d11e9e5cf96f1bbc2a28eb919e2b950449b6d";
            if (string.IsNullOrWhiteSpace(token))
            {
                var viewresponse = new { Status = "Failed", Message = "Failed at provider server." };
                return Json(viewresponse, JsonRequestBehavior.AllowGet);
            }
            var retailer = db.Retailer_Details.SingleOrDefault(a => a.RetailerId == userid);
            var client1 = new RestClient("http://api.vastbazaar.com/api/AEPS/supermerchant?merchant=" + retailer.AepsMerchandId + "");
            var request1 = new RestRequest(Method.POST);
            request1.AddHeader("Authorization", "Bearer " + token);
            IRestResponse response1 = client1.Execute(request1);
            var respsuper = response1.Content;
            dynamic chkresp = JsonConvert.DeserializeObject(respsuper);
            var stscode = chkresp.Content.ADDINFO.stscode.ToString();
            if (stscode == "0")
            {
                var msg = chkresp.Content.ADDINFO.message.ToString();
                var viewresponse = new { Status = "Failed", Message = msg };
                return Json(viewresponse, JsonRequestBehavior.AllowGet);
            }
            var superid = chkresp.Content.ADDINFO.data.superid.ToString();
            var superusername = chkresp.Content.ADDINFO.data.superusername.ToString();
            string lattitude = string.Empty;
            string longitude = string.Empty;
            if (retailer.UserLocation == null)
            {
                insertGeoLocation(retailer.RetailerId, out lattitude, out longitude);
            }
            else
            {
                lattitude = retailer.UserLocation.Lattitude;
                longitude = retailer.UserLocation.Longitute;
            }
            var latLong = db.Update_Aeps_Info.Where(x => x.UserId == userid).FirstOrDefault();
            if (latLong != null)
            {
                lattitude = latLong.latitude;
                longitude = latLong.longitude;
            }
            else
            {
                string Aeps_Update = UpdateAeps(lattitude, longitude);
                if (Aeps_Update == "TXN")
                {
                    var data = new Update_Aeps_Info()
                    {
                        UserId = userid,
                        latitude = lattitude,
                        longitude = longitude,
                        UpdateTime = DateTime.Now,
                        status = true,
                        RequestFrom = "Web"
                    };
                    db.Update_Aeps_Info.Add(data);
                    db.SaveChanges();
                }
            }
            CashDepositModel model = new CashDepositModel();
            model.superMerchantId = Convert.ToInt32(superid);
            model.merchantUserName = retailer.AepsMerchandId;
            model.merchantPin = CreateMD5(retailer.AepsMPIN);
            model.secretKey = seceretkey;
            model.mobileNumber = mobile;
            model.iin = iin;
            model.transactionType = "CDO";
            model.latitude = Convert.ToDouble(lattitude);
            model.longitude = Convert.ToDouble(longitude);
            model.merchantTranId = DateTime.Now.ToString("dd-MM-yyy hh-mm-ss").Replace("-", "").Replace(" ", "");
            model.accountNumber = account;
            model.amount = amount;
            model.fingpayTransactionId = fingpayTransactionId;
            model.otp = otp;
            model.cdPkId = cdPkId;
            // model.timestamp = DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss", CultureInfo.InvariantCulture);//"dd/MM/yyyy HH:mm:ss"
            var RequestJson = JsonConvert.SerializeObject(model);
            System.Data.Entity.Core.Objects.ObjectParameter output = new
System.Data.Entity.Core.Objects.ObjectParameter("output", typeof(string));
            var chk = db.insert_cash_deposit(userid, Convert.ToDecimal(amount), account, agentid, bankname, benname, RequestJson, output).SingleOrDefault().msg;
            try
            {
                var retailerdetails = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
                var dealerdetails = db.Dealer_Details.Where(aa => aa.DealerId == retailerdetails.DealerId).SingleOrDefault();
                var masterdetails = db.Superstokist_details.Where(aa => aa.SSId == dealerdetails.SSId).SingleOrDefault();

                var remdetails = db.Remain_reteller_balance.Where(aa => aa.RetellerId == userid).SingleOrDefault();
                var dlmdetails = db.Remain_dealer_balance.Where(aa => aa.DealerID == retailerdetails.DealerId).SingleOrDefault();
                var Masterdetails = db.Remain_superstokist_balance.Where(aa => aa.SuperStokistID == dealerdetails.SSId).SingleOrDefault();

                var admininfo = db.Admin_details.SingleOrDefault();
                Backupinfo back = new Backupinfo();
                var modeln = new Backupinfo.Addinfo
                {
                    Websitename = admininfo.WebsiteUrl,
                    RetailerID = userid,
                    Email = retailerdetails.Email,
                    Mobile = retailerdetails.Mobile,
                    Details = "Cash Deposite",
                    RemainBalance = (decimal)remdetails.Remainamount,
                    Usertype = "Retailer"
                };
                back.info(modeln);

                var model1 = new Backupinfo.Addinfo
                {
                    Websitename = admininfo.WebsiteUrl,
                    RetailerID = retailerdetails.DealerId,
                    Email = dealerdetails.Email,
                    Mobile = dealerdetails.Mobile,
                    Details = "Cash Deposite",
                    RemainBalance = Convert.ToDecimal(dlmdetails.Remainamount),
                    Usertype = "Dealer"
                };
                back.info(model1);

                var model2 = new Backupinfo.Addinfo
                {
                    Websitename = admininfo.WebsiteUrl,
                    RetailerID = dealerdetails.SSId,
                    Email = masterdetails.Email,
                    Mobile = masterdetails.Mobile,
                    Details = "Cash Deposite",
                    RemainBalance = Convert.ToDecimal(Masterdetails.Remainamount),
                    Usertype = "Master"
                };
                back.info(model2);
            }
            catch { }
            if (chk == "OK")
            {
                model.timestamp = DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss", CultureInfo.InvariantCulture);//"dd/MM/yyyy HH:mm:ss"
                byte[] hash = Main.generateSha256Hash(Encoding.ASCII.GetBytes(RequestJson + seceretkey));
                byte[] skey = Main.generateSessionKey();
                string encryptUsingSessionKey = Main.encryptUsingSessionKey(skey, Encoding.ASCII.GetBytes(RequestJson));
                string encryptUsingPublicKey = Main.encryptUsingPublicKey(skey);
                if (string.IsNullOrWhiteSpace(encryptUsingSessionKey) || string.IsNullOrWhiteSpace(encryptUsingPublicKey))
                {
                    var viewresponse = new { Status = "Failed", Message = "Failed to initiate request.", userinfo = "" };
                    return Json(viewresponse, JsonRequestBehavior.AllowGet);
                }
                var client = new RestClient();
                var request = new RestRequest(Method.POST);
                client = new RestClient(VastbazaarBaseUrl + "api/Deposit/CashDepositeWithOtpTranstion");
                request.AddHeader("superid", superid.ToString());
                request.AddHeader("content-type", "text/plain");
                request.AddHeader("cache-control", "no-cache");
                request.AddHeader("authorization", "bearer " + token);//OAUTH token
                request.AddHeader("eskey", encryptUsingPublicKey);
                request.AddHeader("deviceIMEI", string.IsNullOrWhiteSpace("3171153") ? "352801082418919" : "3171153"); //can pass Unique device Id
                request.AddHeader("hash", Convert.ToBase64String(hash));
                request.AddHeader("trnTimestamp", model.timestamp);
                request.AddHeader("agentid", agentid);
                request.AddHeader("amount", amount.ToString());
                request.AddHeader("MerchantId", retailer.AepsMerchandId);
                request.AddHeader("mobileno", mobile);
                request.AddHeader("accountno", account);
                request.AddHeader("benname", benname);
                request.AddHeader("bankname", bankname);
                request.AddHeader("requestjson", RequestJson);
                request.AddParameter("text/plain",
                    encryptUsingSessionKey, ParameterType.RequestBody);
                IRestResponse response = client.Execute(request);
                if (response.StatusCode == System.Net.HttpStatusCode.BadRequest)
                {
                    TryLogin();
                }
                var bankrrn = ""; var sts = "";
                dynamic respoJson = JsonConvert.DeserializeObject(response.Content);
                var statusCode = respoJson.Content.ADDINFO.statusCode;
                var msg11 = respoJson.Content.ADDINFO.message;
                if (statusCode == 10000)
                {
                    var respcode = respoJson.Content.ADDINFO.data.responseCode;
                    if (respcode == "00")
                    {
                        sts = "Success";
                        bankrrn = respoJson.Content.ADDINFO.data.bankRrn;
                    }
                    else if (respcode == "91" || respcode == "52" || respcode == "08")
                    {
                        sts = "Pending";
                    }
                    else
                    {
                        sts = "Failed";
                        bankrrn = respoJson.Content.ADDINFO.data.responseMessage;
                    }
                }
                else if (statusCode == 10004)
                {
                    sts = "Pending";
                }
                else
                {
                    sts = "Failed";
                    bankrrn = msg11;
                }
                if (sts == "Success" || sts == "Failed")
                {
                    db.update_cash_deposit(agentid, sts, bankrrn, response.Content);
                    if (sts == "Failed")
                    {
                        try
                        {
                            var retailerdetails = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
                            var dealerdetails = db.Dealer_Details.Where(aa => aa.DealerId == retailerdetails.DealerId).SingleOrDefault();
                            var masterdetails = db.Superstokist_details.Where(aa => aa.SSId == dealerdetails.SSId).SingleOrDefault();

                            var remdetails = db.Remain_reteller_balance.Where(aa => aa.RetellerId == userid).SingleOrDefault();
                            var dlmdetails = db.Remain_dealer_balance.Where(aa => aa.DealerID == retailerdetails.DealerId).SingleOrDefault();
                            var Masterdetails = db.Remain_superstokist_balance.Where(aa => aa.SuperStokistID == dealerdetails.SSId).SingleOrDefault();

                            var admininfo = db.Admin_details.SingleOrDefault();
                            Backupinfo back = new Backupinfo();
                            var model3 = new Backupinfo.Addinfo
                            {
                                Websitename = admininfo.WebsiteUrl,
                                RetailerID = userid,
                                Email = retailerdetails.Email,
                                Mobile = retailerdetails.Mobile,
                                Details = "Cash Depoiste Refund",
                                RemainBalance = (decimal)remdetails.Remainamount,
                                Usertype = "Retailer"
                            };
                            back.info(model3);

                            var model1 = new Backupinfo.Addinfo
                            {
                                Websitename = admininfo.WebsiteUrl,
                                RetailerID = retailerdetails.DealerId,
                                Email = dealerdetails.Email,
                                Mobile = dealerdetails.Mobile,
                                Details = "Cash Depoiste Refund",
                                RemainBalance = Convert.ToDecimal(dlmdetails.Remainamount),
                                Usertype = "Dealer"
                            };
                            back.info(model1);

                            var model2 = new Backupinfo.Addinfo
                            {
                                Websitename = admininfo.WebsiteUrl,
                                RetailerID = dealerdetails.SSId,
                                Email = masterdetails.Email,
                                Mobile = masterdetails.Mobile,
                                Details = "Cash Depoiste Refund",
                                RemainBalance = Convert.ToDecimal(Masterdetails.Remainamount),
                                Usertype = "Master"
                            };
                            back.info(model2);
                        }
                        catch { }
                    }
                }
                var viewresponse1 = new { Status = sts, Message = msg11, bankrrn = bankrrn, benname = benname };
                return Json(viewresponse1, JsonRequestBehavior.AllowGet);
            }
            else
            {
                var viewresponse1 = new { Status = "Failed", Message = chk };
                return Json(viewresponse1, JsonRequestBehavior.AllowGet);
            }
        }
