        public ActionResult Ecommerce_Report()
        {
            var userid = User.Identity.GetUserId();
            string txt_frm_date = DateTime.Now.ToString();
            string txt_to_date = DateTime.Now.ToString();
            string frm_date = Convert.ToDateTime(txt_frm_date).Date.ToString("yyyy-MM-dd");
            string to_date = Convert.ToDateTime(txt_to_date).AddDays(1).ToString("yyyy-MM-dd");
            var category = db.SubCatagories.Distinct().ToList();
            ViewBag.category = new SelectList(category, "SubCatID", "SubCatName");
            var ch = db.Show_Ecommerce_Retailer_Report(userid, "ALL", "ALL", "Retailer", 50, Convert.ToDateTime(frm_date), Convert.ToDateTime
                (to_date)).ToList();
            //sucess and failed and pending
            var success = ch.Where(a => a.AdminStatus == 2).Sum(a => a.Amount);
            var failed = ch.Where(a => a.AdminStatus == 3).Sum(a => a.Amount);
            var pending = ch.Where(a => a.AdminStatus == 1).Sum(a => a.Amount);
            ViewData["totalsuccess"] = success;
            ViewData["totalfailed"] = failed;
            ViewData["totalpending"] = pending;
            return View(ch);
