        public ActionResult Excel_Ecommerce_Report(string category, string ddl_status, string txt_frm_date, string txt_to_date)
        {
            var catagory = "";
            var status = "";
            var userid = User.Identity.GetUserId();
            DateTime frm = Convert.ToDateTime(txt_frm_date);
            DateTime to = Convert.ToDateTime(txt_to_date);
            txt_frm_date = frm.ToString("dd-MM-yyyy");
            txt_to_date = to.ToString("dd-MM-yyyy");
            string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy",
                            "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
            DateTime dt = !string.IsNullOrWhiteSpace(txt_frm_date) ? DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
            DateTime dt1 = !string.IsNullOrWhiteSpace(txt_to_date) ? DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
            DateTime frm_date = Convert.ToDateTime(dt).Date;
            DateTime to_date = Convert.ToDateTime(dt1).Date.AddDays(1);
            var category1 = db.SubCatagories.Distinct().ToList();
            ViewBag.category = new SelectList(category1, "SubCatID", "SubCatName");
            int ddltop = Convert.ToInt32(50);
            var ch = db.Show_Ecommerce_Retailer_Report(userid, status, catagory, "Retailer", ddltop, Convert.ToDateTime(frm_date), Convert.ToDateTime(to_date)).ToList();
            DataTable dataTbl = new DataTable();
            dataTbl.Columns.Add("Vendor Name", typeof(string));
            dataTbl.Columns.Add("Product Name", typeof(string));
            dataTbl.Columns.Add("List Price", typeof(string));
            dataTbl.Columns.Add("Price", typeof(string));
            dataTbl.Columns.Add("Qty ", typeof(string));
            dataTbl.Columns.Add("Amount", typeof(string));
            dataTbl.Columns.Add("OTP", typeof(string));
            dataTbl.Columns.Add("Status", typeof(string));
            dataTbl.Columns.Add("Date", typeof(string));
            if (ch.Any())
            {
                foreach (var item in ch)
                {
                    dataTbl.Rows.Add(item.Name, item.ProductName, item.ListPrice, item.StandardPrice, item.QTY, item.Amount, item.DOTP, item.AdminStatus, item.OrderDate);
                }
            }
            else
            {
                dataTbl.Rows.Add("", "", "", "", "", "", "", "", "");
            }
            var grid = new GridView();
            grid.DataSource = dataTbl;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=Excel_Ecommerce_Report.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();
            return View();
        }
