        public ActionResult Reset_IMPSPin(string txtemail, string oTP, string oTP1, string oTP2, string oTP3)
        {
            string OTp = oTP + oTP1 + oTP2 + oTP3;
            if (oTP == null && oTP1 == null && oTP2 == null && oTP3 == null)
            {
                OTp = null;
            }
            var chk = db.Retailer_Details.Any(a => a.Email == txtemail);
            if (chk == true)
            {
                var chk1 = db.Retailer_Details.Where(a => a.Email == txtemail).SingleOrDefault();
                var optcheck = db.Users.Where(a => a.UserId == chk1.RetailerId).SingleOrDefault();
                if (optcheck.forgetpin == OTp || OTp == null)
                {
                    int pin = new Random().Next(100000, 999999);
                    var msg = Encrypt(pin.ToString());
                    var userid = User.Identity.GetUserId();
                    var id = (from tbl in db.Retailer_Details
                              where tbl.RetailerId == userid
                              select tbl).SingleOrDefault();
                    id.PIN = msg;
                    id.lastupdatetrans = DateTime.Now;
                    db.SaveChanges();
                    var emailid = db.Retailer_Details.Single(p => p.RetailerId == userid).Email;
                    try
                    {
                        var details = db.Users.Where(s => s.UserId == userid).SingleOrDefault();
                        var apiurls = "";
                        var smsapi2 = db.apisms.Where(x => x.sts == "Y").ToList();
                        var smsapionsts2 = smsapi2.Where(s => s.api_type == "whatsapp").SingleOrDefault();
                        if (smsapionsts2 != null)
                        {
                            apiurls = smsapionsts2.smsapi;
                            string text = "Your Reset Transaction Password is " + pin;
                            text = string.Format(text, "1230");
                            var apinamechange = apiurls.Replace("tttt", details.PhoneNumber).Replace("mmmm", text);
                            var whatsts = db.Email_show_passcode.SingleOrDefault();
                            var client = new RestClient(apinamechange);
                            var request = new RestRequest(Method.GET);
                            VastBazaartoken Responsetoken = new VastBazaartoken();
                            var userwise = db.retailerwise_whatsappsts.Where(a => a.userid == userid).ToList();
                            if (apinamechange.ToUpper().Contains("API.VASTBAZAAR.COM/API/WEB/WHATSAPPMSG") && whatsts.whatsappapists == true && userwise[0].sts != false)
                            {
                                var token = Responsetoken.gettoken();
                                request.AddHeader("authorization", "bearer " + token);
                                request.AddHeader("content-type", "application/json");
                            }
                            var task = Task.Run(() =>
                            {
                                return client.Execute(request).Content;
                            });
                            bool isCompletedSuccessfully = task.Wait(TimeSpan.FromSeconds(10000));
                            var resp = "";
                            if (isCompletedSuccessfully == true)
                            {
                                resp = task.Result;
                            }
                            sms_api_entry sms = new sms_api_entry();
                            sms.apiname = apinamechange;
                            sms.msg = text;
                            sms.m_date = System.DateTime.Now;
                            sms.response = resp;
                            sms.messagefor = details.UserId;
                            db.sms_api_entry.Add(sms);
                            db.SaveChanges();
                        }
                        var ToCC = db.Admin_details.FirstOrDefault().email;
                        CommUtilEmail emailsend = new CommUtilEmail();
                        smssend.SendEmailAll(details.Email, "Your  Reset Transaction Password is " + pin, "Transaction Password otp", ToCC);
                        emailsend.EmailLimitChk(emailid, ToCC, "Transaction Pin", "Your Transaction Pin Is  " + pin, "No CallBackUrl");
                    }
                    catch { }
                    TempData["success"] = "Your Transaction Pin Send Successfully in Your Mail Id . Please Check Your Mail Id.";
                    optcheck.forgetpin = null;
                    db.SaveChanges();
                }
                else
                {
                    if (OTp == "")
                    {
                        TempData["error"] = "Please Enter Otp";
                    }
                    else
                    {
                        TempData["error"] = "Your Transaction Pin Reset OTP is Wrong Please Try Again";
                    }
                }
            }
            else
            {
                TempData["error"] = "Your Email Not Verify.Please Enter Your Corrent Registered Email";
            }
            return RedirectToAction("ChangePassword");
        }
        [HttpPost]
        public ActionResult Edit_IMPSPin([Bind(Prefix = "Item2")] ChangePinViewModel model)
        {
            var userid = User.Identity.GetUserId();
            var oldpin = db.Retailer_Details.Single(p => p.RetailerId == userid).PIN;
            var oldp = Decrypt(oldpin);
            if (oldp != model.OldPin)
            {
                TempData["error"] = "Your Old Pin does Not Match .Please Re-Enter Your Old Pin ";
                return RedirectToAction("ChangePassword");
            }
            var msg = Encrypt(model.NewPin);
            var id = (from tbl in db.Retailer_Details
                      where tbl.RetailerId == userid
                      select tbl).SingleOrDefault();
            id.PIN = msg;
            id.lastupdatetrans = DateTime.Now;
            db.SaveChanges();
            var emailid = db.Retailer_Details.Single(p => p.RetailerId == userid).Email;
            try
            {
                var ToCC = db.Admin_details.FirstOrDefault().email;
                CommUtilEmail emailsend = new CommUtilEmail();
                emailsend.EmailLimitChk(emailid, ToCC, "Transaction Pin", "Your New Transaction Pin Is  " + model.NewPin, "No CallBackUrl");
            }
            catch { }
            TempData["success"] = "Your Transaction Pin Changed and Send Successfully in Your Mail Id . Please Check Your Mail Id.";
            return RedirectToAction("ChangePassword");
        }
