        [HttpGet]
        public ActionResult WalletUnloadReport()
        {
            var userid = User.Identity.GetUserId();
            DateTime todayStart = DateTime.Now.Date;
            DateTime todayEnd = DateTime.Now.AddDays(1).Date;
            modelviewwalletunload model = new modelviewwalletunload();
            model.Requests = db.WalletToBankAmountTransferRequests.Where(a => a.RetailerId == userid && a.RequestDate >= todayStart).OrderByDescending(aa => aa.RequestDate).ToList();
            var ch = db.WalletToBankAmountTransferCharges.Where(a => a.userid == userid).ToList();
            if (ch.Any())
            {
                model.Charges = db.WalletToBankAmountTransferCharges.Where(a => a.UserRole == "Retailer" && a.userid == userid).ToList();
            }
            else
            {
                model.Charges = db.WalletToBankAmountTransferCharges.Where(a => a.UserRole == "Retailer" && a.userid == "All").ToList();
            }
            model.Posledger = db.pos_ledger_report(userid, todayStart, todayEnd).Where(a => a.tras_type.ToUpper().Contains("POSTRANSFER") || a.tras_type.ToUpper().Contains("POSTRANSFER")).ToList();
            model.Posledger1 = db.pos_ledger_report(userid, todayStart, todayEnd).Where(a => a.tras_type.ToUpper().Contains("POSTODISTRIBUTORRANSFER")).ToList();
