            var remaccount = db.UpdateREMAccounts.Where(x => x.UserId == userid && x.Status == "Approved").OrderByDescending(x => x.Idno).ToList();
            ViewBag.remaccounts = new SelectList(remaccount, "BankAccountNo", "BankAccountNo", null);
            return View(model);
        }
