        [HttpPost]
        public ActionResult AddWalletToBankRequest(decimal Amount, string Type, string BankAccountNo, string Hdtransectionidgen, string txtdmtpin)
        {
            try
            {
                var stspinotp = "NOTOK";
                string dmtpin = txtdmtpin;
                var userid = User.Identity.GetUserId();
                if (Amount > 0 && !string.IsNullOrWhiteSpace(Type) && !string.IsNullOrWhiteSpace(BankAccountNo))
                {
                    var retailerDetails = db.Retailer_Details.Where(a => a.RetailerId == userid).FirstOrDefault();
                    if (retailerDetails != null)
                    {
                        if (retailerDetails.PSAStatus == "Y" && retailerDetails.AadhaarStatus == "Y" && retailerDetails.ShopwithSalfieStatus == "Y" && !string.IsNullOrEmpty(retailerDetails.pancardPath) && !string.IsNullOrEmpty(retailerDetails.aadharcardPath) && !string.IsNullOrEmpty(retailerDetails.ShopwithSalfie))
                        {
                            string transid = "";
                            try
                            {
                                transid = TempData["wallettransectiongen"].ToString();
                            }
                            catch (Exception ex)
                            {
                                var ViewResponse = new { status = "Failed", Message = "Try After SomeTime" };
                                return Json(JsonConvert.SerializeObject(ViewResponse));
                            }
                            if (!string.IsNullOrEmpty(Hdtransectionidgen) && !string.IsNullOrEmpty(transid))
                            {
                                if (transid == Hdtransectionidgen)
                                {
                                    int after = 0;
                                    try
                                    {
                                        var checktime = db.WalletToBankAmountTransferRequests.Where(x => x.RetailerId == userid && x.RequestDate <= DateTime.Now).OrderByDescending(x => x.RequestDate).Select(x => x.RequestDate).FirstOrDefault();
                                        TimeSpan ts = DateTime.Now - checktime;
                                        if (ts.TotalMinutes < 1)
                                        {
                                            after = 0;
                                        }
                                        else
                                        {
                                            after = 1;
                                        }
                                    }
                                    catch (Exception ex)
                                    {
                                        after = 1;
                                    }
                                    if (after == 1)
                                    {
                                        var pin = Encrypt(dmtpin);
                                        var pin_check = (from pi in db.Retailer_Details where pi.RetailerId == userid select pi).Single().PIN;
                                        var chkstsotp = db.dmtpin_otp_status.SingleOrDefault();
                                        if (chkstsotp != null)
                                        {
                                            if (chkstsotp.status == true)
                                            {
                                                var mobileotplist = db.MobileOtps.Where(a => a.Userid == userid && a.Type == "WALLETPINOTP").OrderByDescending(a => a.Date).ToList();
                                                var mobileotp = mobileotplist.FirstOrDefault();
                                                if (mobileotp == null)
                                                {
                                                    var ViewResponse = new { status = "Failed", Message = "OTP Error!!! Please Generate New OTP!!!" };
                                                    return Json(JsonConvert.SerializeObject(ViewResponse));
                                                }
                                                var last5minute = DateTime.Now.AddMinutes(-5);
                                                if (mobileotp.Date >= last5minute)
                                                {
                                                    if (mobileotp.Otp == dmtpin)
                                                    {
                                                        stspinotp = "OK";
                                                        db.MobileOtps.RemoveRange(mobileotplist);
                                                        db.SaveChanges();
                                                    }
                                                    else
                                                    {
                                                        var ViewResponse = new { status = "Failed", Message = "Wrong OTP!!! Please Enter Correct OTP!!!" };
                                                        return Json(JsonConvert.SerializeObject(ViewResponse));
                                                    }
                                                }
                                                else
                                                {
                                                    db.MobileOtps.RemoveRange(mobileotplist);
                                                    db.SaveChanges();
                                                    var ViewResponse = new { status = "Failed", Message = "Expire OTP!!! Please Generate New OTP!!!" };
                                                    return Json(JsonConvert.SerializeObject(ViewResponse));
                                                }
                                            }
                                            else if (chkstsotp.status == false)
                                            {
                                                var chktranss = db.Retailer_Details.Where(a => a.RetailerId == userid).SingleOrDefault();
                                                DateTime currenttime = DateTime.Now;
                                                DateTime lastchangedpassdtr = Convert.ToDateTime(chktranss.lastupdatetrans);
                                                lastchangedpassdtr = lastchangedpassdtr.AddDays(Convert.ToInt32(chktranss.transexpdays));
                                                if (lastchangedpassdtr <= currenttime)
                                                {
                                                    var ViewResponse = new { status = "Failed", Message = "Your transaction pin is expired or have to be changed!! Please set new transaction pin" };
                                                    return Json(JsonConvert.SerializeObject(ViewResponse));
                                                }
                                                if (pin == pin_check)
                                                {
                                                    stspinotp = "OK";
                                                }
                                                else
                                                {
                                                    var ViewResponse = new { status = "Failed", Message = "Wrong Pin!!! Please Enter Correct Pin!!!" };
                                                    return Json(JsonConvert.SerializeObject(ViewResponse));
                                                }
                                            }
                                        }
                                        else if (pin == pin_check)
                                        {
                                            var chktranss = db.Retailer_Details.Where(a => a.RetailerId == userid).SingleOrDefault();
                                            DateTime currenttime = DateTime.Now;
                                            DateTime lastchangedpassdtr = Convert.ToDateTime(chktranss.lastupdatetrans);
                                            lastchangedpassdtr = lastchangedpassdtr.AddDays(Convert.ToInt32(chktranss.transexpdays));
                                            if (lastchangedpassdtr <= currenttime)
                                            {
                                                var ViewResponse = new { status = "Failed", Message = "Your transaction pin is expired or have to be changed!! Please set new transaction pin" };
                                                return Json(JsonConvert.SerializeObject(ViewResponse));
                                            }
                                            stspinotp = "OK";
                                        }
                                        else
                                        {
                                            var ViewResponse = new { status = "Failed", Message = "Wrong Pin!!! Please Enter Correct Pin!!!" };
                                            return Json(JsonConvert.SerializeObject(ViewResponse));
                                        }
