        #region IndoNepal
        public ActionResult IndoNepal(string senderno)
        {
            var userid = User.Identity.GetUserId();
            ViewBag.senderno = senderno;
            var show = db.searchbyaccountno_imps("").ToList();
            ViewBag.showdata = show;
            //show pancard and aeps and mpos status
            var ch = db.Retailer_Details.Where(a => a.RetailerId == userid).FirstOrDefault();
            ViewBag.psncardsts = ch.PSAStatus;
            ViewBag.aepsandmpos = ch.AepsMposstatus;
            string jspath = Path.Combine(Server.MapPath("~/IndoNepalSenders/"), "BankBranchList.json");
            using (StreamReader reader = new StreamReader(jspath))
            {
                string jsonStringData = reader.ReadToEnd();
                dynamic jsObj = JsonConvert.DeserializeObject(jsonStringData);
                List<IndoNepalBankNameModel> lst = JsonConvert.DeserializeObject<List<IndoNepalBankNameModel>>(JsonConvert.SerializeObject(jsObj.data));
                ViewBag.banknm = lst.Select(a => new SelectListItem { Text = a.bank_name + " - " + a.branch_name + " - " + a.address, Value = a.branchid }).ToList();
                ViewBag.BANKNMCHK = lst.Select(a => new SelectListItem { Text = a.bank_name + " - " + a.branch_name + " - " + a.address, Value = a.branchid }).ToList();
            }
            ViewBag.bankdown = null;
            return View();
        }
        [HttpPost]
        public ActionResult process_sender_indonepal(string sender_number)
        {
            var userid = User.Identity.GetUserId();
            try
            {
                try
                {
                    var entry = db.IndoNepalSenders.FirstOrDefault(a => a.sendermobile == sender_number);
                    var benfList = entry.IndoNepalBeneficiaries != null ? entry.IndoNepalBeneficiaries.ToList() : null;
                    if (entry != null)
                    {
                        var response = new
                        {
                            statuscode = "TXN",
                            status = "Transaction Successful",
                            data = new
                            {
                                remitter = new { id = entry.Idno.ToString(), name = entry.sendername.ToString(), senderbob = entry.senderdob, sendergender = entry.sendergender, mobile = entry.sendermobile, address = entry.senderaddress, employer = entry.employer, senderidtype = entry.senderidtype, senderidNumber = entry.senderidnumber },
                                beneficiary = benfList.Select(a => new
                                {
                                    id = a.BenIdno,
                                    name = a.receivername,
                                    mobile = a.receivermobile,
                                    account = a.accountnumber,
                                    bank = a.branchid,
                                    status = "1",
                                    ifsc = "",
                                    imps = "1",
                                    address = a.receiveraddress,
                                    gender = a.receivergender
                                }
                                )
                            }
                        };
                        //    string json = "";
                        var jss = new JavaScriptSerializer();
                        var dict = jss.Deserialize<dynamic>(jss.Serialize(response));
                        return Json(dict, JsonRequestBehavior.AllowGet);
                        //return Json(dict).AddPartialView("_FincialViewPendingImps", pending);
                    }
                    else
                    {
                        var msg = "No data";
                        var results = "{'message':'" + msg + "','statuscode':'RNF'}";
                        var jss = new JavaScriptSerializer();
                        var dict = jss.Deserialize<dynamic>(results);
                        return Json(dict, JsonRequestBehavior.AllowGet);
                    }
                }
                catch (Exception ex)
                {
                    var msg = ex.Message.ToString();
                    var results = "{'message':'" + msg + "','status':'failure'}";
                    var jss = new JavaScriptSerializer();
                    var dict = jss.Deserialize<dynamic>(results);
                    return Json(dict, JsonRequestBehavior.AllowGet);
                }
            }
            catch (Exception ex)
            {
                var results = "{'message':'" + ex.Message + "','status':'failure'}";
                var jss = new JavaScriptSerializer();
                var dict = jss.Deserialize<dynamic>(results);
                return Json(dict, JsonRequestBehavior.AllowGet);
            }
        }
        [HttpPost]
        public ActionResult RegisterIndoNepalSender()
        {
            try
            {
                string fname, fpath;
                var file = Request.Files[0];
                var fullname = Request.Form.Get("name");
                var docType = Request.Form.Get("docType");
                var docNum = Request.Form.Get("docNumber");
                var gender = Request.Form.Get("gender");
                var dob = Request.Form.Get("dob");
                var SenderAddress = Request.Form.Get("SenderAddress");
                var pincode = Request.Form.Get("pincode");
                var sendermobile = Request.Form.Get("sendermobile");
                if (!string.IsNullOrWhiteSpace(fullname) && !string.IsNullOrWhiteSpace(docType) && !string.IsNullOrWhiteSpace(docNum) && !string.IsNullOrWhiteSpace(gender) && !string.IsNullOrWhiteSpace(dob) && !string.IsNullOrWhiteSpace(pincode))
                {
                    // Checking for Internet Explorer  
                    if (Request.Browser.Browser.ToUpper() == "IE" || Request.Browser.Browser.ToUpper() == "INTERNETEXPLORER")
                    {
                        string[] testfiles = file.FileName.Split(new char[] { '\\' });
                        fname = testfiles[testfiles.Length - 1];
                    }
                    else
                    {
                        fname = file.FileName;
                    }
                    fname = Guid.NewGuid().ToString() + "_" + fname;
                    // Get the complete folder path and store the file inside it.  
                    fpath = Path.Combine(Server.MapPath("~/IndoNepalSenders/"), fname);
                    file.SaveAs(fpath);
                    IndoNepalSender sender = new IndoNepalSender();
                    sender.CreatedBy = User.Identity.GetUserId();
                    sender.Docfilename = fname;
                    sender.employer = "";
                    sender.image_url = fpath;
