        [HttpPost]
        public ActionResult IndoNepalFundTransfer(string SenderNumber, string benIFSC, int benCode, string transamount, string key, string bank_account, string transtype, string remiterid, string gender, string address, string bankname, string totalremaincheck)
        {
            try
            {
                var userid = User.Identity.GetUserId();
                var sender = db.IndoNepalSenders.SingleOrDefault(a => a.sendermobile == SenderNumber);
                var receiver = db.IndoNepalBeneficiaries.SingleOrDefault(a => a.BenIdno == benCode);
                decimal exchangeRate = 0;
                var pin = Encrypt(key);
                var pin_check = (from pi in db.Retailer_Details where pi.RetailerId == userid select pi).Single().PIN;
                if (pin_check == pin)
                {
                    var reqObject = new
                    {
                        agentid = DateTime.Now.ToString("dd-MM-yyy hh-mm-ss").Replace("-", "").Replace(" ", "") + "INDMT",
                        sendername = sender.sendername,
                        sendergender = sender.sendergender,
                        senderdob = sender.senderdob,
                        senderaddress = sender.senderaddress,
                        sendermobile = sender.sendermobile,
                        employer = "",//TODO
                        senderidtype = sender.senderidtype,
                        senderidnumber = sender.senderidnumber,
                        receivername = receiver.receivername,
                        receivergender = receiver.receivergender,
                        receiveraddress = receiver.receiveraddress,
                        receivermobile = receiver.receivermobile,
                        mode = "BANK TRANSFER",//transtype,
                        branchid = receiver.branchid,
                        amount = transamount,
                        accountnumber = receiver.accountnumber,
                        exchangerate = "0",//TODO
                        filename = sender.Docfilename,
                        image_url = sender.image_url
                    };
                    System.Data.Entity.Core.Objects.ObjectParameter status = new System.Data.Entity.Core.Objects.ObjectParameter("Status", typeof(string));
                    System.Data.Entity.Core.Objects.ObjectParameter message = new System.Data.Entity.Core.Objects.ObjectParameter("Message", typeof(string));
                    var procResponse = db.proc_IndoNepalPreProcess(userid, sender.Idno.ToString(), benCode.ToString(), Convert.ToInt32(transamount), exchangeRate, transtype, bank_account, reqObject.agentid, bankname, JsonConvert.SerializeObject(reqObject), status, message).FirstOrDefault();
                    if (procResponse.Status != "Success")
                    {
                        var results = "{'Details':" + procResponse.Message + ",'status':'Failed'}";
                        var jss1 = new JavaScriptSerializer();
                        var dict1 = jss1.Deserialize<dynamic>(results);
                        return Json(dict1, JsonRequestBehavior.AllowGet);
                    }
                    var token = string.Empty;
                    token = getAuthToken();
                    if (string.IsNullOrWhiteSpace(token))
                    {
                        var results = "{'Details':'Failed to create request!!!','status':'Failed'}";
                        var jss1 = new JavaScriptSerializer();
                        var dict1 = jss1.Deserialize<dynamic>(results);
                        return Json(dict1, JsonRequestBehavior.AllowGet);
                    }
                    var client = new RestClient();
                    client = new RestClient(VastbazaarBaseUrl + "api/IndoNepal/send_txn");
                    string RequestJsonString = JsonConvert.SerializeObject(reqObject);
                    var request = new RestRequest(Method.POST);
                    //request.RequestFormat = DataFormat.Json;
                    request.AddHeader("content-type", "application/json");
                    request.AddHeader("cache-control", "no-cache");
                    request.AddHeader("authorization", "bearer " + token);//OAUTH token
                    request.AddParameter("application/json",
                           RequestJsonString, ParameterType.RequestBody);
                    IRestResponse response = client.Execute(request);
                    if (response.StatusCode == System.Net.HttpStatusCode.BadRequest)
                    {
                        var xx = db.proc_IndoNepalPostProcess(reqObject.agentid, "", "", "Login failed", "Failed");
                        TryLogin();
                        var results = "{'Details':'Unauthorized access!!!','status':'Failed'}";
                        var jss1 = new JavaScriptSerializer();
                        var dict1 = jss1.Deserialize<dynamic>(results);
                        return Json(dict1, JsonRequestBehavior.AllowGet);
                    }
                    dynamic respoJson = JsonConvert.DeserializeObject(response.Content);
                    if (Convert.ToString(respoJson.Content.ADDINFO.statuscode) == "TXN")
                    {
                        var xx = db.proc_IndoNepalPostProcess(reqObject.agentid, "", "", response.Content, "Success");
                        var results = "{'Details':'Processed successfully!!!','status':'Success'}";
                        var jss1 = new JavaScriptSerializer();
                        var dict1 = jss1.Deserialize<dynamic>(results);
                        return Json(dict1, JsonRequestBehavior.AllowGet);
                    }
                    else if (Convert.ToString(respoJson.Content.ADDINFO.statuscode) == "TUP")
                    {
                        var results = "{'Details':'Processed successfully!!!','status':'Success'}";
                        var jss1 = new JavaScriptSerializer();
                        var dict1 = jss1.Deserialize<dynamic>(results);
                        return Json(dict1, JsonRequestBehavior.AllowGet);
                    }
                    else
                    {
                        var xx = db.proc_IndoNepalPostProcess(reqObject.agentid, "", "", response.Content, "Failed");
                        var results = "{'Details':'" + Convert.ToString(respoJson.Content.ADDINFO.status) + "','status':'Failed'}";
                        var jss1 = new JavaScriptSerializer();
                        var dict1 = jss1.Deserialize<dynamic>(results);
                        return Json(dict1, JsonRequestBehavior.AllowGet);
                    }
                }
                else
                {
                    var results = "{'Details':'Wrong Pin!!! Please Enter Correct Pin!!!','status':'Failed'}";
                    var jss1 = new JavaScriptSerializer();
                    var dict1 = jss1.Deserialize<dynamic>(results);
                    return Json(dict1, JsonRequestBehavior.AllowGet);
                }
            }
            catch
            {
                var results = "{'Details':'Internal Error!!!','status':'Failed'}";
                var jss1 = new JavaScriptSerializer();
                var dict1 = jss1.Deserialize<dynamic>(results);
                return Json(dict1, JsonRequestBehavior.AllowGet);
            }
        }
