        public ActionResult Excel_Retailer_Daybook_Report(DateTime txt_frm_date,DateTime txt_to_date)
        {
            var userid = User.Identity.GetUserId();
            Daybookretailerrreport rep = new Daybookretailerrreport();
            txt_to_date = txt_to_date.AddDays(1);
            DataTable dataTbl = new DataTable();
            dataTbl.Columns.Add("Firm Name", typeof(string));
            dataTbl.Columns.Add("Recharge & Bill", typeof(string));
            dataTbl.Columns.Add("IMPS", typeof(string));
            dataTbl.Columns.Add("AEPS", typeof(string));
            dataTbl.Columns.Add("M-POS ", typeof(string));
            dataTbl.Columns.Add("Pancard ", typeof(string));
            dataTbl.Columns.Add("Travel", typeof(string));
            dataTbl.Columns.Add("Purchase ", typeof(string));
            dataTbl.Columns.Add("Opening Bal ", typeof(string));
            dataTbl.Columns.Add("Closing Bal", typeof(string));
            dataTbl.Columns.Add("Old Day Refund", typeof(string));
            dataTbl.Columns.Add("Old Day Failed", typeof(string));
            dataTbl.Columns.Add("Diff", typeof(string));
            if (DateTime.Now.Date == txt_frm_date.Date)
            {
                rep.Daybooklive = db.Retailer_daybook_report_live(userid, txt_frm_date, txt_to_date).ToList();
            }
            else
            {
                rep.DayboolOLD = db.Retailer_daybook_report_Old(userid, txt_frm_date, txt_to_date).ToList();
            }
            if (rep.Daybooklive.Any())
            {
                foreach (var item in rep.Daybooklive)
                {
                    dataTbl.Rows.Add(item.Frm_Name == null ? item.RetailerName : item.Frm_Name, item.RCH, item.IMPS, item.AEPS, 0.00, item.PAN, 0.00, item.PURCHASE, item.openbal, item.closebal, item.OLDDAYREFUND, item.OLDDAYFAILED, item.DIFF); ;
                }
            }
            else if (rep.DayboolOLD.Any())
            {
                foreach (var item in rep.DayboolOLD)
                {
                    dataTbl.Rows.Add(item.Frm_Name == null ? item.RetailerName : item.Frm_Name, item.RCH, item.IMPS, item.AEPS, 0.00, item.PAN, 0.00, item.PURCHASE, item.openbal, item.closebal, item.OLDDAYREFUND, item.OLDDAYFAILED, item.DIFF); ;
                }
            }
            else
            {
                dataTbl.Rows.Add("", "", "", "", "", "", "", "", "", "", "", "", "");
            }
            var grid = new GridView();
            grid.DataSource = dataTbl;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=Excel_Retailer_Daybook_Report.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();
            return View();
        }
