        public ActionResult ExcelSecurityReport(string ddl_status, DateTime txt_frm_date, DateTime txt_to_date)
        {
            ViewBag.chk = "post";
            var userid = User.Identity.GetUserId();
            DateTime to = txt_to_date.AddDays(1);
            var ch = db.history_norton("Retailer", userid, txt_frm_date, to, ddl_status).ToList();
            DataTable dataTbl = new DataTable();
            dataTbl.Columns.Add("Status", typeof(string));
            dataTbl.Columns.Add("Plan Name", typeof(string));
            dataTbl.Columns.Add("Customer Mobile", typeof(string));
            dataTbl.Columns.Add("Customer Email", typeof(string));
            dataTbl.Columns.Add("Pre Amt", typeof(string));
            dataTbl.Columns.Add("Amount", typeof(string));
            dataTbl.Columns.Add("Cr/Dr Amt", typeof(string));
            dataTbl.Columns.Add("Post Amt", typeof(string));
            dataTbl.Columns.Add("Request Time", typeof(string));
            dataTbl.Columns.Add("Operator Id", typeof(string));
            if (ch.Count > 0)
            {
                foreach (var item in ch)
                {
                    decimal final = Convert.ToDecimal(item.amount) - Convert.ToDecimal(item.total_rem_pay);
                    dataTbl.Rows.Add(item.Status, item.plan_nm, item.customermobile, item.customeremail, item.rempre, item.amount, final, item.rempost, item.transfer_time, item.OPerator_id);
                }
            }
            else
            {
                dataTbl.Rows.Add("", "", "", "", "", "", "", "", "", "");
            }
            var grid = new GridView();
            grid.DataSource = dataTbl;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=Security_Report.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();
            return View();
        }
