                    {
                        var checKYC = db.Retailer_Details.Where(x => x.RetailerId == userid).SingleOrDefault();
                        if (!string.IsNullOrEmpty(checKYC.pancardPath) && !string.IsNullOrEmpty(checKYC.aadharcardPath) && !string.IsNullOrEmpty(checKYC.BackSideAadharcardphoto) && checKYC.PSAStatus == "Y" && checKYC.AadhaarStatus == "Y" && !string.IsNullOrEmpty(checKYC.ShopwithSalfie) && checKYC.ShopwithSalfieStatus == "Y")
                        {
                            done = "OK";
                        }
                        else
                        {
                            done = "NOTOK";
                        }
                    }
