        [HttpPost]
        public ActionResult RadaintUPIATMSendOTP(string amount)
        {
            var userid = User.Identity.GetUserId();
            var retailerinfo = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
            var radiantauthchk = db.radiantauths.SingleOrDefault();
            var radiantresponse = db.rediantremtresponses.Where(aa => aa.userid == userid).SingleOrDefault();
            Radiantdmt radi = new Radiantdmt();
            var tokenchk = db.radianttokens.SingleOrDefault();
            var msg = ""; var refid = ""; var otpRef_id = "";
            if (tokenchk == null)
            {
                radi.Token(out radianttoken, out radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radiantresponse.username, radiantresponse.password);
            }
            else
            {
                radianttoken = tokenchk.accessToken;
                radianagentid = tokenchk.agentID;
            }
            var respchk = radi.UPIATMsendOTP(radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radianttoken, retailerinfo.Mobile, retailerinfo.RetailerName, amount);
            if (respchk.StatusCode == HttpStatusCode.NotAcceptable)
            {
                radi.Token(out radianttoken, out radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radiantresponse.username, radiantresponse.password);
                respchk = radi.UPIATMsendOTP(radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radianttoken, retailerinfo.Mobile, retailerinfo.RetailerName, amount);
            }
            if (respchk.StatusCode == HttpStatusCode.OK)
            {
                dynamic dyrespchk = JsonConvert.DeserializeObject(respchk.Content);
                if (dyrespchk.success == true)
                {
                    msg = "OK";
                    refid = dyrespchk.refid;
                    otpRef_id = dyrespchk.otpRef_id;
                }
                else
                {
                    msg = dyrespchk.message;
                }
            }
            else
            {
                dynamic dyrespchk = JsonConvert.DeserializeObject(respchk.Content);
                msg = dyrespchk.message;
            }
            var respout = new
            {
                msg,
                refid,
                otpRef_id
            };
            var outmsg = JsonConvert.SerializeObject(respout);
            return Json(outmsg, JsonRequestBehavior.AllowGet);
        }
        [HttpPost]
        public ActionResult RadaintUPIATMverifyOTP(string otp, string refid, string otprefid, decimal amount)
        {
            var userid = User.Identity.GetUserId();
            var radiantauthchk = db.radiantauths.SingleOrDefault();
            var radiantresponse = db.rediantremtresponses.Where(aa => aa.userid == userid).SingleOrDefault();
            Radiantdmt radi = new Radiantdmt();
            var tokenchk = db.radianttokens.SingleOrDefault();
            var msg = ""; var QR = "";
            if (tokenchk == null)
            {
                radi.Token(out radianttoken, out radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radiantresponse.username, radiantresponse.password);
            }
            else
            {
                radianttoken = tokenchk.accessToken;
                radianagentid = tokenchk.agentID;
            }
            var respchk = radi.UPIATMverifyOTP(radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radianttoken, otprefid, refid, otp);
            if (respchk.StatusCode == HttpStatusCode.NotAcceptable)
            {
                radi.Token(out radianttoken, out radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radiantresponse.username, radiantresponse.password);
                respchk = radi.UPIATMverifyOTP(radianagentid, radiantauthchk.clientID, radiantauthchk.clientSecret, radiantauthchk.APIKey, radianttoken, otprefid, refid, otp);
            }
            if (respchk.StatusCode == HttpStatusCode.OK)
            {
                dynamic dyrespchk = JsonConvert.DeserializeObject(respchk.Content);
                if (dyrespchk.success == true)
                {
                    msg = "OK";
                    string upitxt = dyrespchk.qrData;
                    string refid1 = dyrespchk.refId;
                    Rem_UPI_REQUEST req = new Rem_UPI_REQUEST();
                    req.amount = amount;
                    req.retailerid = userid;
                    req.Bankrrn = "RADIANTQR";
                    req.UPITXNID = refid1;
                    req.transferdate = DateTime.Now;
                    req.requestdate = DateTime.Now;
                    req.responsedate = DateTime.Now;
                    req.status = "PENDING";
                    db.Rem_UPI_REQUEST.Add(req);
                    db.SaveChanges();


                    var bw = new BarcodeWriter();
                    var encOptions = new ZXing.Common.EncodingOptions
                    {
                        Width = 500,
                        Height = 500,
                        Margin = 0,
                        PureBarcode = false
                    };
                    bw.Renderer = new BitmapRenderer();
                    bw.Options = encOptions;
                    bw.Format = ZXing.BarcodeFormat.QR_CODE;
                    using (MemoryStream memory = new MemoryStream())
                    {
                        Bitmap bm = bw.Write(upitxt);
                        bm.Save(memory, ImageFormat.Png);
                        QR = "data:image/png;base64," + Convert.ToBase64String(memory.ToArray());
                    }
                }
                else
                {
                    msg = dyrespchk.message;
                }
            }
            else
            {
                dynamic dyrespchk = JsonConvert.DeserializeObject(respchk.Content);
                msg = dyrespchk.message;
            }

            var respout = new
            {
                msg,
                QR
            };
            var outmsg = JsonConvert.SerializeObject(respout);
            return Json(outmsg, JsonRequestBehavior.AllowGet);
        }
        public ActionResult UPICollection()
        {
            ViewBag.chkmsg = TempData["respmsgreq"];
            var userid = User.Identity.GetUserId();
            var upisettinginfo = db.UPIandGatewayStatus.Where(aa => aa.Status == true && aa.Name == "UPI_Collection").SingleOrDefault();
            if (upisettinginfo != null)
            {
                var apiname = db.UPI_Collection_API.Where(aa => aa.sts == true).SingleOrDefault();
                if (apiname != null)
                {
                    ViewBag.msg = "OK";
                    ViewBag.Api = apiname.Name;
                    var done = "OK";
                    var kycsts = db.upi_kyc_status.SingleOrDefault().isekyc;
                    if (kycsts == true)
                    {
                        var checKYC = db.Retailer_Details.Where(x => x.RetailerId == userid).SingleOrDefault();
                        if (!string.IsNullOrEmpty(checKYC.pancardPath) && !string.IsNullOrEmpty(checKYC.aadharcardPath) && !string.IsNullOrEmpty(checKYC.BackSideAadharcardphoto) && checKYC.PSAStatus == "Y" && checKYC.AadhaarStatus == "Y" && !string.IsNullOrEmpty(checKYC.ShopwithSalfie) && checKYC.ShopwithSalfieStatus == "Y")
                        {
                            done = "OK";
                        }
                        else
                        {
                            done = "NOTOK";
                        }
                    }
                    if (done == "OK")
                    {
                        if (apiname.Name == "RADIANT")
                        {
                            ViewBag.set = "OK";
                        }
