        public string calculatecharge_gateway(decimal amount, string type)
        {
            var userid = User.Identity.GetUserId();
            var chk = db.PaymentGatewaycharge_new.Where(s => s.userid == userid).SingleOrDefault();
            var obj = new JObject();
            if (chk == null)
            {
                obj.Add("status", false);
                return JsonConvert.SerializeObject(obj);
            }
            else
            {
                obj.Add("status", true);
                if (type == "NB")
                {
                    var cols = new JArray();
                    var status = new JObject();
                    var hdfc_icici = new JObject();
                    var axis = new JObject();
                    var other = new JObject();
                    var sub_cols = new JArray();
                    sub_cols.Add("charge");
                    sub_cols.Add("total");
                    sub_cols.Add("net");
                    status.Add("text", "Status");
                    hdfc_icici.Add("text", "HDFC/ICICI");
                    hdfc_icici.Add("cols", sub_cols);
                    axis.Add("text", "AXIS/SBI/KOTAK");
                    axis.Add("cols", sub_cols);
                    other.Add("text", "OTHERS");
                    other.Add("cols", sub_cols);
                    cols.Add(status);
                    cols.Add(hdfc_icici);
                    cols.Add(axis);
                    cols.Add(other);
                    var values = new JArray();
                    values.Add(chk.netbankingsts);
                    var hdfc_val = new JArray();
                    hdfc_val.Add(chk.netbanking);
                    var charge_amt = (chk.netbanking * amount) / 100;
                    var gst = (charge_amt * 18) / 100;
                    var total_charge = charge_amt + gst;
                    hdfc_val.Add(total_charge);
                    hdfc_val.Add(amount - total_charge);
                    var axis_val = new JArray();
                    axis_val.Add(chk.axis);
                    var chargeaxis_amt = (chk.axis * amount) / 100;
                    var gstaxis = (chargeaxis_amt * 18) / 100;
                    var totalaxis_charge = chargeaxis_amt + gstaxis;
                    axis_val.Add(totalaxis_charge);
                    axis_val.Add(amount - totalaxis_charge);
                    var other_val = new JArray();
                    other_val.Add(chk.others);
                    var chargeother_amt = chk.others;
                    var gstother = (chargeother_amt * 18) / 100;
                    var totalother_charge = chargeother_amt + gstother;
                    other_val.Add(totalother_charge);
                    other_val.Add(amount - totalother_charge);
                    values.Add(hdfc_val);
                    values.Add(axis_val);
                    values.Add(other_val);
                    obj.Add("cols", cols);
                    obj.Add("values", values);
                }
                else if (type == "WA")
                {
                    var cols = new JArray();
                    cols.Add("Status");
                    cols.Add("Charge");
                    cols.Add("Total");
                    cols.Add("Net Received");
                    var values = new JArray();
                    values.Add(chk.walletsts);
                    values.Add(chk.wallet);
                    var charge_amt = (chk.wallet * amount) / 100;
                    var gst = (charge_amt * 18) / 100;
                    var total_charge = charge_amt + gst;
                    values.Add(total_charge);
                    values.Add(amount - total_charge);
                    obj.Add("cols", cols);
                    obj.Add("values", values);
                }
                else if (type == "UP")
                {
                    var cols = new JArray();
                    cols.Add("Status");
                    cols.Add("Charge");
                    cols.Add("Total");
                    cols.Add("Net Received");
                    var values = new JArray();
                    values.Add(chk.upists);
                    values.Add(chk.UPI);
                    var charge_amt = (chk.UPI * amount) / 100;
                    var gst = (charge_amt * 18) / 100;
                    var total_charge = charge_amt + gst;
                    values.Add(total_charge);
                    values.Add(amount - total_charge);
                    obj.Add("cols", cols);
                    obj.Add("values", values);
                }
                else if (type == "DC")
                {
                    var cols = new JArray();
                    cols.Add("Status");
                    var sub_cols = new JArray();
                    sub_cols.Add("charge");
                    sub_cols.Add("total");
                    sub_cols.Add("net");
                    var rupay = new JObject();
                    rupay.Add("text", "RUPAY");
                    rupay.Add("cols", sub_cols);
                    var other = new JObject();
                    other.Add("text", "OTHERS");
                    var other_cols = new JArray();
                    var upto2k = new JObject();
                    upto2k.Add("text", "UpTo 2K");
                    upto2k.Add("cols", sub_cols);
                    var above2k = new JObject();
                    above2k.Add("text", "Above 2K");
                    above2k.Add("cols", sub_cols);
                    other_cols.Add(upto2k);
                    other_cols.Add(above2k);
                    other.Add("cols", other_cols);
                    cols.Add(rupay);
                    cols.Add(other);
                    var values = new JArray();
                    values.Add(chk.DebitCardsts);
                    var rupay_array = new JArray();
                    rupay_array.Add(chk.rupaydebit);
                    rupay_array.Add((chk.rupaydebit * amount) / 100);
                    rupay_array.Add(amount - (chk.rupaydebit * amount) / 100);
                    var upto2k_array = new JArray();
                    upto2k_array.Add(chk.debitupto2000);
                    var charge2000_amt = (chk.debitupto2000 * amount) / 100;
                    var gst2000 = (charge2000_amt * 18) / 100;
                    var total2000_charge = charge2000_amt + gst2000;
                    upto2k_array.Add(total2000_charge);
                    upto2k_array.Add(amount - total2000_charge);
                    var above2k_array = new JArray();
                    above2k_array.Add(chk.debitabove2000);
                    var charge2001_amt = (chk.debitabove2000 * amount) / 100;
                    var gst2001 = (charge2001_amt * 18) / 100;
                    var total2001_charge = charge2001_amt + gst2001;
                    above2k_array.Add(total2001_charge);
                    above2k_array.Add(amount - total2001_charge);
                    var other_array = new JArray();
                    other_array.Add(upto2k_array);
                    other_array.Add(above2k_array);
                    values.Add(rupay_array);
                    values.Add(other_array);
                    obj.Add("cols", cols);
                    obj.Add("values", values);
                }
                else if (type == "CC")
                {
                    var cols = new JArray();
                    cols.Add("Status");
                    cols.Add("Charge");
                    cols.Add("Total");
                    cols.Add("Net Received");
                    var values = new JArray();
                    values.Add(chk.CreditCardsts);
                    values.Add(chk.creditcard);
                    var charge_amt = (chk.creditcard * amount) / 100;
                    var gst = (charge_amt * 18) / 100;
                    var total_charge = charge_amt + gst;
                    values.Add(total_charge);
                    values.Add(amount - total_charge);
                    obj.Add("cols", cols);
                    obj.Add("values", values);
                }
                return JsonConvert.SerializeObject(obj);
            }
        }
        public ActionResult UPITRANSFER()
        {
            var userid = User.Identity.GetUserId();
            var done = "OK";
            var upistatus = db.Hidw_Show.Where(x => x.UseFor.ToUpper() == "UPI").FirstOrDefault().Status;
            ViewData["upi_msg"] = TempData["upimsg"];
            ViewData["UPICollect"] = TempData["UPICollect"];
            TempData.Remove("upimsg");
            TempData.Remove("QRCodeImage");
            TempData.Remove("UPICollect");
            TempData.Remove("GetUniqueid");
            if (upistatus == "Y")
            {
                var chkchk = db.Upi_slab.SingleOrDefault();
                if (chkchk != null)
                {
                    var kycsts = db.upi_kyc_status.SingleOrDefault().isekyc;
                    if (kycsts == true)
                    {
                        var checKYC = db.Retailer_Details.Where(x => x.RetailerId == userid).SingleOrDefault();
                        if (!string.IsNullOrEmpty(checKYC.pancardPath) && !string.IsNullOrEmpty(checKYC.aadharcardPath) && !string.IsNullOrEmpty(checKYC.BackSideAadharcardphoto) && checKYC.PSAStatus == "Y" && checKYC.AadhaarStatus == "Y" && !string.IsNullOrEmpty(checKYC.ShopwithSalfie) && checKYC.ShopwithSalfieStatus == "Y")
                        {
                            done = "OK";
                            ViewBag.msg = "";
                        }
                        else
                        {
                            done = "NOTOK";
                            ViewBag.msg = "Your Kyc is Due.";
                        }
                    }
                    if (done == "OK")
                    {
                        var apiupi = db.UPI_API.SingleOrDefault() ?? null;
                        if (apiupi != null)
                        {
                            if (apiupi.APIID == "ICICI")
                            {
                                ViewBag.Upi_Qr_codeGenerator = db.Upi_Qr_codeGenerator.Where(x => x.status == true).SingleOrDefault();
                                var chk = db.UPI_Ref_details.Where(aa => aa.userid == userid).SingleOrDefault();
                                if (chk == null)
                                {
                                    ViewBag.msg = "QR Not Genrated";
                                    ViewBag.set = "NOTOK";
                                }
                                else
                                {
                                    var upiinfo = db.Upi_info.SingleOrDefault();
                                    if (upiinfo != null)
                                    {
                                        var rem = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
                                        var finaltxn = db.UPI_Ref_details.Where(aa => aa.userid == userid).SingleOrDefault().UPITxnid;
                                        var generateQr = db.Upi_Qr_codeGenerator.Where(x => x.status == true).SingleOrDefault();
                                        if (generateQr != null)
                                        {
                                            ViewBag.Upi_Qr_codeGenerator = generateQr;
                                            ViewBag.set = "NOTOK";
                                        }
                                        else
                                        {
                                            ViewBag.Upi_Qr_codeGenerator = null;
                                            var upitxt = "upi://pay?pa=" + upiinfo.MerchantVPA + "&pn=test&tr=" + finaltxn + "&am=&cu=INR&mc=5411";
                                            var bw = new BarcodeWriter();
                                            var encOptions = new ZXing.Common.EncodingOptions
                                            {
                                                Width = 500,
                                                Height = 500,
                                                Margin = 0,
                                                PureBarcode = false
                                            };
                                            bw.Renderer = new BitmapRenderer();
                                            bw.Options = encOptions;
                                            bw.Format = ZXing.BarcodeFormat.QR_CODE;
                                            using (MemoryStream memory = new MemoryStream())
                                            {
                                                Bitmap bm = bw.Write(upitxt);
                                                bm.Save(memory, ImageFormat.Png);
                                                TempData["QRCodeImage"] = "data:image/png;base64," + Convert.ToBase64String(memory.ToArray());
                                            }
                                        }
                                    }
                                    else
                                    {
                                        done = "NOTOK";
                                        ViewBag.msg = "Not Set Upi infomation";
                                    }
                                }
                            }
                            else if (apiupi.APIID == "PAYU")
                            {
                                var payuauth = db.Payu_QR_auth.SingleOrDefault();
                                if (payuauth == null)
                                {
                                    ViewBag.msg = "QR Auth Not Found";
                                }
                                else
                                {
                                    var payuqrcheck = db.PAYU_QR_info.Where(aa => aa.userid == userid).SingleOrDefault();
                                    if (payuqrcheck == null)
                                    {
                                        ViewBag.set = "NOTOK";
                                    }
                                    else
                                    {
                                        TempData["QRCodeImage"] = payuqrcheck.QRCODE;
                                    }
                                }
                            }
                            else if (apiupi.APIID == "CFREE")
                            {
                                var cfree = db.cashfree_auth.SingleOrDefault();
                                if (cfree == null)
                                {
                                    ViewBag.msg = "QR Auth Not Found";
                                }
                                else
                                {
                                    var generateQr = db.Upi_Qr_codeGenerator.Where(x => x.status == true).SingleOrDefault();
                                    if (generateQr != null)
                                    {
                                        ViewBag.Upi_Qr_codeGenerator = generateQr;
                                        ViewBag.set = "NOTOK";
                                    }
                                }
                            }
                            else
                            {
                                ViewBag.msg = "UPI Api Not Set";
                            }
                        }
                        else
                        {
                            ViewBag.msg = "UPI Api Not Set";
                        }
                    }
                }
                else
                {
                    ViewBag.msg = "Slab Not Set.";
                }
            }
            else
            {
                ViewBag.msg = "UPI Status Not Active";
            }
            var slab = db.Upi_slab.SingleOrDefault();
            if (slab == null)
            {
                ViewBag.min = 0;
                ViewBag.charge = 0;
            }
            else
            {
                ViewBag.min = slab.min;
                ViewBag.charge = slab.Charge;
            }
            DateTime from = DateTime.Now.Date;
            DateTime to = DateTime.Now.AddDays(1).Date;
            var ch = db.show_upi_txn_details("Retailer", userid, "ALL", from, to);
            var upitxndetails = db.Upi_txn_details.Where(x => x.userid == userid && x.rolename == "Retailer" && x.txndate >= from && x.txndate <= to);
            var totalsuccess = upitxndetails.Where(x => x.status.ToUpper().Contains("SUCCESS")).Sum(x => x.amt);
            var totalFailed = upitxndetails.Where(x => x.status.ToUpper().Contains("FAILED")).Sum(x => x.amt);
            var totalpending = upitxndetails.Where(x => x.status.ToUpper().Contains("PENDING")).Sum(x => x.amt);
            var totalcharges = upitxndetails.Sum(x => x.charge);
            ViewBag.totalsuccess = totalsuccess;
            ViewBag.totalfailedamount = totalFailed;
            ViewBag.totalpendingamount = totalpending;
            ViewBag.totalchargesamount = totalcharges;
            ViewBag.cfreeapi = db.UPI_API.Where(a => a.APIID == "CFREE").SingleOrDefault();
            ViewBag.phonepe = db.UPI_API.Where(a => a.APIID == "PHONEPE").SingleOrDefault();
            return View(ch);
        }
