        [HttpPost]
        public ActionResult UPITRANSFER_add()
        {
            var kycstatus = "NOTKYCUSER";
            var userid = User.Identity.GetUserId();
            var chkfor = db.UPI_Ref_details.Where(aa => aa.userid == userid).SingleOrDefault();
            var checKYC = db.Retailer_Details.Where(x => x.RetailerId == userid).SingleOrDefault();
            var kycsts = db.upi_kyc_status.SingleOrDefault().isekyc;
            if (kycsts == true)
            {
                if (!string.IsNullOrEmpty(checKYC.pancardPath) && !string.IsNullOrEmpty(checKYC.aadharcardPath) && !string.IsNullOrEmpty(checKYC.BackSideAadharcardphoto) && checKYC.PSAStatus == "Y" && checKYC.AadhaarStatus == "Y" && !string.IsNullOrEmpty(checKYC.ShopwithSalfie) && checKYC.ShopwithSalfieStatus == "Y")
                {
                    kycstatus = "FULLKYC";
                }
                if (kycstatus == "FULLKYC")
                {
                    var upiapi = db.UPI_API.SingleOrDefault() ?? null;
                    if (upiapi != null)
                    {
                        if (upiapi.APIID == "ICICI")
                        {
                            var upiinfo = db.Upi_info.SingleOrDefault();
                            if (upiinfo == null)
                            {
                                TempData["upimsg"] = "Upi Information Not Found";
                                return RedirectToAction("UPITRANSFER");
                            }
                            else if (string.IsNullOrEmpty(upiinfo.UpiPreFix))
                            {
                                TempData["upimsg"] = "Upi Information Not Found";
                                return RedirectToAction("UPITRANSFER");
                            }
                            if (chkfor != null)
                            {
                                TempData["upimsg"] = "Not Genrated UPI";
                                return RedirectToAction("UPITRANSFER");
                            }
                            var upistatus = db.Hidw_Show.Where(x => x.UseFor.ToUpper() == "UPI").FirstOrDefault().Status;
                            if (upistatus == "Y")
                            {
                                var rem = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
                                var admindetails = db.Admin_details.SingleOrDefault();
                                var txnid = admindetails.WebsiteUrl.Substring(0, 4);
                                var datetxn = DateTime.Now.ToString("dd-MM-yyy hh-mm-ss").Replace("-", "").Replace(" ", "");
                                Random random = new Random();
                                var ran = random.Next(11, 99);
                                var finaltxn = upiinfo.UpiPreFix + txnid + datetxn + ran;
                                if (upiinfo.MerchantVPA.Contains("VWIPL"))
                                {
                                    var token = string.Empty;
                                    token = getAuthToken();
                                    if (string.IsNullOrWhiteSpace(token))
                                    {
                                        ViewBag.msg = "Failed at provider server";
                                        return RedirectToAction("UPITRANSFER");
                                    }
                                    var req = new
                                    {
                                        upitxnid = finaltxn,
                                        useremail = rem.Email,
                                        userrole = "Retailer",
                                        username = rem.RetailerName,
                                        userfirm = rem.Frm_Name
                                    };
                                    var freq = JsonConvert.SerializeObject(req);
                                    var client = new RestClient("http://api.vastbazaar.com/api/UPI/UPIUSER");
                                    var request = new RestRequest(Method.POST);
                                    request.AddHeader("Authorization", "Bearer " + token);
                                    request.AddHeader("Content-Type", "application/json");
                                    request.AddParameter("application/json", freq, ParameterType.RequestBody);
                                    IRestResponse response = client.Execute(request);
                                    var resp = response.Content;
                                    dynamic reschk = JsonConvert.DeserializeObject(resp);
                                    var sts = reschk.Content.ADDINFO.Status.ToString();
                                    var statusMessage = reschk.Content.ADDINFO.statusMessage.ToString();
                                    if (sts.ToUpper() == "SUCCESS")
                                    {
                                        UPI_Ref_details upi = new UPI_Ref_details();
                                        upi.crdate = DateTime.Now;
                                        upi.role = "Retailer";
                                        upi.UPITxnid = finaltxn;
                                        upi.userid = userid;
                                        db.UPI_Ref_details.Add(upi);
                                        db.SaveChanges();
                                    }
                                    else
                                    {
                                        ViewBag.msg = statusMessage;
                                    }
                                }
                                else
                                {
                                    UPI_Ref_details upi = new UPI_Ref_details();
                                    upi.crdate = DateTime.Now;
                                    upi.role = "Retailer";
                                    upi.UPITxnid = finaltxn;
                                    upi.userid = userid;
                                    db.UPI_Ref_details.Add(upi);
                                    db.SaveChanges();
                                }
                                return RedirectToAction("UPITRANSFER");
                            }
                            else
                            {
                                TempData["upimsg"] = "UPI Status Off";
                                return RedirectToAction("UPITRANSFER");
                            }
                        }
                        else if (upiapi.APIID == "PAYU")
                        {
                            var upistatus = db.Hidw_Show.Where(x => x.UseFor.ToUpper() == "UPI").FirstOrDefault().Status;
                            if (upistatus == "Y")
                            {
                                var upiinfochk = db.PAYU_QR_info.Where(aa => aa.userid == userid).SingleOrDefault();
                                var payuauth = db.Payu_QR_auth.SingleOrDefault();
                                if (upiinfochk == null)
                                {
