        public ActionResult uploadgstfile()
        {
            ViewBag.chk = "post";
            var userid = User.Identity.GetUserId();
            if (Request.Files.Count > 0)
            {
                try
                {
                    HttpFileCollectionBase files = Request.Files;
                    for (int i = 0; i < files.Count; i++)
                    {
                        string Month = Request.Form["month"];
                        string Year = Request.Form["year"];
                        HttpPostedFileBase file = files[i];
                        string extension = Path.GetExtension(file.FileName);
                        if (extension.ToUpper() == ".PDF")
                        {
                            string fname = file.FileName;
                            fname = Month + Year + userid + fname;
                            string filenm = fname;
                            fname = Path.Combine(Server.MapPath("~/UploadGst/Retailer"), fname);
                            file.SaveAs(fname);
                            var chk = db.Retailer_upload_gst.Where(aa => aa.retailerid == userid && aa.monthchk == Month && aa.yearchk == Year && (aa.status == "Approved" || aa.status == "Pending")).SingleOrDefault();
                            if (chk == null)
                            {
                                Retailer_upload_gst up = new Retailer_upload_gst();
                                up.monthchk = Month;
                                up.retailerid = userid;
                                up.status = "Pending";
                                up.uploadfile = "UploadGst/Retailer/" + filenm;
                                up.yearchk = Year;
                                db.Retailer_upload_gst.Add(up);
                                db.SaveChanges();
                            }
                        }
                    }
                    return Json("File Uploaded Successfully!");
                }
                catch (Exception ex)
                {
                    return Json("Error occurred. Error details: " + ex.Message);
                }
            }
            else
            {
                return Json("No files selected.");
            }
        }
