        public ActionResult Rechargeuploadgstfile()
        {
            var userid = User.Identity.GetUserId();
            if (Request.Files.Count > 0)
            {
                try
                {
                    HttpFileCollectionBase files = Request.Files;
                    for (int i = 0; i < files.Count; i++)
                    {
                        string Month = Request.Form["month"];
                        string Year = Request.Form["year"];
                        HttpPostedFileBase file = files[i];
                        string extension = Path.GetExtension(file.FileName);
                        if (extension.ToUpper() == ".PDF")
                        {
                            string fname = file.FileName;
                            fname = "Recharge" + Month + Year + userid + fname;
                            string filenm = fname;
                            fname = Path.Combine(Server.MapPath("~/UploadGst/Retailer"), fname);
                            file.SaveAs(fname);
                            var chk = db.Retailer_Recharge_upload_gst.Where(aa => aa.retailerid == userid && aa.monthchk == Month && aa.yearchk == Year && (aa.status == "Approved" || aa.status == "Pending")).SingleOrDefault();
                            if (chk == null)
                            {
                                Retailer_Recharge_upload_gst up = new Retailer_Recharge_upload_gst();
                                up.monthchk = Month;
                                up.retailerid = userid;
                                up.status = "Pending";
                                up.uploadfile = "UploadGst/Retailer/" + filenm;
                                up.yearchk = Year;
                                db.Retailer_Recharge_upload_gst.Add(up);
                                db.SaveChanges();
                            }
                        }
                    }
                    return Json("File Uploaded Successfully!");
                }
                catch (Exception ex)
                {
                    return Json("Error occurred. Error details: " + ex.Message);
                }
            }
            else
            {
                return Json("No files selected.");
            }
        }
        public ActionResult Certificate()
        {
            var userid = User.Identity.GetUserId();
            var confirm = false; var name = ""; var firmname = "";
            var message = ""; var mobile = ""; var address = ""; var joindate = "";
            var photo = "";
            var userinfo = db.Users.Where(aa => aa.UserId == userid).SingleOrDefault();
            var token = string.Empty;
            token = getAuthToken();
            var client = new RestClient("http://api.vastbazaar.com/api/Web/KycStatus");
            client.Timeout = -1;
            var request = new RestRequest(Method.POST);
            request.AddHeader("Authorization", "Bearer " + token);
            IRestResponse response = client.Execute(request);
            var respp = response.Content;
            dynamic chkkk = JsonConvert.DeserializeObject(respp);
            // kyc sts var bazaar
            var kycsts = chkkk.Content.ADDINFO.kycsts;
            if (kycsts == true)
            {
                // aggrement vastbazaar
                string aggrement = chkkk.Content.ADDINFO.aggrement;
                if (string.IsNullOrEmpty(aggrement) == false)
                {
                    //1. Email Confirm
                    var emailconfirm = userinfo.EmailConfirmed;
                    if (emailconfirm == true)
                    {
                        //2. Mobile Confirm
                        var mobileconfirm = userinfo.PhoneNumberConfirmed;
                        if (mobileconfirm == true)
                        {
                            var reminfo = db.Retailer_Details.Where(aa => aa.RetailerId == userid).SingleOrDefault();
                            //3. panconfirm
                            var panconfirm = reminfo.pan_verification;
                            if (panconfirm == true)
                            {
                                //4. aadharconfirm
                                var aadharconfirm = reminfo.aadhar_verification;
                                if (aadharconfirm == true)
                                {
                                    confirm = true;
                                    name = reminfo.RetailerName;
                                    firmname = reminfo.Frm_Name;
                                    mobile = reminfo.Mobile;
                                    address = reminfo.Address;
                                    joindate = reminfo.JoinDate.ToString("dd-MM-yyyy");
                                    photo = reminfo.aadhar_image;
                                }
                                else
                                {
                                    message = "Aadhar is Not Confirmed";
                                }
                            }
                            else
                            {
                                message = "Pan Card is Not Confirmed";
                            }
                        }
                        else
                        {
                            message = "Mobile is Not Confirmed";
                        }
                    }
                    else
                    {
                        message = "Email is Not Confirmed";
                    }
                }
                else
                {
                    message = "Contact To Admin";
                }
            }
            else
            {
                message = "Contact To Admin";
            }
            var logoimage = "";
            var logo = db.tblHeaderLogoes.Where(p => p.Role == "ADMIN").ToList();
            if (logo.Count > 0)
            {
                if (logo.SingleOrDefault().Role == "ADMIN")
                {
                    logoimage = logo.Where(p => p.Role == "ADMIN").SingleOrDefault().LogoImage;
                }
            }
            else
            {
                logoimage = "";
            }
            ViewBag.logo = logoimage;
            ViewBag.sts = confirm;
            ViewBag.message = message;
            ViewBag.name = name;
            ViewBag.firmname = firmname;
            ViewBag.mobile = mobile;
            ViewBag.address = address;
            ViewBag.joindate = joindate;
            ViewBag.photo = photo;
            var admindetail = db.Admin_details.SingleOrDefault();
            var signature = admindetail.signaturepath;
            ViewBag.signature = signature;
            var upitxt = admindetail.WebsiteUrl;
            var bw = new BarcodeWriter();
            var encOptions = new ZXing.Common.EncodingOptions
            {
                Width = 500,
                Height = 500,
                Margin = 0,
                PureBarcode = false
            };
            //string pathchk = System.Web.Hosting.HostingEnvironment.MapPath("~/");
            //string path = pathchk + "Outside_logo/1d1dbcfa-d7a1-473d-8501-fb18414cecdd_logoaasha.png";
            //     System.Drawing.Image image = System.Drawing.Image.FromFile(path);
            //encOptions.Hints.Add(EncodeHintType.ERROR_CORRECTION);
            bw.Renderer = new BitmapRenderer();
            bw.Options = encOptions;
            bw.Format = ZXing.BarcodeFormat.QR_CODE;
            using (MemoryStream memory = new MemoryStream())
            {
                Bitmap bm = bw.Write(upitxt);
                bm.Save(memory, ImageFormat.Png);
                //   ViewBag.QRCodeImage
                ViewBag.qr = "data:image/png;base64," + Convert.ToBase64String(memory.ToArray());
            }
            return View();
        }
